window.ASBAB_NUZUL_CACHE["9"] = {"asbab_nuzul":{"19":[{"ar":"عَنِ النُّعْمَانِ بْنِ بَشِيرٍ رضي الله عنهما قَالَ: كُنْتُ عِنْدَ مِنْبَرِ رَسُولِ اللهِ ﷺ، فَقَالَ رَجُلٌ: مَا أُبَالِي أَنْ لَا أَعْمَلَ عَمَلًا بَعْدَ الْإِسْلَامِ، إِلَّا أَنْ أَسْقِيَ الْحَاجَّ، وَقَالَ آخَرُ: مَا أُبَالِي أَنْ لَا أَعْمَلَ عَمَلًا بَعْدَ الْإِسْلَامِ، إِلَّا أَنْ أَعْمُرَ الْمَسْجِدَ الْحَرَامَ، وَقَالَ آخَرُ: الْجِهَادُ فِي سَبِيلِ اللهِ أَفْضَلُ مِمَّا قُلْتُمْ، فَزَجَرَهُمْ عُمَرُ وَقَالَ: لَا تَرْفَعُوا أَصْوَاتَكُمْ عِنْدَ مِنْبَرِ رَسُولِ اللهِ ﷺ - وَهُوَ يَوْمُ الْجُمُعَةِ - وَلَكِنْ إِذَا صَلَّيْتُ الْجُمُعَةَ دَخَلْتُ فَاسْتَفْتَيْتُهُ فِيمَا اخْتَلَفْتُمْ فِيهِ، فَأَنْزَلَ اللهُ عز و جل: { أَجَعَلْتُمْ سِقَايَةَ ٱلْحَآجِّ وَعِمَارَةَ ٱلْمَسْجِدِ ٱلْحَرَامِ كَمَنْ ءَامَنَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ } الْآيَةَ إِلَى آخِرِهَا. واللفظ لمسلم.","id":""},{"ar":"وهناك سبب آخر لنزول هذه الآية: عن ابن عباس رضي الله عنهما قوله: { أَجَعَلْتُمْ سِقَايَةَ ٱلْحَآجِّ وَعِمَارَةَ ٱلْمَسْجِدِ ٱلْحَرَامِ كَمَنْ ءَامَنَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ }، قال العباس بن عبد المطلب - حين أسر يوم بدر -: لئن كنتم سبقتمونا بالإسلام، والهجرة، والجهاد، لقد كنا نعمر المسجد الحرام، ونسقي الحاج، ونفك العاني، قال الله: { أَجَعَلْتُمْ سِقَايَةَ } إلي قوله { ٱلظَّـٰلِمِينَ }.","id":""}],"39":[{"ar":"عن ابن عباس رضي الله تعالى عنهما: أن رسول الله ﷺ استنفر حيّاً من العرب فتثاقلوا، فنزلت: { إِلَّا تَنفِرُوا۟ يُعَذِّبْكُمْ عَذَابًا أَلِيمًا }، قال: كان عذابهم حبس المطر عنهم.","id":""}],"49":[{"ar":"عن ابن عباس رضي الله عنهما قال: لما أراد النبي ﷺ أن يخرج إلى غزوة تبوك، قال للجد بن قيس: ما تقول في مجاهدة بني الأصفر؟ قال: یا رسول الله إني امرؤ صاحب نساء ومتى أرى نساء بني الأصفر أفتتن، أفتأذن لي في الجلوس ولا تفتني، فأنزل الله: { وَمِنْهُم مَّن يَقُولُ ٱئْذَن لِّى وَلَا تَفْتِنِّىٓ ۚ أَلَا فِى ٱلْفِتْنَةِ سَقَطُوا۟ ۗ }.","id":""},{"ar":"وقد جاء من مرسل الزهري، ويزيد بن رومان، وعبد الله بن أبي بكر، وعاصم بن عمر بن قتادة وغيرهم، قالوا: قال رسول الله ﷺ ذات يوم - وهو في جهازه - للجد بن قيس أخي بن سلمة: « هل لك يا جد العام في جلاد بني الأصفر؟ » فقال: يا رسول الله أو تأذن لي ولا تفتني، فوالله لقد عرف قومي ما رجل أشد عجباً بالنساء مني، وإني أخشى إن رأيت نساء بني الأصفر أن لا أصبر عنهن. فأعرض عنه رسول الله ﷺ وقال: « قد أذنت لك » ففي الجد بن قيس نزلت هذه: { وَمِنْهُم مَّن يَقُولُ ٱئْذَن لِّى وَلَا تَفْتِنِّىٓ ۚ } الآية، أي إن كان إنما يخشى من نساء بني الأصفر وليس ذلك به، فما سقط فيه من الفتنة بتخلفه عن رسول الله ﷺ، والرغبة بنفسه عن نفسه أعظم.","id":""}],"58":[{"ar":"عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رضي الله عنه قَالَ: بَيْنَا رَسُولُ اللهِ ﷺ يَقْسِمُ قِسْماً، إِذْ جَاءَهُ ابْنُ ذِي الْخُوَيْصِرَةِ التَّمِيمِيُّ، فَقَالَ: اعْدِلْ يَا رَسُولَ اللهِ، فَقَالَ: « وَيْلَكَ، وَمَنْ يَعْدِلُ إِذَا لَمْ أَعْدِلْ »، فَقَالَ عُمَرُ بْنُ الْخَطَابِ: يَا رَسُولَ اللهِ، أَتَأْذَنْ لِي فِيهِ فَأَضْرِبَ عُنُقَهُ، فَقَالَ النَّبِيُّ ﷺ: « دَعْهُ، فَإِنَّ لَهُ أَصْحَابَاً، يَحْتَقِرُ أَحَدُكُمْ صَلَاتَهُ مَعَ صَلَاتِهِ، وَصِيَامَهُ مَعَ صِيَامِهِ، يَمْرُقُونَ مِنْ الدِّينِ، كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ، فَيُنْظَرُ فِي قُذَذِهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ، ثُمَّ يُنظَرُ فِي نَضِيَّتِهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ، ثُمَّ يُنْظَرُ فِي رِصَافِهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ، ثُمَّ يُنْظَرُ فِي نَصْلِهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ، قَدْ سَبَقَ الْفَرْثَ وَالدَّمَ، مِنْهُمْ رَجُلٌ أَسْوَدُ فِي إِحْدَى يَدَيْهِ - أَوْ قَالَ إِحْدَى ثَدْيَيْهِ - مِثْلُ ثَدْيِ الْمَرْأَةِ، أَوْ مِثْلُ الْبَضْعَةِ تَدَرْدَرُ، يَخْرُجُونَ عَلَى حِينِ فَتْرَةٍ مِنْ النَّاسِ » فَنَزَلَتْ فِيهِمْ { وَمِنْهُم مَّن يَلْمِزُكَ فِى ٱلصَّدَقَـٰتِ } الْآيَةَ.\n\nقَالَ أَبُو سَعِيدٍ: أَشْهَدُ أَنِّي سَمِعْتُ هَذَا مِنْ رَسُولِ اللهِ ﷺ، وَأَشْهَدُ أَنَّ عَلِيًّا حِينَ قَتَلَهُ وَأَنَا مَعَهُ جِيءَ بِالرَّجُلِ عَلَى النَّعْتِ الَّذِي نَعَتَ رَسُولُ اللهِ ﷺ.","id":""}],"65":[{"ar":"عن عبد الله بن عمر رضي الله عنهما قال: قال رجل في غزوة تبوك في مجلس: ما رأيت مثل قرائنا هؤلاء أرغب بطونا، ولا أكذب ألسنا، ولا أجبن عند اللقاء. فقال رجل في المجلس: كذبت، ولكنك منافق، لأخبرن رسول الله ﷺ. فبلغ ذلك رسول الله ﷺ ونزل القرآن.\n\nفقال عبد الله بن عمرو: أنا رأيته متعلقاً بحقب ناقة رسول الله ﷺ تنكبه الحجارة، وهو يقول: يا رسول الله إنما كنا نخوض ونلعب، ورسول الله ﷺ يقول: { أَبِٱللَّهِ وَءَايَـٰتِهِۦ وَرَسُولِهِۦ كُنتُمْ تَسْتَهْزِءُونَ } الآية.","id":""},{"ar":"وهناك سبب آخر لنزول هذه الآية: فقد جاء عن كعب بن مالك رضي الله عنها قال: « كان جماعة من المنافقين، ورجل من أشجع حليف لبني سلمة يقال له: مخشي بن حمير، يسيرون مع رسول الله ﷺ وهو منطلق إلى تبوك فقال بعضهم لبعض: أتحسبون جلاد بني الأصفر كقتال العرب بعضهم بعضاً، والله لكأنا بكم غداً مقرنين في الحبال إرجافاً وترهيباً للمؤمنين، وقال مخشي بن حمير والله لوددت أن أقاضي على أن يضرب كل رجل منكم مائة على أن ينجو من أن ينزل فينا قرآن، فقال رسول الله ﷺ لعمار بن ياسر: « أدرك القوم فإنهم قد احترقوا، فسلهم عما قالوا، فإن هم أنكروا، فقل: بلى، قلتم كذا وكذا »، فأدركهم فقال لهم: فجاءوا يعتذرون إليه، فأنزل الله: { لَا تَعْتَذِرُوا۟ قَدْ كَفَرْتُم بَعْدَ إِيمَـٰنِكُمْ ۚ إِن نَّعْفُ عَن طَآئِفَةٍ }، فكان الذي عفى الله عنه مخشي بن حمير، فتسمى عبد الرحمن، وسأل الله أن يقتل شهيداً، وألا يعلم بمقتله، فقتل باليمامة لا يعلم مقتله، ولا من قتله ولا يرى له أثر ولا عين.","id":""}],"66":[{"ar":"عن عبد الله بن عمر رضي الله عنهما قال: قال رجل في غزوة تبوك في مجلس: ما رأيت مثل قرائنا هؤلاء أرغب بطونا، ولا أكذب ألسنا، ولا أجبن عند اللقاء. فقال رجل في المجلس: كذبت، ولكنك منافق، لأخبرن رسول الله ﷺ. فبلغ ذلك رسول الله ﷺ ونزل القرآن.\n\nفقال عبد الله بن عمرو: أنا رأيته متعلقاً بحقب ناقة رسول الله ﷺ تنكبه الحجارة، وهو يقول: يا رسول الله إنما كنا نخوض ونلعب، ورسول الله ﷺ يقول: { أَبِٱللَّهِ وَءَايَـٰتِهِۦ وَرَسُولِهِۦ كُنتُمْ تَسْتَهْزِءُونَ } الآية.","id":""},{"ar":"وهناك سبب آخر لنزول هذه الآية: فقد جاء عن كعب بن مالك رضي الله عنها قال: « كان جماعة من المنافقين، ورجل من أشجع حليف لبني سلمة يقال له: مخشي بن حمير، يسيرون مع رسول الله ﷺ وهو منطلق إلى تبوك فقال بعضهم لبعض: أتحسبون جلاد بني الأصفر كقتال العرب بعضهم بعضاً، والله لكأنا بكم غداً مقرنين في الحبال إرجافاً وترهيباً للمؤمنين، وقال مخشي بن حمير والله لوددت أن أقاضي على أن يضرب كل رجل منكم مائة على أن ينجو من أن ينزل فينا قرآن، فقال رسول الله ﷺ لعمار بن ياسر: « أدرك القوم فإنهم قد احترقوا، فسلهم عما قالوا، فإن هم أنكروا، فقل: بلى، قلتم كذا وكذا »، فأدركهم فقال لهم: فجاءوا يعتذرون إليه، فأنزل الله: { لَا تَعْتَذِرُوا۟ قَدْ كَفَرْتُم بَعْدَ إِيمَـٰنِكُمْ ۚ إِن نَّعْفُ عَن طَآئِفَةٍ }، فكان الذي عفى الله عنه مخشي بن حمير، فتسمى عبد الرحمن، وسأل الله أن يقتل شهيداً، وألا يعلم بمقتله، فقتل باليمامة لا يعلم مقتله، ولا من قتله ولا يرى له أثر ولا عين.","id":""}],"74":[{"ar":"عن أنس بن مالك رضي الله عنه: سأل أنس - بعض من كان عنده - عن زيد بن أرقم رضي الله عنه فقال: هو الذي يقول له رسول الله ﷺ: «أوفى الله له بإذنه ». \nقال: وذلك حين سمع رجلاً من المنافقين يقول - ورسول الله ﷺ يخطب -: لئن كان صادقاً فنحن شر من الحمير، فقال زيد بن أرقم: فهو والله صادق، ولأنت شر من الحمار. ثم رفع ذلك إلى رسول الله ﷺ، فجحده، فأنزل الله هذه الآية تصديقاً لزيد، يعني قوله: { يَحْلِفُونَ بِٱللَّهِ مَا قَالُوا۟ } الآية.","id":""},{"ar":"ولها سبب آخر: فقد جاء عن ابن عباس رضي الله عنهما قال: كان رسول الله ﷺ جالساً تحت ظل شجرة، فقال: « إنه سيأتيكم إنسان فينظر إليكم - بعين الشيطان - فإذا جاء فلا تكلموه »، فلم يلبثوا أن طلع رجل أزرق، فدعاه رسول الله ﷺ فقال: « علام تشتمني أنت وأصحابك؟ »، فانطلق الرجل فجاء بأصحابه فحلفوا بالله ما قالوا، حتى تجاوز عنهم، فأنزل الله { يَحْلِفُونَ بِٱللَّهِ مَا قَالُوا۟ } الآية.","id":""}],"79":[{"ar":"عَنْ أَبِي مَسْعُودٍ رضي الله عنه قَالَ: أُمِرْنَا بِالصَّدَقَةِ، وَكُنَّا نُحَامِلُ، فَتَصَدَّقَ أَبُو عَقِيلٍ بِنِصْفِ صَاعٍ، قَالَ: وَجَاء إِنْسَانٌ بِشَيْءٍ أَكْثَرَ مِنْهُ، فَقَالَ الْمُنَافِقُونَ: إِنَّ اللهَ لَغَنِيٌّ عَنْ صَدَقَةِ هَذَا، وَمَا فَعَلَ هَذَا الْآخَرُ إِلَّا رِيَاءً، فَنَزَلَتْ: { ٱلَّذِينَ يَلْمِزُونَ ٱلْمُطَّوِّعِينَ مِنَ ٱلْمُؤْمِنِينَ فِى ٱلصَّدَقَـٰتِ وَٱلَّذِينَ لَا يَجِدُونَ إِلَّا جُهْدَهُمْ } ولم يلفظ بشر بالمطوعين.","id":""}],"84":[{"ar":"عَنْ ابْنِ عَبَّاسٍ رضي الله عنهما عَنْ عُمَرَ بْنِ الْخَطَّابِ رضي الله عنه أَنَّهُ قَالَ: لَمَّا مَاتَ عَبْدُ اللهِ بْنُ أَبَيٍّ أبْنُ سَلُولَ، دُعِيَ لَهُ رَسُولُ اللهِ ﷺ لِيُصَلِّيَ عَلَيْهِ، فَلَمَّا قَامَ رَسُولُ اللهِ ﷺ وَثَبْتُ إِلَيْهِ، فَقُلْتُ: يَا رَسُولَ اللهِ، أَتُصَلِّي عَلَى ابْنِ أُبَيٍّ، وَقَدْ قَالَ: يَوْمَ كَذَا وَكَذَا، قَالَ: أُعَدِّدُ عَلَيْهِ قَوْلَهُ، فَتَبَسَّمَ رَسُولُ اللهِ ﷺ وَقَالَ: « أَخِّرْ عَنِّي يَا عُمَرُ »، فَلَمَّا أَكْثَرْتُ عَلَيْهِ، قَالَ: « إِنِّي خُيِّرْتُ فَاخْتَرْتُ، لَوْ أَعْلَمُ أَنِّي إِنْ زِدْتُ عَلَى السَّبْعِينَ يُغْفَرْ لَهُ لَزِدْتُ عَلَيْهَا »، قَالَ: فَصَلَّى عَلَيْهِ رَسُولُ اللهِ ﷺ ثُمَّ انْصَرَفَ، فَلَمْ يَمْكُثْ إِلَّا يَسِيراً حَتَّى نَزَلَتِ الْآيَتَانِ مِنْ بَرَاءَةَ: { وَلَا تُصَلِّ عَلَىٰٓ أَحَدٍ مِّنْهُم مَّاتَ أَبَدًا } إِلَى قَوْلِهِ: { وَهُمْ فَـٰسِقُونَ }، قَالَ: فَعَجِبْتُ بَعْدُ مِنْ جُرْأَتِي عَلَى رَسُولِ اللهِ ﷺ، وَاللهُ وَرَسُولُهُ أَعْلَمُ. واللفظ للبخاري.","id":""},{"ar":"عَنِ ابْنِ عُمَرَ رضي الله عنهما أَنَّ عَبْدَ اللهِ بْنَ أُبَيٍّ لَمَّا تُوُفِّيَ، جَاءَ ابْنُهُ إِلَى النَّبِيِّ ﷺ، فَقَالَ: يَا رَسُولَ اللهِ أَعْطِنِي قَمِيصَكَ أُكَفِّنُهُ فِيهِ، وَصَلِّ عَلَيْهِ، وَاسْتَغْفِرْ لَهُ، فَأَعْطَاهُ النَّبِيُّ ﷺ قَمِيصَهُ، فَقَالَ: « آذِنِّي أُصَلِّي عَلَيْهِ »، فَآذَنَهُ، فَلَمَّا أَرَادَ أَنْ يُصَلِّيَ عَلَيْهِ جَذَبَهُ عُمَرُ رضي الله عنه، فَقَالَ: أَلَيْسَ اللهُ نَهَاكَ أَنْ تُصَلِّيَ عَلَى الْمُنَافِقِينَ؟ فَقَالَ: أَنَا بَيْنَ خِيَرَتَيْنِ، قَالَ: { ٱسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِن تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً فَلَن يَغْفِرَ ٱللَّهُ لَهُمْ ۚ }، فَصَلَّى عَلَيْهِ، فَنَزَلَتْ: { وَلَا تُصَلِّ عَلَىٰٓ أَحَدٍ مِّنْهُم مَّاتَ أَبَدًا وَلَا تَقُمْ عَلَىٰ قَبْرِهِۦٓ ۖ }، واللفظ للبخاري.","id":""},{"ar":"عن ابن عباس رضي الله عنهما، أن عبد الله بن عبد الله بن أُبَيٍّ قال له أبوه: أي بني! اطلب ثوباً من ثياب النبي ﷺ تُكَفِّنِّي فيه، ومره فليصلِّ عَلَيَّ، قال: فأتاه فقال: يا رسول الله! قد عرفت شرف عبد الله، وهو يطلب إليك ثوباً من ثيابكَ تُكَفِّنْه فيه وتصلِّي عليه، فقال عمر: يا رسول الله! أتصلي عليه وقد نهاك الله أن تصلي عليه! فقال: « أين؟ » فقال: { ٱسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِن تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً فَلَن يَغْفِرَ ٱللَّهُ لَهُمْ ۚ }. قال: « فإني سازيد على سبعين »، فأنزل الله عز و جل: { وَلَا تُصَلِّ عَلَىٰٓ أَحَدٍ مِّنْهُم مَّاتَ أَبَدًا وَلَا تَقُمْ عَلَىٰ قَبْرِهِۦٓ ۖ } الآية، قال: فأرسل إلى عمر، فأخبر بذلك.","id":""}],"95":[{"ar":"عن كعب بن مالك رضي الله عنه يقول: لما قدم رسول الله ﷺ من تبوك جلس للناس، فلما فعل ذلك جاءه المخلفون فطفقوا يعتذرون إليه، ويحلفون له، وكانوا بضعة وثمانين رجلاً، فقبل منهم رسول الله ﷺ علانيتهم، وبايعهم واستغفر لهم، ووكل سرائرهم إلى الله، وصدقته حديثي، فقال كعب: والله ما أنعم الله عليّ من نعمة قط بعد أن هداني للإسلام، أعظم في نفسي من صدق رسول الله، أن لا أكون كذبته فأهلك، كما هلك الذين كذبوا، إن الله قال للذين كذبوا حين أنزل الوحي شر ما قال لأحد: { سَيَحْلِفُونَ بِٱللَّهِ لَكُمْ إِذَا ٱنقَلَبْتُمْ إِلَيْهِمْ لِتُعْرِضُوا۟ عَنْهُمْ ۖ فَأَعْرِضُوا۟ عَنْهُمْ ۖ إِنَّهُمْ رِجْسٌ ۖ وَمَأْوَىٰهُمْ جَهَنَّمُ جَزَآءَۢ بِمَا كَانُوا۟ يَكْسِبُونَ ﴿٩٥﴾ } إلى قوله: { فَإِنَّ ٱللَّهَ لَا يَرْضَىٰ عَنِ ٱلْقَوْمِ ٱلْفَـٰسِقِينَ }.","id":""}],"102":[{"ar":"عن ابن عباس رضي الله عنهما: قوله: { وَءَاخَرُونَ ٱعْتَرَفُوا۟ بِذُنُوبِهِمْ خَلَطُوا۟ عَمَلًا صَـٰلِحًا وَءَاخَرَ سَيِّئًا } قال: كانوا عشرة رهط تخلفوا عن النبي ﷺ في غزوة تبوك، فلما حضر رجوع النبي ﷺ، أوثق سبعة منهم أنفسهم بسواري المسجد، وكان ممر النبي ﷺ إذا رجع في المسجد عليهم، فلما رآهم قال: « من هؤلاء الموثقون أنفسهم بالسواري؟ » قالوا: هذا أبو لبابة وأصحاب له تخلفوا عنك يا رسول الله حتى تطلقهم وتعذرهم، فقال النبي ﷺ: « وأنا أقسم بالله لا أطلقهم ولا أعذرهم حتى يكون الله هو الذي يطلقهم، رغبوا عني وتخلفوا عن الغزو مع المسلمين »، فلما بلغهم ذلك، قالوا: ونحن نقسم بالله لا نطلق أنفسنا حتى يكون الله الذي يطلقنا، فأنزل الله تبارك وتعالى: { وَءَاخَرُونَ ٱعْتَرَفُوا۟ بِذُنُوبِهِمْ خَلَطُوا۟ عَمَلًا صَـٰلِحًا وَءَاخَرَ سَيِّئًا عَسَى ٱللَّهُ أَن يَتُوبَ عَلَيْهِمْ ۚ إِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ }، « وعسى » من الله واجب، فلما نزلت أرسل إليهم النبي ﷺ فأطلقهم وعذرهم.","id":""}],"107":[{"ar":"عن ابن عباس رضي الله عنهما قوله: { وَٱلَّذِينَ ٱتَّخَذُوا۟ مَسْجِدًا ضِرَارًا }، وهم أناس من الأنصار، ابتنوا مسجداً فقال لهم أبو عامر: ابنوا مسجدكم واستعدوا بما استطعتم من قوة ومن سلاح، فإني ذاهب إلى قيصر ملك الروم آتي بجند من الروم فأخرج محمداً وأصحابه، فلما فرغوا من مسجدهم أتوا النبي ﷺ، فقالوا: قد فرغنا من بناء مسجدنا، فنحب أن تصلي فيه، وتدعو لنا بالبركة، فأنزل الله فيه: { لَا تَقُمْ فِيهِ أَبَدًا ۚ لَّمَسْجِدٌ أُسِّسَ عَلَى ٱلتَّقْوَىٰ مِنْ أَوَّلِ يَوْمٍ أَحَقُّ أَن تَقُومَ فِيهِ ۚ } إلى قوله { وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّـٰلِمِينَ }.","id":""}],"109":[{"ar":"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه، عَنِ النَّبِي ﷺ قَالَ: نَزَلَتْ هَذِهِ الْآيَةُ فِي أَهْلِ قُبَاءٍ، { فِيهِ رِجَالٌ يُحِبُّونَ أَن يَتَطَهَّرُوا۟ ۚ } قَالَ: كَانُوا يَسْتَنْجُونَ بِالْمَاءِ، فَنَزَلَتْ فِيهِمْ هَذِهِ الْآيَةُ.","id":""}],"113":[{"ar":"عَنْ عَلِيٍّ رَضِيَ اللهُ تَعَالَى عَنْهُ قَالَ: سَمِعْتُ رَجُلاً يَسْتَغْفِرُ لِأَبَوَيْهِ وَهُمَا مُشْرِكَانِ، فَقُلْتُ: تَسْتَغْفِرُ لِأَبَوَيْكَ وَهُمَا مُشْرِكَانِ، فَقَالَ: أَلَيْسَ قَدْ اسْتَغْفَرَ إِبْرَاهِيمُ لِأَبِيهِ وَهُوَ مُشْرِكٌ، قَالَ: فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ ﷺ فَنَزَلَتْ: { مَا كَانَ لِلنَّبِىِّ وَٱلَّذِينَ ءَامَنُوٓا۟ أَن يَسْتَغْفِرُوا۟ لِلْمُشْرِكِينَ } إلى آخرِ الآيَتَيْنِ، قَالَ عبد الرحمن: فَأَنْزَلَ اللهُ { وَمَا كَانَ ٱسْتِغْفَارُ إِبْرَٰهِيمَ لِأَبِيهِ إِلَّا عَن مَّوْعِدَةٍ وَعَدَهَآ إِيَّاهُ }.","id":""},{"ar":"عن ابن عباس رضي الله عنهما قوله: { مَا كَانَ لِلنَّبِىِّ وَٱلَّذِينَ ءَامَنُوٓا۟ أَن يَسْتَغْفِرُوا۟ لِلْمُشْرِكِينَ } الآية، فكانوا يستغفرون لهم حتى نزلت هذه الآية، فلما نزلت أمسكوا عن الاستغفار لأمواتهم، ولم ينهوا أن يستغفروا للأحياء حتى يموتوا، ثم أنزل الله: { وَمَا كَانَ ٱسْتِغْفَارُ إِبْرَٰهِيمَ لِأَبِيهِ إِلَّا عَن مَّوْعِدَةٍ وَعَدَهَآ إِيَّاهُ } الآية.","id":""}],"114":[{"ar":"عَنْ عَلِيٍّ رَضِيَ اللهُ تَعَالَى عَنْهُ قَالَ: سَمِعْتُ رَجُلاً يَسْتَغْفِرُ لِأَبَوَيْهِ وَهُمَا مُشْرِكَانِ، فَقُلْتُ: تَسْتَغْفِرُ لِأَبَوَيْكَ وَهُمَا مُشْرِكَانِ، فَقَالَ: أَلَيْسَ قَدْ اسْتَغْفَرَ إِبْرَاهِيمُ لِأَبِيهِ وَهُوَ مُشْرِكٌ، قَالَ: فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ ﷺ فَنَزَلَتْ: { مَا كَانَ لِلنَّبِىِّ وَٱلَّذِينَ ءَامَنُوٓا۟ أَن يَسْتَغْفِرُوا۟ لِلْمُشْرِكِينَ } إلى آخرِ الآيَتَيْنِ، قَالَ عبد الرحمن: فَأَنْزَلَ اللهُ { وَمَا كَانَ ٱسْتِغْفَارُ إِبْرَٰهِيمَ لِأَبِيهِ إِلَّا عَن مَّوْعِدَةٍ وَعَدَهَآ إِيَّاهُ }.","id":""},{"ar":"عن ابن عباس رضي الله عنهما قوله: { مَا كَانَ لِلنَّبِىِّ وَٱلَّذِينَ ءَامَنُوٓا۟ أَن يَسْتَغْفِرُوا۟ لِلْمُشْرِكِينَ } الآية، فكانوا يستغفرون لهم حتى نزلت هذه الآية، فلما نزلت أمسكوا عن الاستغفار لأمواتهم، ولم ينهوا أن يستغفروا للأحياء حتى يموتوا، ثم أنزل الله: { وَمَا كَانَ ٱسْتِغْفَارُ إِبْرَٰهِيمَ لِأَبِيهِ إِلَّا عَن مَّوْعِدَةٍ وَعَدَهَآ إِيَّاهُ } الآية.","id":""}],"117":[{"ar":"جاء في صحيح مسلم: قَالَ كَعْبُ بْنُ مَالِكٍ: لَمْ أَتَخَلَّفْ عَنْ رَسُولِ اللهِ ﷺ فِي غَزْوَةٍ غَزَاهَا قَطُّ، إِلَّا فِي غَزْوَةِ تَبُوكَ، غَيْرَ أَنِّي قَدْ تَخَلَّفْتُ فِي غَزْوَةِ بَدْرٍ، وَلَمْ يُعَاتِبْ أَحَداً تَخُلَّفَ عَنْهُ، إِنَّمَا خَرَجَ رَسُولُ اللهِ ﷺ وَالْمُسْلِمُونَ يُرِيدُونَ عِيرَ قُرَيْشٍ، حَتَّى جَمَعَ اللهُ بَيْنَهُمْ وَبَيْنَ عَدُوِّهِمْ، عَلَى غَيْرِ مِيَعَادٍ، وَلَقَدْ شَهِدْتُ مَعَ رَسُولِ الله ﷺ لَيْلَةَ الْعَقَبَةِ، حِينَ تَوَاثَقْنَا عَلَى الْإِسْلَامِ، وَمَا أُحِبُّ أَنَّ لِي بِهَا مَشْهَدَ بَدْرٍ، وَإِنْ كَانَتْ بَدْرٌ أَذْكَرَ فِي النَّاسِ مِنْهَا. وَكَانَ مِنْ خَبَرِي، حِينَ تَخَلَّفْتُ عَنْ رَسُولِ اللهِ ﷺ فِي غَزْوَةِ تَبُوكَ، أَنِّي لَمْ أَكُنْ قَطُّ أَقْوَى وَلَا أَيْسَرَ مِنِّي حِينَ تَخَلَّفْتُ عَنْهُ فِي تِلْكَ الْغَزْوَةِ، وَاللهِ مَا جَمَعْتُ قَبْلَهَا رَاحِلَتَيْنِ قَطُّ، حَتَّى جَمَعْتُهُمَا فِي تِلْكَ الْغَزْوَةِ، فَغَزَاهَا رَسُولُ اللهِ ﷺ فِي حَرٍّ شَدِيدٍ، وَاسْتَقْبَلَ سَفَراً بَعِيداً وَمَفَازَاً، وَاسْتَقْبَلَ عَدُوًّا كَثِيراً، فَجَلَا لِلْمُسْلِمِينَ أَمْرَهُمْ لِيَتَأَهَّبُوا أُهْبَةَ غَزْوِهِمْ، فَأَخْبَرَهُمْ بِوَجْهِهِم الَّذِي يُرِيدُ، وَالْمُسْلِمُونَ مَعَ رَسُولِ اللهِ ﷺ كَثِيرٌ، وَلَا يَجْمَعُهُمْ كِتَابُ حَافِظٍ - يُرِيدُ بِذَلِكَ الدِّيوَانَ -.\n\nقَالَ كَعْبٌ: فَقَلَّ رَجُلٌ يُرِيدُ أَنْ يَتَغَيَّبَ يَظُنُّ أَنَّ ذَلِكَ سَيَخْفَى لَهُ، مَا لَمْ يَنْزِلْ فِيهِ وَحْيٌ مِنْ اللهِ عز و جل، وَغَزَا رَسُولُ اللهِ ﷺ تِلْكَ الْغَزْوَةَ حِينَ طَابَت الثِّمَارُ وَالظِّلَالُ، فَأَنَا إِلَيْهَا أَصْعَرُ، فَتَجَهَّزَ رَسُولُ اللهِ ﷺ وَالْمُسْلِمُونَ مَعَهُ، وَطَفِقْتُ أَغْدُو لِكَيْ أَتَجَهَّزَ مَعَهُمْ، فَأَرْجِعُ وَلَمْ أَقْضِ شَيْئاً، وَأَقُولُ فِي نَفْسِي: أَنَا قَادِرٌ عَلَى ذَلِكَ، إِذَا أَرَدْتُ فَلَمْ يَزَلْ ذَلِكَ يَتَمَادَى بِي حَتَّى اسْتَمَرَّ بِالنَّاسِ الْجِدُّ، فَأَصْبَحَ رَسُولُ اللهِ ﷺ غَادِياً وَالْمُسْلِمُونَ مَعَهُ، وَلَمْ أَقْضِ مِنْ جَهَازِي شَيْئاً، ثُمَّ غَدَوْتُ فَرَجَعْتُ وَلَمْ أَقْضِ شَيْئاً، فَلَمْ يَزَلْ ذَلِكَ يَتَمَادَى بِي حَتَّى أَسْرَعُوا وَتَفَارَطَ الْغَزْوُ، فَهَمَمْتُ أَنْ أَرْتَحِلَ فَأُدْرِكَهُمْ، فَيَا لَيْتَنِي فَعَلْتُ، ثُمَّ لَمْ يُقَدَّرُ ذَلِكَ لِي، فَطَفِقْتُ إِذَا خَرَجْتُ فِي النَّاسِ، بَعْدَ خُرُوجِ رَسُولِ اللهِ، يَحْزُنُنِي أَنِّي لَا أَرَى لِي أُسْوَةً إِلَّا رَجُلًا مَغْمُوصاً عَلَيْهِ فِي النِّفَاقِ، أَوْ رَجُلًا مِمَّنْ عَذَرَ اللهُ مِنْ الضُّعَفَاءِ.\n\nوَلَمْ يَذْكُرْنِي رَسُولُ اللهِ ﷺ حَتَّى بَلَغَ تَبُوكَ، فَقَالَ: وَهُوَ جَالِسٌ فِي الْقَوْمِ بَتَبُوكَ: « مَا فَعَلَ كَعْبُ بْنُ مَالِكٍ؟ » قَالَ رَجُلٌ مِنْ بَنِي سَلِمَةَ: يَا رَسُولَ اللهِ! حَبَسَهُ بُرْدَاهُ وَالنَّظَرُ فِي عِطْفَيْهِ. فَقَالَ لَهُ مُعَاذُ بْنُ جَبَلٍ: بِئْسَ مَا قُلْتَ: وَاللهِ يَا رَسُولَ اللهِ! مَا عَلِمْنَا عَلَيْهِ إِلَّا خَيْراً، فَسَكَتَ رَسُولُ اللهِ ﷺ. فَبَيْنَمَا هُوَ عَلَى ذَلِكَ رَأَى رَجُلًا مُبَيِّضاً يَزُولُ بِهِ السَّرَابُ، فَقَالَ رَسُولُ اللهِ ﷺ: « كُنْ أَبَا خَيْثَمَةَ »، فَإِذَا هُوَ أَبُو خَيْثَمَةَ الْأَنْصَارِيُّ، وَهُوَ الَّذِي تَصَدَّقَ بِصَاعِ التَّمْرِ حِينَ لَمَزَهُ الْمُنَافِقُونَ -.\n\nفَقَالَ كَعْبُ بْنُ مَالِكٍ: فَلَمَّا بَلَغَنِي أَنَّ رَسُولَ اللهِ ﷺ قَدْ تَوَجَّهَ قَافِلًا مِنْ تَبُوكَ، حَضَرَنِي بَثِّي فَطَفِقْتُ أَتَذَكَّرُ الْكَذِبَ وَأَقُولُ: بِمَ أَخْرُجُ مِنْ سَخَطِهِ غَداً؟ وَأسْتَعِينُ عَلَى ذَلِكَ كُلَّ ذِي رَأْيٍ مِنْ أَهْلِي، فَلَمَّا قِيلَ لِي إِنَّ رَسُولَ اللهِ ﷺ قَدْ أَظَلَّ قَادِماً، زَاحَ عَنِّي الْبَاطِلُ حَتَّى عَرَفْتُ أَنِّي لَنْ أَنْجُوَ مِنْهُ بِشَيْءٍ أَبَداً، فَأَجْمَعْتُ صِدْقَهُ، وَصَبَّحَ رَسُولُ اللهِ ﷺ قَادِماً، وَكَانَ إِذَا قَدِمَ مِنْ سَفَرٍ، بَدَأَ بِالْمَسْجِدِ فَرَكَعَ فِيهِ رَكْعَتَيْنِ، ثُمَّ جَلَسَ لِلنَّاسِ، فَلَمَّا فَعَلَ ذَلِكَ جَاءَهُ الْمُخَلَّفُونَ، فَطَفِقُوا يَعْتَذِرُونَ إِلَيْهِ وَيَحْلِفُونَ لَهُ، وَكَانُوا بِضْعَةً وَثَمَانِينَ رَجُلًا، فَقَبِلَ مِنْهُمْ رَسُولُ اللهِ ﷺ عَلَانِيَتَهُمْ وَبَايَعَهُمْ وَاسْتَغْفَرَ لَهُمْ، وَوَكَلَ سَرَائِرَهُمْ إِلَى اللهِ، حَتَّى جِئْتُ، فَلَمَّا سَلَّمْتُ، تَبَسَّمَ تَبَسُّمَ الْمُغْضَبِ ثُمَّ قَالَ: « تَعَالَ » فَجِئْتُ أَمْشِي حَتَّى جَلَسْتُ بَيْنَ يَدَيْهِ، فَقَالَ لِي: « مَا خَلَّفَكَ؟ أَلَمْ تَكُنْ قَدِ ابْتَعْتَ ظَهْرَكَ؟ ». \n\nقَالَ: قُلْتُ: يَا رَسُولَ اللهِ! إِنِّي وَاللهِ لَوْ جَلَسْتُ عِنْدَ غَيْرِكَ مِنْ أَهْلِ الدُّنْيَا، لَرَأَيْتُ أَنِّي سَأَخْرُجُ مِنْ سَخَطِهِ بِعُذْرٍ، وَلَقَدْ أُعْطِيتُ جَدَلًا، وَلَكِنِّي وَاللهِ لَقَدْ عَلِمْتُ، لَئِنْ حَدَّثْتُكَ الْيَوْمَ حَدِيثَ كَذِبٍ تَرْضَى بِهِ عَنِّي، لَيُوشِكَنَّ اللهُ أَنْ يُسْخِطَكَ عَلَيَّ، وَلَئِنْ حَدَّثْتُكَ حَدِيثَ صِدْقٍ تَجِدُ عَلَيَّ فِيهِ، إِنِّي لَأَرْجُو فِيهِ عُقْبَى اللهِ. وَاللهِ! مَا كَانَ لِي عُذْرٌ، وَاللهِ! مَا كُنْتُ قَطُّ أَقْوَى وَلَا أَيْسَرَ مِنِّي حِينَ تَخَلَّفْتُ عَنْكَ. قَالَ رَسُولُ اللهِ ﷺ: « أَمَّا هَذَا، فَقَدْ صَدَقَ، فَقُمْ حَتَّى يَقْضِيَ اللهُ فِيكَ »، فَقُمْتُ، وَثَارَ رِجَالٌ مِنْ بَنِي سَلِمَةَ فَاتَّبَعُونِي، فَقَالُوا لِي: وَاللهِ! مَا عَلِمْنَاكَ أَذْنَبْتَ ذَنْباً قَبْلَ هَذَا، لَقَدْ عَجَرْتَ فِي أَنْ لَا تَكُونَ اعْتَذَرْتَ إِلَى رَسُولِ اللهِ ﷺ بِمَا اعْتَذَرَ بِهِ إِلَيْهِ الْمُخَلَّفُونَ، فَقَدْ كَانَ كَافِيَكَ ذَنْبَكَ اسْتِغْفَارُ رَسُولِ اللهِ ﷺ لَكَ.\n \nقَالَ: فَوَاللهِ! مَا زَالُوا يُؤَنِّبُونَنِي حَتَّى أَرَدْتُ أَنْ أَرْجِعَ إِلَى رَسُولِ اللهِ ﷺ فَأُكَذِّبَ نَفْسِي، قَالَ: ثُمَّ قُلْتُ لَهُمْ: هَلْ لَقِيَ هَذَا مَعِي مِنْ أَحَدٍ؟ قَالُوا: نَعَمْ، لَقِيَهُ مَعَكَ رَجُلَانِ، قَالُوا مِثْلَ مَا قُلْتَ، فَقِيلَ لَهُمَا مِثْلَ مَا قِيلَ لَكَ، قَالَ: قُلْتُ: مَنْ هُمَا؟ قَالُوا: مُرَارَةُ بْنُ الرَّبِيعَةَ الْعَامِرِيُّ، وَهِلَالُ بْنُ أُمَيَّةَ الْوَاقِفِيُّ، قَالَ: فَذَكَرُوا لِي رَجُلَيْنِ صَالِحَيْنِ قَدْ شَهِدَا بَدْراً فِيهِمَا أُسْوَةٌ، قَالَ: فَمَضَيْتُ حِينَ ذَكَرُوهُمَا لِي.\n \nقَالَ: وَنَهَى رَسُولُ اللهِ ﷺ الْمُسْلِمِينَ عَنْ كَلَامِنَا، أَيُّهَا الثَّلَاثَةُ، مِنْ بَيْنِ مَنْ تَخَلَّفَ عَنْهُ.\n \nقَالَ: فَاجْتَنَبَنَا النَّاسُ، وَقَالَ: تَغَيَّرُوا لَنَا حَتَّى تَنَكَّرَتْ لِي فِي نَفْسِيَ الْأَرْضُ، فَمَا هِيَ بِالْأَرْضِ الَّتِي أَعْرِفُ، فَلَبِثْنَا عَلَى ذَلِكَ خَمْسِينَ لَيْلَةً، فَأَمَّا صَاحِبَايَ فَاسْتَكَانَا وَقَعَدَا فِي بُيُوتِهِمَا يَبْكِيَانِ، وَأَمَّا أَنَا فَكُنْتُ أَشَبَّ الْقَوْمِ وَأَجْلَدَهُمْ، فَكُنْتُ أَخْرُجُ فَأَشْهَدُ الصَّلَاةَ وَأَطُوفُ فِي الْأَسْوَاقِ وَلَا يُكَلِّمُنِي أَحَدٌ، وَآتِي رَسُولَ اللهِ ﷺ عَلَيْهِ وَهُوَ فِي مَجْلِسِهِ بَعْدَ الصَّلَاةِ، فَأَقُولُ فِي نَفْسِي: هَلْ حَرَّكَ شَفَتَيْهِ بِرَدِّ السَّلَام، أَمْ لَا؟ ثُمَّ أُصَلِّي قَرِيباً مِنْهُ وَأُسَارِقُهُ النَّظَرَ، فَإِذَا أَقْبَلْتُ عَلَى صَلَاتِي نَظَرَ إِلَيَّ، وَإِذَا الْتَفَتُّ نَحْوَهُ أَعْرَضَ عَنِّي، حَتَّى إِذَا طَالَ ذَلِكَ عَلَيَّ مِنْ جَفْوَةِ الْمُسْلِمِينَ، مَشَيْتُ حَتَّى تَسَوَّرْتُ جِدَارَ حَائِطِ أَبِي قَتَادَةَ، وَهُوَ ابْنُ عَمِّي، وَأَحَبُّ النَّاسِ إِلَيَّ، فَسَلَّمْتُ عَلَيْهِ، فَوَاللهِ! مَا رَدَّ عَلَيَّ السَّلَامَ، فَقُلْتُ لَهُ: يَا أَبَا قَتَادَةَ! أَنْشُدُكَ بِاللَّهِ! هَلْ تَعْلَمَنَّ أَنِّي أُحِبُّ اللهَ وَرَسُولَهُ؟ قَالَ: فَسَكَتَ، فَعُدْتُ فَنَاشَدْتُهُ، فَسَكَتَ فَعُدْتُ فَنَاشَدْتُهُ. فَقَالَ: اللهُ وَرَسُولُهُ أَعْلَمُ، فَفَاضَت عَيْنَايَ، وَتَوَلَّيْتُ، حَتَّى تَسَوَّرْتُ الْجِدَارَ.\n \nفَبَيْنَا أَنَا أَمْشِي فِي سُوق الْمَدِينَةِ، إِذَا نَبَطِيٌّ مِنْ نَبَطِ أَهْلِ الشَّامِ، مِمَّنْ قَدِمَ بِالطَّعَامِ يَبِيعُهُ بِالْمَدِينَةِ، يَقُولُ: مَنْ يَدُلُّ عَلَى كَعْبِ بْنِ مَالِكٍ. قَالَ: فَطَفِقَ النَّاسُ يُشِيرُونَ لَهُ إِلَيَّ، حَتَّى جَاءَنِي فَدَفَعَ إِلَيَّ كِتَاباً مِنْ مَلِكِ غَسَّانَ، وَكُنْتُ كَاتِباً، فَقَرَأَتُهُ فَإِذَا فِيهِ: أَمَّا بَعْدُ، فَإِنَّهُ قَدْ بَلَغَنَا أَنَّ صَاحِبَكَ قَدْ جَفَاكَ، وَلَمْ يَجْعَلْكَ اللهُ بِدَارِ هَوَانٍ وَلَا مَضْيَعَةٍ، فَالْحَقِّ بِنَا نُوَاسِكَ. قَالَ: فَقُلْتُ، حِينَ قَرْأَتُهَا: وَهَذِهِ أَيْضَاً مِنْ الْبَلَاءِ، فَتَيَامَمْتُ بِهَا التَّنُّورَ فَسَجَرْتُهَا بِهَا.\n\nحَتَّى إِذَا مَضَتْ أَرْبَعُونَ مِنْ الْخَمْسِينَ، وَاسْتَلْبَثَ الْوَحْيُ، إِذَا رَسُولُ رَسُولِ اللهِ ﷺ يَأْتِينِي، فَقَالَ: إِنَّ رَسُولَ اللهِ ﷺ يَأْمُرُكَ أَنْ تَعْتَزِلَ امْرَأَتَكَ، قَالَ: فَقُلْتُ: أُطَلِّقُهَا أَمْ مَاذَا أَفْعَلُ؟ قَالَ: لَا، بَل اعْتَزِلْهَا فَلَا تَقْرَبَنَّهَا. قَالَ: فَأَرْسَلَ إِلَى صَاحِبَيَّ بِمِثْلِ ذَلِكَ، قَالَ: فَقُلْتُ لِامْرَأَتِي: الْحَقِي بِأَهْلِكِ فَكُونِي عِنْدَهُمْ حَتَّى يَقْضِيَ اللهُ فِي هَذَا الْأَمْرِ.\n\nقَالَ: فَجَاءَتِ امْرَأَةُ هِلَالَ بْن أُمَيَّةَ رَسُولَ اللهِ ﷺ، فَقَالَتْ لَهُ: يَا رَسُولَ اللهِ! إِنَّ هِلَالَ بْنَ أُمَيَّةَ شَيْخٌ ضَائِعٌ لَيْسَ لَهُ خَادِمٌ، فَهَلْ تَكْرَهُ أَنْ أَخْدُمَهُ؟ قَالَ: « لا، وَلَكِنْ لا يَقْرَبَنَّكِ » فَقَالَتْ: إِنَّهُ، وَاللهِ! مَا بِهِ حَرَكَةٌ إِلَى شَيْءٍ، وَوَاللهِ! مَا زَالَ يَبْكِي مُنْذُ كَانَ مِنْ أَمْرِهِ مَا كَانَ، إِلَى يَوْمِهِ هَذَا.\n \nقَالَ: فَقَالَ لِي بَعْضُ أَهْلِي: لَوْ اسْتَأَذَنْتَ رَسُولَ اللهِ ﷺ فِي امْرَأَتِكَ؟ فَقَدْ أَذِنَ لِامْرَأَةِ هِلَالِ بْنِ أُمَيَّةَ أَنْ تَخْدُمَهُ، قَالَ: فَقُلْتُ: لَا أَسْتَأْذِنَ فِيهَا رَسُولَ اللهِ ﷺ، وَمَا يُدْرِينِي مَاذَا يَقُولُ رَسُولُ اللهِ ﷺ إِذَا اسْتَأَذَنْتُهُ فِيهَا، وَأَنَا رَجُلٌ شَابٌّ.\n \nقَالَ: فَلَبِثْتُ بِذَلِكَ عَشْرَ لَيَالٍ، فَكَمُلَ لَنَا خَمْسُونَ لَيْلَةً مِنْ حِينَ نُهِيَ عَنْ كَلَامِنَا، قَالَ: ثُمَّ صَلَّيْتُ صَلَاةَ الْفَجْرِ صَبَاحَ خَمْسِينَ لَيْلَةً، عَلَى ظَهْرِ بَيْتٍ مِنْ بُيُوتِنَا، فَبَيْنَا أَنَا جَالِسٌ عَلَى الْحَالِ الَّتِي ذَكَرَ اللهُ عز و جل مِنَّا، قَدْ ضَاقَتْ عَلَيَّ نَفْسِي، وَضَاقَتْ عَلَيَّ الْأَرْضُ بِمَا رَحُبَتْ، سَمِعْتُ صَوْتَ صَارِخٍ أَوْفَى عَلَى سَلْعٍ يَقُولُ بِأَعْلَى صَوْتِهِ: يَا كَعْبَ بْنَ مَالِكٍ. أَبْشِرْ. قَالَ: فَخَرَرْتُ ساجِداً، وَعَرَفْتُ أَنْ قَدْ جَاءَ فَرَجٌ.\n\nقَالَ: فَآذَنَ رَسُولُ اللهِ ﷺ النَّاسَ بِتَوْبَةِ اللهِ عَلَيْنَا، حِينَ صَلَّى صَلَاةَ الْفَجْرِ، فَذَهَبَ النَّاسُ يُبَشِّرُونَنَا، فَذَهَبَ قِبَلَ صَاحِبَيَّ مُبَشِّرُونَ، وَرَكَضَ رَجُلٌ إِلَيَّ فَرَساً، وَسَعَى سَاعٍ مِنْ أَسْلَمَ قِبَلِي وَأَوْفَى الْجَبَلَ، فَكَانَ الصَّوْتُ أَسْرَعَ مِنْ الْفَرَسِ، فَلَمَّا جَاءَنِي الَّذِي سَمِعْتُ صَوْتَهُ يُبَشِّرُنِي، فَنَزَعْتُ لَهُ ثَوْبَيَّ فَكَسَوْتُهُمَا إِيَّاهُ بِبِشَارَته، وَاللهِ! مَا أَمْلِكُ غَيْرَهُمَا يَوْمَئِذٍ، وَاسْتَعَرْتُ ثَوْبَيْنِ فَلَبِسْتُهُمَا، فَانْطَلَقْتُ أَتَأَمَّمُ رَسُولَ اللهِ ﷺ يَتَلَقَّانِي النَّاسُ فَوْجاً فَوْجاً، يُهَنِّئُونِي بِالْتَّوْبَةِ وَيَقُولُونَ: لِتَهْنِئِكَ تَوْبَةُ اللهِ عَلَيْكَ. حَتَّى دَخَلْتُ الْمَسْجِدَ، فَإِذَا رَسُولُ اللهَ ﷺ جَالِسٌ فِي الْمَسْجِدِ، وَحَوْلَهُ النَّاسُ، فَقَامَ طَلْحَةُ بْنُ عُبَيْدِ اللهِ يُهَرْوِلُ حَتَّى صَافَحَنِي وَهَنَّأَنِي، وَاللهِ مَا قَامَ رَجُلٌ مِنْ الْمُهَاجِرِينَ غَيْرُهُ.\n\nقَالَ: فَكَانَ كَعْبٌ لَا يَنْسَاهَا لِطَلْحَةَ.\n\nقَالَ كَعْبٌ: فَلَمَّا سَلَّمْتُ عَلَى رَسُولِ اللهِ ﷺ قَالَ: وَهُوَ يَبْرُقُ وَجْهَهُ مِنْ السُّرورِ، وَيَقُولُ: « أَبْشِرْ بِخَيْرِ يَوْمٍ مَرَّ عَلَيْكَ مُنْذُ وَلَدَتْكَ أُمُّكَ »، قَالَ: فَقُلْتُ: أَمِنْ عِنْدِكَ؟ يَا رَسُولَ اللهِ. أَمْ مِنْ عِنْدِ اللهِ؟ فَقَالَ: « لَا، بَلْ مِنْ عِنْدِ اللهِ »، وَكَانَ رَسُولُ اللهِ ﷺ إِذَا سُرَّ اسْتَنَارَ وَجْهُهُ كَأَنَّ وَجْهَهُ قِطْعَةُ قَمَرٍ، قَالَ: وَكُنَّا نَعْرِفُ ذَلِكَ.\n\nقَالَ: فَلَمَّا جَلَسْتُ بَيْنَ يَدَيْهِ قُلْتُ: يَا رَسُولَ اللهِ! إِنَّ مِنْ تَوْبَتِي أَنْ أَنْخِلَعَ مِنْ مَالِي صَدَقَةً إِلَى اللهِ وَإِلَى رَسُولِهِ ﷺ. فَقَالَ رَسُولُ اللهِ ﷺ: « أَمْسِكْ بَعْضَ مَالِكَ فَهُوَ خَيْرٌ لَكَ »، قَالَ: فَقُلْتُ: فَإِنِّي أُمْسِكُ سَهْمِيَ الَّذِي بِخَيْبَرَ، قَالَ: وَقُلْتُ: يَا رَسُولَ اللهِ! إِنَّ اللهَ إِنَّمَا أَنْجَانِي بِالصِّدْقِ، وَإِنَّ مِنْ تَوْبَتِي أَنْ لَا أُحَدِّثَ إِلَّا صِدْقاً مَا بَقِيتُ. قَالَ: فَوَاللهِ! مَا عَلِمْتُ أَنَّ أَحَداً مِنْ الْمُسْلِمِينَ أَبْلَاهُ اللهُ فِي صِدْقِ الْحَدِيثِ، مُنْذُ ذَكَرْتُ ذَلِكَ لِرَسُولِ اللهِ ﷺ إِلَى يَوْمِي هَذَا، أَحْسَنَ مِمَّا أَبْلَانِي اللهُ بِهِ، وَاللهِ! مَا تَعَمَّدْتُ كَذِبَةً مُنْذُ قُلْتُ ذَلِكَ لِرَسُولِ اللهِ ﷺ، إِلَى يَوْمِي هَذَا وَإِنِّي لَأَرْجُو أَنْ يَحْفَظَنِي اللهُ فِيمَا بَقِيَ.\n \nقَالَ: فَأَنزلَ اللهُ عز و جل: { لَّقَد تَّابَ ٱللَّهُ عَلَى ٱلنَّبِىِّ وَٱلْمُهَـٰجِرِينَ وَٱلْأَنصَارِ ٱلَّذِينَ ٱتَّبَعُوهُ فِى سَاعَةِ ٱلْعُسْرَةِ مِنۢ بَعْدِ مَا كَادَ يَزِيغُ قُلُوبُ فَرِيقٍ مِّنْهُمْ ثُمَّ تَابَ عَلَيْهِمْ ۚ إِنَّهُۥ بِهِمْ رَءُوفٌ رَّحِيمٌ ﴿١١٧﴾ وَعَلَى ٱلثَّلَـٰثَةِ ٱلَّذِينَ خُلِّفُوا۟ حَتَّىٰٓ إِذَا ضَاقَتْ عَلَيْهِمُ ٱلْأَرْضُ بِمَا رَحُبَتْ وَضَاقَتْ عَلَيْهِمْ أَنفُسُهُمْ وَظَنُّوٓا۟ أَن لَّا مَلْجَأَ مِنَ ٱللَّهِ إِلَّآ إِلَيْهِ ثُمَّ تَابَ عَلَيْهِمْ لِيَتُوبُوٓا۟ ۚ إِنَّ ٱللَّهَ هُوَ ٱلتَّوَّابُ ٱلرَّحِيمُ ﴿١١٨﴾ }، حَتَّى بَلَغَ: { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ ٱللَّهَ وَكُونُوا۟ مَعَ ٱلصَّـٰدِقِينَ ﴿١١٩﴾ }.\n\nقَالَ كَعْبٌ: وَاللهِ! مَا أَنْعَمَ اللهُ عَلَيَّ مِنْ نِعْمَةٍ قَطُّ، بَعْدَ إِذْ هَدَانِي اللهُ لِلْإِسْلَامِ، أَعْظَمَ فِي نَفْسِي مِنْ صِدْقِي رَسُولَ اللهِ ﷺ، أَنْ لَا أَكُونَ كَذَبْتُهُ فَأَهْلِكَ كَمَا هَلَكَ الَّذِينَ كَذَبُوا، إِنَّ اللهَ قَالَ لِلَّذِينَ كَذَبُوا حِينَ أَنْزَلَ الْوَحْيَ شَرَّ مَا قَالَ لِأَحَدٍ، وَقَالَ اللهُ: { سَيَحْلِفُونَ بِٱللَّهِ لَكُمْ إِذَا ٱنقَلَبْتُمْ إِلَيْهِمْ لِتُعْرِضُوا۟ عَنْهُمْ ۖ فَأَعْرِضُوا۟ عَنْهُمْ ۖ إِنَّهُمْ رِجْسٌ ۖ وَمَأْوَىٰهُمْ جَهَنَّمُ جَزَآءَۢ بِمَا كَانُوا۟ يَكْسِبُونَ ﴿٩٥﴾ يَحْلِفُونَ لَكُمْ لِتَرْضَوْا۟ عَنْهُمْ ۖ فَإِن تَرْضَوْا۟ عَنْهُمْ فَإِنَّ ٱللَّهَ لَا يَرْضَىٰ عَنِ ٱلْقَوْمِ ٱلْفَـٰسِقِينَ ﴿٩٦﴾ }.\n\nقَالَ كَعْبٌ: كُنَّا خُلُفْنَا أَيُّهَا الثَّلَاثَةُ عَنْ أَمْرِ أُولَئِكَ الَّذِينَ قَبِلَ مِنْهُمْ رَسُولُ اللهِ ﷺ حِينَ حَلَفُوا لَهُ، فَبَايَعَهُمْ وَاسْتَغْفَرَ لَهُمْ، وَأَرْجَأَ رَسُولُ اللهِ ﷺ أَمْرَنَا حَتَّى قَضَى فِيهِ، فَبِذَلِكَ قَالَ اللهُ عز و جل: { وَعَلَى ٱلثَّلَـٰثَةِ ٱلَّذِينَ خُلِّفُوا۟ }، وَلَيْسَ الَّذِي ذَكَرَ اللهُ مِمَّا خُلِّفْنَا تَخَلُّفَنَا عَنْ الْغَزْوِ، وَإِنَّمَا هُوَ تَخْلِيفُهُ إِيَّانَا وَإِرْجَاؤُهُ أَمْرَنَا عَمَّنْ حَلَفَ لَهُ وَاعْتَذَرَ إِلَيْهِ فَقَبِلَ مِنْهُ.","id":""}],"118":[{"ar":"جاء في صحيح مسلم: قَالَ كَعْبُ بْنُ مَالِكٍ: لَمْ أَتَخَلَّفْ عَنْ رَسُولِ اللهِ ﷺ فِي غَزْوَةٍ غَزَاهَا قَطُّ، إِلَّا فِي غَزْوَةِ تَبُوكَ، غَيْرَ أَنِّي قَدْ تَخَلَّفْتُ فِي غَزْوَةِ بَدْرٍ، وَلَمْ يُعَاتِبْ أَحَداً تَخُلَّفَ عَنْهُ، إِنَّمَا خَرَجَ رَسُولُ اللهِ ﷺ وَالْمُسْلِمُونَ يُرِيدُونَ عِيرَ قُرَيْشٍ، حَتَّى جَمَعَ اللهُ بَيْنَهُمْ وَبَيْنَ عَدُوِّهِمْ، عَلَى غَيْرِ مِيَعَادٍ، وَلَقَدْ شَهِدْتُ مَعَ رَسُولِ الله ﷺ لَيْلَةَ الْعَقَبَةِ، حِينَ تَوَاثَقْنَا عَلَى الْإِسْلَامِ، وَمَا أُحِبُّ أَنَّ لِي بِهَا مَشْهَدَ بَدْرٍ، وَإِنْ كَانَتْ بَدْرٌ أَذْكَرَ فِي النَّاسِ مِنْهَا. وَكَانَ مِنْ خَبَرِي، حِينَ تَخَلَّفْتُ عَنْ رَسُولِ اللهِ ﷺ فِي غَزْوَةِ تَبُوكَ، أَنِّي لَمْ أَكُنْ قَطُّ أَقْوَى وَلَا أَيْسَرَ مِنِّي حِينَ تَخَلَّفْتُ عَنْهُ فِي تِلْكَ الْغَزْوَةِ، وَاللهِ مَا جَمَعْتُ قَبْلَهَا رَاحِلَتَيْنِ قَطُّ، حَتَّى جَمَعْتُهُمَا فِي تِلْكَ الْغَزْوَةِ، فَغَزَاهَا رَسُولُ اللهِ ﷺ فِي حَرٍّ شَدِيدٍ، وَاسْتَقْبَلَ سَفَراً بَعِيداً وَمَفَازَاً، وَاسْتَقْبَلَ عَدُوًّا كَثِيراً، فَجَلَا لِلْمُسْلِمِينَ أَمْرَهُمْ لِيَتَأَهَّبُوا أُهْبَةَ غَزْوِهِمْ، فَأَخْبَرَهُمْ بِوَجْهِهِم الَّذِي يُرِيدُ، وَالْمُسْلِمُونَ مَعَ رَسُولِ اللهِ ﷺ كَثِيرٌ، وَلَا يَجْمَعُهُمْ كِتَابُ حَافِظٍ - يُرِيدُ بِذَلِكَ الدِّيوَانَ -.\n\nقَالَ كَعْبٌ: فَقَلَّ رَجُلٌ يُرِيدُ أَنْ يَتَغَيَّبَ يَظُنُّ أَنَّ ذَلِكَ سَيَخْفَى لَهُ، مَا لَمْ يَنْزِلْ فِيهِ وَحْيٌ مِنْ اللهِ عز و جل، وَغَزَا رَسُولُ اللهِ ﷺ تِلْكَ الْغَزْوَةَ حِينَ طَابَت الثِّمَارُ وَالظِّلَالُ، فَأَنَا إِلَيْهَا أَصْعَرُ، فَتَجَهَّزَ رَسُولُ اللهِ ﷺ وَالْمُسْلِمُونَ مَعَهُ، وَطَفِقْتُ أَغْدُو لِكَيْ أَتَجَهَّزَ مَعَهُمْ، فَأَرْجِعُ وَلَمْ أَقْضِ شَيْئاً، وَأَقُولُ فِي نَفْسِي: أَنَا قَادِرٌ عَلَى ذَلِكَ، إِذَا أَرَدْتُ فَلَمْ يَزَلْ ذَلِكَ يَتَمَادَى بِي حَتَّى اسْتَمَرَّ بِالنَّاسِ الْجِدُّ، فَأَصْبَحَ رَسُولُ اللهِ ﷺ غَادِياً وَالْمُسْلِمُونَ مَعَهُ، وَلَمْ أَقْضِ مِنْ جَهَازِي شَيْئاً، ثُمَّ غَدَوْتُ فَرَجَعْتُ وَلَمْ أَقْضِ شَيْئاً، فَلَمْ يَزَلْ ذَلِكَ يَتَمَادَى بِي حَتَّى أَسْرَعُوا وَتَفَارَطَ الْغَزْوُ، فَهَمَمْتُ أَنْ أَرْتَحِلَ فَأُدْرِكَهُمْ، فَيَا لَيْتَنِي فَعَلْتُ، ثُمَّ لَمْ يُقَدَّرُ ذَلِكَ لِي، فَطَفِقْتُ إِذَا خَرَجْتُ فِي النَّاسِ، بَعْدَ خُرُوجِ رَسُولِ اللهِ، يَحْزُنُنِي أَنِّي لَا أَرَى لِي أُسْوَةً إِلَّا رَجُلًا مَغْمُوصاً عَلَيْهِ فِي النِّفَاقِ، أَوْ رَجُلًا مِمَّنْ عَذَرَ اللهُ مِنْ الضُّعَفَاءِ.\n\nوَلَمْ يَذْكُرْنِي رَسُولُ اللهِ ﷺ حَتَّى بَلَغَ تَبُوكَ، فَقَالَ: وَهُوَ جَالِسٌ فِي الْقَوْمِ بَتَبُوكَ: « مَا فَعَلَ كَعْبُ بْنُ مَالِكٍ؟ » قَالَ رَجُلٌ مِنْ بَنِي سَلِمَةَ: يَا رَسُولَ اللهِ! حَبَسَهُ بُرْدَاهُ وَالنَّظَرُ فِي عِطْفَيْهِ. فَقَالَ لَهُ مُعَاذُ بْنُ جَبَلٍ: بِئْسَ مَا قُلْتَ: وَاللهِ يَا رَسُولَ اللهِ! مَا عَلِمْنَا عَلَيْهِ إِلَّا خَيْراً، فَسَكَتَ رَسُولُ اللهِ ﷺ. فَبَيْنَمَا هُوَ عَلَى ذَلِكَ رَأَى رَجُلًا مُبَيِّضاً يَزُولُ بِهِ السَّرَابُ، فَقَالَ رَسُولُ اللهِ ﷺ: « كُنْ أَبَا خَيْثَمَةَ »، فَإِذَا هُوَ أَبُو خَيْثَمَةَ الْأَنْصَارِيُّ، وَهُوَ الَّذِي تَصَدَّقَ بِصَاعِ التَّمْرِ حِينَ لَمَزَهُ الْمُنَافِقُونَ -.\n\nفَقَالَ كَعْبُ بْنُ مَالِكٍ: فَلَمَّا بَلَغَنِي أَنَّ رَسُولَ اللهِ ﷺ قَدْ تَوَجَّهَ قَافِلًا مِنْ تَبُوكَ، حَضَرَنِي بَثِّي فَطَفِقْتُ أَتَذَكَّرُ الْكَذِبَ وَأَقُولُ: بِمَ أَخْرُجُ مِنْ سَخَطِهِ غَداً؟ وَأسْتَعِينُ عَلَى ذَلِكَ كُلَّ ذِي رَأْيٍ مِنْ أَهْلِي، فَلَمَّا قِيلَ لِي إِنَّ رَسُولَ اللهِ ﷺ قَدْ أَظَلَّ قَادِماً، زَاحَ عَنِّي الْبَاطِلُ حَتَّى عَرَفْتُ أَنِّي لَنْ أَنْجُوَ مِنْهُ بِشَيْءٍ أَبَداً، فَأَجْمَعْتُ صِدْقَهُ، وَصَبَّحَ رَسُولُ اللهِ ﷺ قَادِماً، وَكَانَ إِذَا قَدِمَ مِنْ سَفَرٍ، بَدَأَ بِالْمَسْجِدِ فَرَكَعَ فِيهِ رَكْعَتَيْنِ، ثُمَّ جَلَسَ لِلنَّاسِ، فَلَمَّا فَعَلَ ذَلِكَ جَاءَهُ الْمُخَلَّفُونَ، فَطَفِقُوا يَعْتَذِرُونَ إِلَيْهِ وَيَحْلِفُونَ لَهُ، وَكَانُوا بِضْعَةً وَثَمَانِينَ رَجُلًا، فَقَبِلَ مِنْهُمْ رَسُولُ اللهِ ﷺ عَلَانِيَتَهُمْ وَبَايَعَهُمْ وَاسْتَغْفَرَ لَهُمْ، وَوَكَلَ سَرَائِرَهُمْ إِلَى اللهِ، حَتَّى جِئْتُ، فَلَمَّا سَلَّمْتُ، تَبَسَّمَ تَبَسُّمَ الْمُغْضَبِ ثُمَّ قَالَ: « تَعَالَ » فَجِئْتُ أَمْشِي حَتَّى جَلَسْتُ بَيْنَ يَدَيْهِ، فَقَالَ لِي: « مَا خَلَّفَكَ؟ أَلَمْ تَكُنْ قَدِ ابْتَعْتَ ظَهْرَكَ؟ ». \n\nقَالَ: قُلْتُ: يَا رَسُولَ اللهِ! إِنِّي وَاللهِ لَوْ جَلَسْتُ عِنْدَ غَيْرِكَ مِنْ أَهْلِ الدُّنْيَا، لَرَأَيْتُ أَنِّي سَأَخْرُجُ مِنْ سَخَطِهِ بِعُذْرٍ، وَلَقَدْ أُعْطِيتُ جَدَلًا، وَلَكِنِّي وَاللهِ لَقَدْ عَلِمْتُ، لَئِنْ حَدَّثْتُكَ الْيَوْمَ حَدِيثَ كَذِبٍ تَرْضَى بِهِ عَنِّي، لَيُوشِكَنَّ اللهُ أَنْ يُسْخِطَكَ عَلَيَّ، وَلَئِنْ حَدَّثْتُكَ حَدِيثَ صِدْقٍ تَجِدُ عَلَيَّ فِيهِ، إِنِّي لَأَرْجُو فِيهِ عُقْبَى اللهِ. وَاللهِ! مَا كَانَ لِي عُذْرٌ، وَاللهِ! مَا كُنْتُ قَطُّ أَقْوَى وَلَا أَيْسَرَ مِنِّي حِينَ تَخَلَّفْتُ عَنْكَ. قَالَ رَسُولُ اللهِ ﷺ: « أَمَّا هَذَا، فَقَدْ صَدَقَ، فَقُمْ حَتَّى يَقْضِيَ اللهُ فِيكَ »، فَقُمْتُ، وَثَارَ رِجَالٌ مِنْ بَنِي سَلِمَةَ فَاتَّبَعُونِي، فَقَالُوا لِي: وَاللهِ! مَا عَلِمْنَاكَ أَذْنَبْتَ ذَنْباً قَبْلَ هَذَا، لَقَدْ عَجَرْتَ فِي أَنْ لَا تَكُونَ اعْتَذَرْتَ إِلَى رَسُولِ اللهِ ﷺ بِمَا اعْتَذَرَ بِهِ إِلَيْهِ الْمُخَلَّفُونَ، فَقَدْ كَانَ كَافِيَكَ ذَنْبَكَ اسْتِغْفَارُ رَسُولِ اللهِ ﷺ لَكَ.\n \nقَالَ: فَوَاللهِ! مَا زَالُوا يُؤَنِّبُونَنِي حَتَّى أَرَدْتُ أَنْ أَرْجِعَ إِلَى رَسُولِ اللهِ ﷺ فَأُكَذِّبَ نَفْسِي، قَالَ: ثُمَّ قُلْتُ لَهُمْ: هَلْ لَقِيَ هَذَا مَعِي مِنْ أَحَدٍ؟ قَالُوا: نَعَمْ، لَقِيَهُ مَعَكَ رَجُلَانِ، قَالُوا مِثْلَ مَا قُلْتَ، فَقِيلَ لَهُمَا مِثْلَ مَا قِيلَ لَكَ، قَالَ: قُلْتُ: مَنْ هُمَا؟ قَالُوا: مُرَارَةُ بْنُ الرَّبِيعَةَ الْعَامِرِيُّ، وَهِلَالُ بْنُ أُمَيَّةَ الْوَاقِفِيُّ، قَالَ: فَذَكَرُوا لِي رَجُلَيْنِ صَالِحَيْنِ قَدْ شَهِدَا بَدْراً فِيهِمَا أُسْوَةٌ، قَالَ: فَمَضَيْتُ حِينَ ذَكَرُوهُمَا لِي.\n \nقَالَ: وَنَهَى رَسُولُ اللهِ ﷺ الْمُسْلِمِينَ عَنْ كَلَامِنَا، أَيُّهَا الثَّلَاثَةُ، مِنْ بَيْنِ مَنْ تَخَلَّفَ عَنْهُ.\n \nقَالَ: فَاجْتَنَبَنَا النَّاسُ، وَقَالَ: تَغَيَّرُوا لَنَا حَتَّى تَنَكَّرَتْ لِي فِي نَفْسِيَ الْأَرْضُ، فَمَا هِيَ بِالْأَرْضِ الَّتِي أَعْرِفُ، فَلَبِثْنَا عَلَى ذَلِكَ خَمْسِينَ لَيْلَةً، فَأَمَّا صَاحِبَايَ فَاسْتَكَانَا وَقَعَدَا فِي بُيُوتِهِمَا يَبْكِيَانِ، وَأَمَّا أَنَا فَكُنْتُ أَشَبَّ الْقَوْمِ وَأَجْلَدَهُمْ، فَكُنْتُ أَخْرُجُ فَأَشْهَدُ الصَّلَاةَ وَأَطُوفُ فِي الْأَسْوَاقِ وَلَا يُكَلِّمُنِي أَحَدٌ، وَآتِي رَسُولَ اللهِ ﷺ عَلَيْهِ وَهُوَ فِي مَجْلِسِهِ بَعْدَ الصَّلَاةِ، فَأَقُولُ فِي نَفْسِي: هَلْ حَرَّكَ شَفَتَيْهِ بِرَدِّ السَّلَام، أَمْ لَا؟ ثُمَّ أُصَلِّي قَرِيباً مِنْهُ وَأُسَارِقُهُ النَّظَرَ، فَإِذَا أَقْبَلْتُ عَلَى صَلَاتِي نَظَرَ إِلَيَّ، وَإِذَا الْتَفَتُّ نَحْوَهُ أَعْرَضَ عَنِّي، حَتَّى إِذَا طَالَ ذَلِكَ عَلَيَّ مِنْ جَفْوَةِ الْمُسْلِمِينَ، مَشَيْتُ حَتَّى تَسَوَّرْتُ جِدَارَ حَائِطِ أَبِي قَتَادَةَ، وَهُوَ ابْنُ عَمِّي، وَأَحَبُّ النَّاسِ إِلَيَّ، فَسَلَّمْتُ عَلَيْهِ، فَوَاللهِ! مَا رَدَّ عَلَيَّ السَّلَامَ، فَقُلْتُ لَهُ: يَا أَبَا قَتَادَةَ! أَنْشُدُكَ بِاللَّهِ! هَلْ تَعْلَمَنَّ أَنِّي أُحِبُّ اللهَ وَرَسُولَهُ؟ قَالَ: فَسَكَتَ، فَعُدْتُ فَنَاشَدْتُهُ، فَسَكَتَ فَعُدْتُ فَنَاشَدْتُهُ. فَقَالَ: اللهُ وَرَسُولُهُ أَعْلَمُ، فَفَاضَت عَيْنَايَ، وَتَوَلَّيْتُ، حَتَّى تَسَوَّرْتُ الْجِدَارَ.\n \nفَبَيْنَا أَنَا أَمْشِي فِي سُوق الْمَدِينَةِ، إِذَا نَبَطِيٌّ مِنْ نَبَطِ أَهْلِ الشَّامِ، مِمَّنْ قَدِمَ بِالطَّعَامِ يَبِيعُهُ بِالْمَدِينَةِ، يَقُولُ: مَنْ يَدُلُّ عَلَى كَعْبِ بْنِ مَالِكٍ. قَالَ: فَطَفِقَ النَّاسُ يُشِيرُونَ لَهُ إِلَيَّ، حَتَّى جَاءَنِي فَدَفَعَ إِلَيَّ كِتَاباً مِنْ مَلِكِ غَسَّانَ، وَكُنْتُ كَاتِباً، فَقَرَأَتُهُ فَإِذَا فِيهِ: أَمَّا بَعْدُ، فَإِنَّهُ قَدْ بَلَغَنَا أَنَّ صَاحِبَكَ قَدْ جَفَاكَ، وَلَمْ يَجْعَلْكَ اللهُ بِدَارِ هَوَانٍ وَلَا مَضْيَعَةٍ، فَالْحَقِّ بِنَا نُوَاسِكَ. قَالَ: فَقُلْتُ، حِينَ قَرْأَتُهَا: وَهَذِهِ أَيْضَاً مِنْ الْبَلَاءِ، فَتَيَامَمْتُ بِهَا التَّنُّورَ فَسَجَرْتُهَا بِهَا.\n\nحَتَّى إِذَا مَضَتْ أَرْبَعُونَ مِنْ الْخَمْسِينَ، وَاسْتَلْبَثَ الْوَحْيُ، إِذَا رَسُولُ رَسُولِ اللهِ ﷺ يَأْتِينِي، فَقَالَ: إِنَّ رَسُولَ اللهِ ﷺ يَأْمُرُكَ أَنْ تَعْتَزِلَ امْرَأَتَكَ، قَالَ: فَقُلْتُ: أُطَلِّقُهَا أَمْ مَاذَا أَفْعَلُ؟ قَالَ: لَا، بَل اعْتَزِلْهَا فَلَا تَقْرَبَنَّهَا. قَالَ: فَأَرْسَلَ إِلَى صَاحِبَيَّ بِمِثْلِ ذَلِكَ، قَالَ: فَقُلْتُ لِامْرَأَتِي: الْحَقِي بِأَهْلِكِ فَكُونِي عِنْدَهُمْ حَتَّى يَقْضِيَ اللهُ فِي هَذَا الْأَمْرِ.\n\nقَالَ: فَجَاءَتِ امْرَأَةُ هِلَالَ بْن أُمَيَّةَ رَسُولَ اللهِ ﷺ، فَقَالَتْ لَهُ: يَا رَسُولَ اللهِ! إِنَّ هِلَالَ بْنَ أُمَيَّةَ شَيْخٌ ضَائِعٌ لَيْسَ لَهُ خَادِمٌ، فَهَلْ تَكْرَهُ أَنْ أَخْدُمَهُ؟ قَالَ: « لا، وَلَكِنْ لا يَقْرَبَنَّكِ » فَقَالَتْ: إِنَّهُ، وَاللهِ! مَا بِهِ حَرَكَةٌ إِلَى شَيْءٍ، وَوَاللهِ! مَا زَالَ يَبْكِي مُنْذُ كَانَ مِنْ أَمْرِهِ مَا كَانَ، إِلَى يَوْمِهِ هَذَا.\n \nقَالَ: فَقَالَ لِي بَعْضُ أَهْلِي: لَوْ اسْتَأَذَنْتَ رَسُولَ اللهِ ﷺ فِي امْرَأَتِكَ؟ فَقَدْ أَذِنَ لِامْرَأَةِ هِلَالِ بْنِ أُمَيَّةَ أَنْ تَخْدُمَهُ، قَالَ: فَقُلْتُ: لَا أَسْتَأْذِنَ فِيهَا رَسُولَ اللهِ ﷺ، وَمَا يُدْرِينِي مَاذَا يَقُولُ رَسُولُ اللهِ ﷺ إِذَا اسْتَأَذَنْتُهُ فِيهَا، وَأَنَا رَجُلٌ شَابٌّ.\n \nقَالَ: فَلَبِثْتُ بِذَلِكَ عَشْرَ لَيَالٍ، فَكَمُلَ لَنَا خَمْسُونَ لَيْلَةً مِنْ حِينَ نُهِيَ عَنْ كَلَامِنَا، قَالَ: ثُمَّ صَلَّيْتُ صَلَاةَ الْفَجْرِ صَبَاحَ خَمْسِينَ لَيْلَةً، عَلَى ظَهْرِ بَيْتٍ مِنْ بُيُوتِنَا، فَبَيْنَا أَنَا جَالِسٌ عَلَى الْحَالِ الَّتِي ذَكَرَ اللهُ عز و جل مِنَّا، قَدْ ضَاقَتْ عَلَيَّ نَفْسِي، وَضَاقَتْ عَلَيَّ الْأَرْضُ بِمَا رَحُبَتْ، سَمِعْتُ صَوْتَ صَارِخٍ أَوْفَى عَلَى سَلْعٍ يَقُولُ بِأَعْلَى صَوْتِهِ: يَا كَعْبَ بْنَ مَالِكٍ. أَبْشِرْ. قَالَ: فَخَرَرْتُ ساجِداً، وَعَرَفْتُ أَنْ قَدْ جَاءَ فَرَجٌ.\n\nقَالَ: فَآذَنَ رَسُولُ اللهِ ﷺ النَّاسَ بِتَوْبَةِ اللهِ عَلَيْنَا، حِينَ صَلَّى صَلَاةَ الْفَجْرِ، فَذَهَبَ النَّاسُ يُبَشِّرُونَنَا، فَذَهَبَ قِبَلَ صَاحِبَيَّ مُبَشِّرُونَ، وَرَكَضَ رَجُلٌ إِلَيَّ فَرَساً، وَسَعَى سَاعٍ مِنْ أَسْلَمَ قِبَلِي وَأَوْفَى الْجَبَلَ، فَكَانَ الصَّوْتُ أَسْرَعَ مِنْ الْفَرَسِ، فَلَمَّا جَاءَنِي الَّذِي سَمِعْتُ صَوْتَهُ يُبَشِّرُنِي، فَنَزَعْتُ لَهُ ثَوْبَيَّ فَكَسَوْتُهُمَا إِيَّاهُ بِبِشَارَته، وَاللهِ! مَا أَمْلِكُ غَيْرَهُمَا يَوْمَئِذٍ، وَاسْتَعَرْتُ ثَوْبَيْنِ فَلَبِسْتُهُمَا، فَانْطَلَقْتُ أَتَأَمَّمُ رَسُولَ اللهِ ﷺ يَتَلَقَّانِي النَّاسُ فَوْجاً فَوْجاً، يُهَنِّئُونِي بِالْتَّوْبَةِ وَيَقُولُونَ: لِتَهْنِئِكَ تَوْبَةُ اللهِ عَلَيْكَ. حَتَّى دَخَلْتُ الْمَسْجِدَ، فَإِذَا رَسُولُ اللهَ ﷺ جَالِسٌ فِي الْمَسْجِدِ، وَحَوْلَهُ النَّاسُ، فَقَامَ طَلْحَةُ بْنُ عُبَيْدِ اللهِ يُهَرْوِلُ حَتَّى صَافَحَنِي وَهَنَّأَنِي، وَاللهِ مَا قَامَ رَجُلٌ مِنْ الْمُهَاجِرِينَ غَيْرُهُ.\n\nقَالَ: فَكَانَ كَعْبٌ لَا يَنْسَاهَا لِطَلْحَةَ.\n\nقَالَ كَعْبٌ: فَلَمَّا سَلَّمْتُ عَلَى رَسُولِ اللهِ ﷺ قَالَ: وَهُوَ يَبْرُقُ وَجْهَهُ مِنْ السُّرورِ، وَيَقُولُ: « أَبْشِرْ بِخَيْرِ يَوْمٍ مَرَّ عَلَيْكَ مُنْذُ وَلَدَتْكَ أُمُّكَ »، قَالَ: فَقُلْتُ: أَمِنْ عِنْدِكَ؟ يَا رَسُولَ اللهِ. أَمْ مِنْ عِنْدِ اللهِ؟ فَقَالَ: « لَا، بَلْ مِنْ عِنْدِ اللهِ »، وَكَانَ رَسُولُ اللهِ ﷺ إِذَا سُرَّ اسْتَنَارَ وَجْهُهُ كَأَنَّ وَجْهَهُ قِطْعَةُ قَمَرٍ، قَالَ: وَكُنَّا نَعْرِفُ ذَلِكَ.\n\nقَالَ: فَلَمَّا جَلَسْتُ بَيْنَ يَدَيْهِ قُلْتُ: يَا رَسُولَ اللهِ! إِنَّ مِنْ تَوْبَتِي أَنْ أَنْخِلَعَ مِنْ مَالِي صَدَقَةً إِلَى اللهِ وَإِلَى رَسُولِهِ ﷺ. فَقَالَ رَسُولُ اللهِ ﷺ: « أَمْسِكْ بَعْضَ مَالِكَ فَهُوَ خَيْرٌ لَكَ »، قَالَ: فَقُلْتُ: فَإِنِّي أُمْسِكُ سَهْمِيَ الَّذِي بِخَيْبَرَ، قَالَ: وَقُلْتُ: يَا رَسُولَ اللهِ! إِنَّ اللهَ إِنَّمَا أَنْجَانِي بِالصِّدْقِ، وَإِنَّ مِنْ تَوْبَتِي أَنْ لَا أُحَدِّثَ إِلَّا صِدْقاً مَا بَقِيتُ. قَالَ: فَوَاللهِ! مَا عَلِمْتُ أَنَّ أَحَداً مِنْ الْمُسْلِمِينَ أَبْلَاهُ اللهُ فِي صِدْقِ الْحَدِيثِ، مُنْذُ ذَكَرْتُ ذَلِكَ لِرَسُولِ اللهِ ﷺ إِلَى يَوْمِي هَذَا، أَحْسَنَ مِمَّا أَبْلَانِي اللهُ بِهِ، وَاللهِ! مَا تَعَمَّدْتُ كَذِبَةً مُنْذُ قُلْتُ ذَلِكَ لِرَسُولِ اللهِ ﷺ، إِلَى يَوْمِي هَذَا وَإِنِّي لَأَرْجُو أَنْ يَحْفَظَنِي اللهُ فِيمَا بَقِيَ.\n \nقَالَ: فَأَنزلَ اللهُ عز و جل: { لَّقَد تَّابَ ٱللَّهُ عَلَى ٱلنَّبِىِّ وَٱلْمُهَـٰجِرِينَ وَٱلْأَنصَارِ ٱلَّذِينَ ٱتَّبَعُوهُ فِى سَاعَةِ ٱلْعُسْرَةِ مِنۢ بَعْدِ مَا كَادَ يَزِيغُ قُلُوبُ فَرِيقٍ مِّنْهُمْ ثُمَّ تَابَ عَلَيْهِمْ ۚ إِنَّهُۥ بِهِمْ رَءُوفٌ رَّحِيمٌ ﴿١١٧﴾ وَعَلَى ٱلثَّلَـٰثَةِ ٱلَّذِينَ خُلِّفُوا۟ حَتَّىٰٓ إِذَا ضَاقَتْ عَلَيْهِمُ ٱلْأَرْضُ بِمَا رَحُبَتْ وَضَاقَتْ عَلَيْهِمْ أَنفُسُهُمْ وَظَنُّوٓا۟ أَن لَّا مَلْجَأَ مِنَ ٱللَّهِ إِلَّآ إِلَيْهِ ثُمَّ تَابَ عَلَيْهِمْ لِيَتُوبُوٓا۟ ۚ إِنَّ ٱللَّهَ هُوَ ٱلتَّوَّابُ ٱلرَّحِيمُ ﴿١١٨﴾ }، حَتَّى بَلَغَ: { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ ٱللَّهَ وَكُونُوا۟ مَعَ ٱلصَّـٰدِقِينَ ﴿١١٩﴾ }.\n\nقَالَ كَعْبٌ: وَاللهِ! مَا أَنْعَمَ اللهُ عَلَيَّ مِنْ نِعْمَةٍ قَطُّ، بَعْدَ إِذْ هَدَانِي اللهُ لِلْإِسْلَامِ، أَعْظَمَ فِي نَفْسِي مِنْ صِدْقِي رَسُولَ اللهِ ﷺ، أَنْ لَا أَكُونَ كَذَبْتُهُ فَأَهْلِكَ كَمَا هَلَكَ الَّذِينَ كَذَبُوا، إِنَّ اللهَ قَالَ لِلَّذِينَ كَذَبُوا حِينَ أَنْزَلَ الْوَحْيَ شَرَّ مَا قَالَ لِأَحَدٍ، وَقَالَ اللهُ: { سَيَحْلِفُونَ بِٱللَّهِ لَكُمْ إِذَا ٱنقَلَبْتُمْ إِلَيْهِمْ لِتُعْرِضُوا۟ عَنْهُمْ ۖ فَأَعْرِضُوا۟ عَنْهُمْ ۖ إِنَّهُمْ رِجْسٌ ۖ وَمَأْوَىٰهُمْ جَهَنَّمُ جَزَآءَۢ بِمَا كَانُوا۟ يَكْسِبُونَ ﴿٩٥﴾ يَحْلِفُونَ لَكُمْ لِتَرْضَوْا۟ عَنْهُمْ ۖ فَإِن تَرْضَوْا۟ عَنْهُمْ فَإِنَّ ٱللَّهَ لَا يَرْضَىٰ عَنِ ٱلْقَوْمِ ٱلْفَـٰسِقِينَ ﴿٩٦﴾ }.\n\nقَالَ كَعْبٌ: كُنَّا خُلُفْنَا أَيُّهَا الثَّلَاثَةُ عَنْ أَمْرِ أُولَئِكَ الَّذِينَ قَبِلَ مِنْهُمْ رَسُولُ اللهِ ﷺ حِينَ حَلَفُوا لَهُ، فَبَايَعَهُمْ وَاسْتَغْفَرَ لَهُمْ، وَأَرْجَأَ رَسُولُ اللهِ ﷺ أَمْرَنَا حَتَّى قَضَى فِيهِ، فَبِذَلِكَ قَالَ اللهُ عز و جل: { وَعَلَى ٱلثَّلَـٰثَةِ ٱلَّذِينَ خُلِّفُوا۟ }، وَلَيْسَ الَّذِي ذَكَرَ اللهُ مِمَّا خُلِّفْنَا تَخَلُّفَنَا عَنْ الْغَزْوِ، وَإِنَّمَا هُوَ تَخْلِيفُهُ إِيَّانَا وَإِرْجَاؤُهُ أَمْرَنَا عَمَّنْ حَلَفَ لَهُ وَاعْتَذَرَ إِلَيْهِ فَقَبِلَ مِنْهُ.","id":""}]},"mapping_ayat":{"9:9":[{"p":"Bukhari","n":3997,"ar":"حَدَّثَنِي عُبَيْدُ بْنُ إِسْمَاعِيلَ عَنْ أَبِي أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ جَاءَ ابْنُهُ عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ أَنْ يُعْطِيَهُ قَمِيصَهُ يُكَفِّنُ فِيهِ أَبَاهُ فَأَعْطَاهُ ثُمَّ سَأَلَهُ أَنْ يُصَلِّيَ عَلَيْهِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَقَامَ عُمَرُ فَأَخَذَ بِثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ تُصَلِّي عَلَيْهِ وَقَدْ نَهَاكَ رَبُّكَ أَنْ تُصَلِّيَ عَلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا خَيَّرَنِي اللَّهُ فَقَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً }وَسَأَزِيدُهُ عَلَى السَّبْعِينَ قَالَ إِنَّهُ مُنَافِقٌ قَالَ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }","trj":"Telah menceritakan kepadaku ['Ubaid bin Isma'il] dari [Abu Usamah] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dia berkata; \"Ketika Abdullah bin Ubay meninggal dunia. anak laki-lakinya -yaitu Abdulah bin Abdullah- datang kepada Rasulullah shallallahu 'alaihi wasallam seraya memohon kepada beIiau agar sudi memberikan baju beliau kepada Abdullah untuk kain kafan ayahnya, Abdullah bin Ubay bin Salul. Lalu Rasulullah shallallahu 'alaihi wasallam memberikan bajunya kepada Abdullah. setelah itu, Abdullah juga memohon Rasulullah agar beliau berkenan menshalati jenazah ayahnya. Kemudian Rasulullah pun bersiap-siap untuk menshalati jenazah Abdullah bin Ubay, hingga akhirnya Umar berdiri dan menarik baju Rasulullah seraya berkata, \"Ya Rasulullah, apakah engkau akan menshalati jenazah Abdullah bin Ubay sedangkan Allah telah melarang untuk menshalatinya?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Sesungguhnya Allah Subhanahu wa Ta'ala telah memberikan pilihan kepadaku.\" Lalu beliau membacakan ayat yang berbunyi; \"Kamu memohonkun ampun bagi orang-orang munafik atau tidak kamu mohonkan ampun bagi mereka, maka hal itu adalah sama saja. sekalipun kamu memohonkan ampun bagi mereka tujuh puluh kali (Qs. At-Taubah 9: 80). Oleh karena itu, aku akan menambah istighfar lebih dari tujuh puluh kali untuknya.\" Umar bin Khaththab berkata, \"Ya Rasulullah, sesungguhnya Ia adalah orang munafik?.\" Tetapi, rupanya Rasulullah shallallahu 'alaihi wasallam tetap saja menshalatinya, hingga Allah menurunkan ayat Al Qur'an: \"Janganlah kamu sekali-kali menshalati jenazah seorang di antara orang-orang munafik dan janganlah kamu berdiri di atas kuburnya.\" (Qs. At-Taubah 9: 84)."},{"p":"Bukhari","n":3999,"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ قَالَ لَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ جَاءَ ابْنُهُ عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَاهُ قَمِيصَهُ وَأَمَرَهُ أَنْ يُكَفِّنَهُ فِيهِ ثُمَّ قَامَ يُصَلِّي عَلَيْهِ فَأَخَذَ عُمَرُ بْنُ الْخَطَّابِ بِثَوْبِهِ فَقَالَ تُصَلِّي عَلَيْهِ وَهُوَ مُنَافِقٌ وَقَدْ نَهَاكَ اللَّهُ أَنْ تَسْتَغْفِرَ لَهُمْ قَالَ إِنَّمَا خَيَّرَنِي اللَّهُ أَوْ أَخْبَرَنِي اللَّهُ فَقَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً فَلَنْ يَغْفِرَ اللَّهُ لَهُمْ }فَقَالَ سَأَزِيدُهُ عَلَى سَبْعِينَ قَالَ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَلَّيْنَا مَعَهُ ثُمَّ أَنْزَلَ اللَّهُ عَلَيْهِ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ إِنَّهُمْ كَفَرُوا بِاللَّهِ وَرَسُولِهِ وَمَاتُوا وَهُمْ فَاسِقُونَ }","trj":"Telah menceritakan kepadaku [Ibrahim bin Al Mundzir] Telah menceritakan kepada kami [Anas bin 'Iyadl] dari ['Ubaidillah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dia berkata; \"Ketika Abdullah bin Ubay meninggal dunia. anak laki-lakinya -yaitu Abdulah bin Abdullah- datang kepada Rasulullah shallallahu 'alaihi wasallam dan beliau berikan bajunya dan beliau perintahkannya untuk mengafani ayahnya dengan bajunya tersebut. Lalu Rasulullah shallallahu 'alaihi wasallam menshalati jenazah ayah Abdullah bin Abdullah bin Ubbay. Hingga akhirnya Umar menarik baju Rasulullah seraya berkata; \"Ya Rasulullah, apakah engkau akan menshalati jenazah Abdullah bin Ubay sedangkan dia itu orang munafik? Padahal Allah telah melarang engkau memintakan ampun untuknya?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Sesungguhnya Allah Subhanahu wa Ta'ala telah memberikan pilihan kepadaku atau mengabariku.\" Lalu beliau membacakan ayat yang berbunyi; \"Kamu memohonkun ampun bagi orang-orang munafik atau tidak kamu mohonkan ampun bagi mereka, maka hal itu adalah sama saja. sekalipun kamu memohonkan ampun bagi mereka tujuh puluh kali sekali-kali Allah tidak akan mengampuni mereka (Qs. At-Taubah 9: 80). Rasulullah shallallahu 'alaihi wasallam bersabda: Aku akan menambah istighfar lebih dari tujuh puluh kali untuknya.\" Maka Rasulullah shallallahu 'alaihi wasallam tetap saja menshalatinya dan kami pun shalat bersamanya hingga Allah menurunkan ayat Al Qur'an: \"Janganlah kamu sekali-kali menshalati jenazah seorang di antara orang-orang munafik dan janganlah kamu berdiri di atas kuburnya, sesungguhnya mereka telah kafir kepada Allah dan Rasul-Nya dan mereka mati dalam keadaan munafiq.\" (Qs. At-Taubah 9: 84)."},{"p":"Muslim","n":4077,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَلَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ جَاءَ ابْنُهُ عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ أَنْ يُعْطِيَهُ قَمِيصَهُ أَنْ يُكَفِّنَ فِيهِ أَبَاهُ فَأَعْطَاهُ ثُمَّ سَأَلَهُ أَنْ يُصَلِّيَ عَلَيْهِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَقَامَ عُمَرُ فَأَخَذَ بِثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَتُصَلِّي عَلَيْهِ وَقَدْ نَهَاكَ اللَّهُ أَنْ تُصَلِّيَ عَلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا خَيَّرَنِي اللَّهُ فَقَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً }وَسَأَزِيدُ عَلَى سَبْعِينَ قَالَ إِنَّهُ مُنَافِقٌ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }و حَدَّثَنَاه مُحَمَّدُ بْنُ الْمُثَنَّى وَعُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا يَحْيَى وَهُوَ الْقَطَّانُ عَنْ عُبَيْدِ اللَّهِ بِهَذَا الْإِسْنَادِ فِي مَعْنَى حَدِيثِ أَبِي أُسَامَةَ وَزَادَ قَالَ فَتَرَكَ الصَّلَاةَ عَلَيْهِمْ","trj":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah]; Telah menceritakan kepada kami [Abu Usamah]; Telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar] dia berkata; \"Ketika Abdullah bin Ubay bin Salul meninggal dunia. anak laki-lakinya -yaitu Abdulah bin Abdullah- datang kepada Rasulullah shallallahu 'alaihi wasallam seraya memohon kepada beIiau agar sudi memberikan baju beliau kepada Abdullah untuk kain kafan ayahnya, Abdullah bin Ubay bin Salul. Lalu Rasulullah shallallahu 'alaihi wasallam memberikan bajunya kepada Abdullah. Setelah itu, Abdullah juga memohon Rasulullah agar beliau berkenan menshalati jenazah ayahnya. Kemudian Rasulullah pun bersiap-siap untuk menshalati jenazah Abdullah bin Ubay, hingga akhirnya Umar berdiri dan menarik baju Rasulullah seraya berkata, \"Ya Rasulullah, apakah engkau akan menshalati jenazah Abdullah bin Ubay sedangkan Allah telah melarang untuk menshalatinya?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Sesungguhnya Allah Subhanahu wa Ta'ala telah memberikan pilihan kepadaku.\" Lalu beliau membacakan ayat yang berbunyi; \"Kamu memohonkun ampun bagi orang-orang munafik atau tidak kamu mohonkan ampun bagi mereka, maka hal itu adalah sama saja. sekalipun kamu memohonkan ampun bagi mereka tujuh puluh kali (Qs. At-Taubah 9: 80). Oleh karena itu, aku akan menambah istighfar lebih dari tujuh puluh kali untuknya.\" Umar bin Khaththab berkata, \"Ya Rasulullah, sesungguhnya Ia adalah orang munafik?.\" Tetapi, rupanya Rasulullah shallallahu 'alaihi wasallam tetap saja menshalatinya, hingga Allah menurunkan ayat Al Qur'an: \"Janganlah kamu sekali-kali menshalati jenazah seorang di antara orang-orang munafik dan janganlah kamu berdiri di atas kuburnya.\" (Qs. At-Taubah 9: 84). Dan telah menceritakannya kepada kami [Muhammad bin Al Mutsanna] dan ['Ubaidullah bin Sa'id] keduanya berkata; Telah menceritakan kepada kami [Yahya] yaitu Al Qaththan dari ['Ubaidillah] melalui jalur ini mengenai Hadits yang semakna dengan Abu Usamah namun ada tambahan; 'Kemudian beliau meninggalkan shalat untuk mereka (orang-orang munafik)."},{"p":"Nasa'i","n":1895,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا حُجَيْنُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَلَمَّا مَاتَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ دُعِيَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَلَمَّا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَثَبْتُ إِلَيْهِ فَقُلْتُ يَا رَسُولَ اللَّهِ تُصَلِّي عَلَى ابْنِ أُبَيٍّ وَقَدْ قَالَ يَوْمَ كَذَا وَكَذَا كَذَا وَكَذَا أُعَدِّدُ عَلَيْهِ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَخِّرْ عَنِّي يَا عُمَرُ فَلَمَّا أَكْثَرْتُ عَلَيْهِ قَالَ إِنِّي قَدْ خُيِّرْتُ فَاخْتَرْتُ فَلَوْ عَلِمْتُ أَنِّي لَوْ زِدْتُ عَلَى السَّبْعِينَ غُفِرَ لَهُ لَزِدْتُ عَلَيْهَا فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ انْصَرَفَ فَلَمْ يَمْكُثْ إِلَّا يَسِيرًا حَتَّى نَزَلَتْ الْآيَتَانِ مِنْ بَرَاءَةَ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ إِنَّهُمْ كَفَرُوا بِاللَّهِ وَرَسُولِهِ وَمَاتُوا وَهُمْ فَاسِقُونَ }فَعَجِبْتُ بَعْدُ مِنْ جُرْأَتِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ وَاللَّهُ وَرَسُولُهُ أَعْلَمُ","trj":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Hujain bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah] dari ['Abdullah bin 'Abbas] dari ['Umar bin Al Khaththab] dia berkata; Setelah Abdullah bin Ubai bin Salul meninggal dunia, Rasulullah shallallahu 'alaihi wasallam diundang untuk menshalatinya. Setelah Rasulullah shallallahu 'alaihi wasallam berdiri untuk melaksanakan Shalat, aku meloncat ke arah beliau, lalu aku berkata, \"Wahai Rasulullah shallallahu 'alaihi wasallam, engkau menshalati Ibnu Ubbay, padahal ia telah mengatakan hari ini dan itu begini dan itu begitu?! Aku menyebut kejelekannya, Rasulullah shallallahu 'alaihi wasallam tersenyum seraya bersabda: \"Tundalah -perkataanmu- dariku wahai Umar!\" setelah aku mengulang menyebut-nyebut kejelekannya, beliau bersabda: \" Aku telah diberikan pilihan, aku memilih. Andaikata aku tahu, kalau aku menambahnya lebih dari tujuh puluh ia akan diampuni, niscaya aku menambahnya!.\"Lalu Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat atasnya, kemudian beliau pergi dan tidak berada di tempat itu kecuali hanya sejenak, hingga turun dua ayat dari surah Bara'ah, \"(Dan janganlah kamu sekali-kali menshalatkan (jenazah) seorang yang mati di antara mereka, dan janganlah kamu berdiri (mendo'akan) di kuburnya. mereka telah kafir kepada Allah dan RasulNya dan mereka mati dalam keadaan fasik.\" (Qs. At-Taubah 9: 84). Setelah itu aku heran atas keberanianku terhadap Rasulullah shallallahu 'alaihi wasallam ketika itu. Dan hanya Allah dan Rasul-Nya yang lebih mengatahui.\""},{"p":"Nasa'i","n":1963,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مُحَمَّدٌ وَهُوَ ابْنُ ثَوْرٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِيهِ قَالَلَمَّا حَضَرَتْ أَبَا طَالِبٍ الْوَفَاةُ دَخَلَ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ فَقَالَ أَيْ عَمِّ قُلْ لَا إِلَهَ إِلَّا اللَّهُ كَلِمَةً أُحَاجُّ لَكَ بِهَا عِنْدَ اللَّهِ عَزَّ وَجَلَّ فَقَالَ لَهُ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ يَا أَبَا طَالِبٍ أَتَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ فَلَمْ يَزَالَا يُكَلِّمَانِهِ حَتَّى كَانَ آخِرُ شَيْءٍ كَلَّمَهُمْ بِهِ عَلَى مِلَّةِ عَبْدِ الْمُطَّلِبِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْكَ فَنَزَلَتْ{ مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ }وَنَزَلَتْ{ إِنَّكَ لَا تَهْدِي مَنْ أَحْبَبْتَ }","trj":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Muhammad bin Tsaur] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [bapaknya] dia berkata; \"Ketika Abu Thalib mendekati ajalnya, Rasulullah shallallahu 'alaihi wasallam masuk menemuinya dan di dekatnya ada Abu Jahal dan Abdullah bin Abu Umayyah. Lalu beliau bersabda: \"Wahai pamanku, ucapkanlah 'Laa Ilaaha Illallah (tidak ada sesembahan yang berhak di sembah selain Allah) ' satu kalimat yang dengannya aku akan berhujah untukmu di sisi Allah -Azza wa Jalla-.\" Maka Abu Jahal dan Abdullah bin Umayyah berkata kepadanya; \"Wahai Abu Thalib, Apakah kamu benci dengan agama Abdul Muthalib?\" dan keduanya tetap mangatakan hal itu kepadanya, hingga kalimat terakhir yang ia ucapkan kepada mereka ialah, bahwa ia tetap berpegang pada agama Abdul Muthalib! Maka Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Sungguh akan aku akan mintakan ampunan untukmu selama aku tidak dilarang.\" Lalu turunlah ayat, \"Tidak sepatutnya bagi Nabi dan orang-orang yang beriman memintakan ampun (kepada Allah) bagi orang-orang musyrik.\" (Qs. At Taubah 9; 113) Dan turun ayat, \" Kamu tidak akan dapat memberi petunjuk kepada orang yang kamu kasihi.\" (Qs. Al Qashash 28: 56)."},{"p":"Nasa'i","n":1964,"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْخَلِيلِ عَنْ عَلِيٍّ قَالَسَمِعْتُ رَجُلًا يَسْتَغْفِرُ لِأَبَوَيْهِ وَهُمَا مُشْرِكَانِ فَقُلْتُ أَتَسْتَغْفِرُ لَهُمَا وَهُمَا مُشْرِكَانِ فَقَالَ أَوَ لَمْ يَسْتَغْفِرْ إِبْرَاهِيمُ لِأَبِيهِ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَنَزَلَتْ{ وَمَا كَانَ اسْتِغْفَارُ إِبْرَاهِيمَ لِأَبِيهِ إِلَّا عَنْ مَوْعِدَةٍ وَعَدَهَا إِيَّاهُ }","trj":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dari [Sufyan] dari [Abu Ishaq] dari [Abul Khalil] dari ['Ali] dia berkata; Aku mendengar seseorang memintakan ampunan bagi kedua orang tuanya sedang keduanya musyrik, maka aku bertanya kepadanya; \"Apakah engkau memintakan ampunan untuk mereka berdua, padahal mereka musyrik?\" ia menjawab, \"Bukankah Nabi Ibrahim juga memintakan ampunan untuk bapaknya?\" lalu aku menemui Nabi shallallahu 'alaihi wasallam dan aku ceritakan hal itu kepada beliau, lalu turunlah ayat, \"Dan permintaan ampun dari Ibrahim (kepada Allah) untuk bapaknya tidak lain hanyalah karena suatu janji yang telah diikrarkannya kepada bapaknya itu.\" (Qs. At Taubah 9: 114)"},{"p":"Nasa'i","n":2398,"ar":"أَخْبَرَنَا بِشْرُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مَسْعُودٍ قَالَلَمَّا أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالصَّدَقَةِ فَتَصَدَّقَ أَبُو عَقِيلٍ بِنِصْفِ صَاعٍ وَجَاءَ إِنْسَانٌ بِشَيْءٍ أَكْثَرَ مِنْهُ فَقَالَ الْمُنَافِقُونَ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَغَنِيٌّ عَنْ صَدَقَةِ هَذَا وَمَا فَعَلَ هَذَا الْآخَرُ إِلَّا رِيَاءً فَنَزَلَتْ{ الَّذِينَ يَلْمِزُونَ الْمُطَّوِّعِينَ مِنْ الْمُؤْمِنِينَ فِي الصَّدَقَاتِ وَالَّذِينَ لَا يَجِدُونَ إِلَّا جُهْدَهُمْ }","trj":"Telah mengabarkan kepada kami [Bisyr bin Khalid] dia berkata; Telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Sulaiman] dari [Abu Wa'il] dari [Abu Mas'ud] dia berkata; \"Setelah Rasulullah Shalallahu 'Alaihi Wa Sallam memerintahkan kami untuk bersedekah, maka Abu Uqail bersedekah dengan satu sha', dan datang seseorang dengan membawa lebih banyak dari itu, lalu orang-orang munafik berkata; \" Allah Azza Wa Jalla benar-benar tidak membutuhkan sedekah orang ini, orang ini tidak melakukannya kecuali dengan riya'. Lalu turun ayat: 'Orang-orang munafik itu yaitu orang-orang yang mencela orang-orang mukmin yang memberi sedekah dengan sukarela dan (mencela) orang-orang yang tidak memperoleh (untuk disedekahkan) selain sekadar kesanggupannya.\" (Qs. At Taubah 9: 79)."}],"9:18":[{"p":"Darimi","n":842,"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ الْحُمَيْدِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ دَرَّاجٍ أَبِي السَّمْحِ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَأَيْتُمْ الرَّجُلَ يَعْتَادُ الْمَسَاجِدَ فَاشْهَدُوا لَهُ بِالْإِيمَانِ فَإِنَّ اللَّهَ يَقُولُ { إِنَّمَا يَعْمُرُ مَسَاجِدَ اللَّهِ مَنْ آمَنَ بِاللَّهِ }","trj":"Telah mengabarkan kepada kami [Abdullah bin Az Zubair Al Humaidi] telah menceritakan kepada kami [Abdullah bin Wahb] dari ['Amru bin Al Harits] dari [Darraj Abu As Samah] dari [Abu Al Haitsam] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila kalian melihat seorang laki-laki yang terbiasa mendatangi masjid maka bersaksilah atas keimanannya, sesungguhnya Allah berfirman: '(Sesungguhnya hanyalah yang memakmurkan masjid itu adalah orang-orang yang beriman kepada Allah) ' (Qs. At Taubah: 18)."}],"9:19":[{"p":"Muslim","n":3251,"ar":"حَدَّثَنِي حَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ حَدَّثَنَا أَبُو تَوْبَةَ حَدَّثَنَا مُعَاوِيَةُ بْنُ سَلَّامٍ عَنْ زَيْدِ بْنِ سَلَّامٍ أَنَّهُ سَمِعَ أَبَا سَلَّامٍ قَالَ حَدَّثَنِي النُّعْمَانُ بْنُ بَشِيرٍ قَالَكُنْتُ عِنْدَ مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَجُلٌ مَا أُبَالِي أَنْ لَا أَعْمَلَ عَمَلًا بَعْدَ الْإِسْلَامِ إِلَّا أَنْ أُسْقِيَ الْحَاجَّ وَقَالَ آخَرُ مَا أُبَالِي أَنْ لَا أَعْمَلَ عَمَلًا بَعْدَ الْإِسْلَامِ إِلَّا أَنْ أَعْمُرَ الْمَسْجِدَ الْحَرَامَ وَقَالَ آخَرُ الْجِهَادُ فِي سَبِيلِ اللَّهِ أَفْضَلُ مِمَّا قُلْتُمْ فَزَجَرَهُمْ عُمَرُ وَقَالَ لَا تَرْفَعُوا أَصْوَاتَكُمْ عِنْدَ مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَوْمُ الْجُمُعَةِ وَلَكِنْ إِذَا صَلَّيْتُ الْجُمُعَةَ دَخَلْتُ فَاسْتَفْتَيْتُهُ فِيمَا اخْتَلَفْتُمْ فِيهِ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ أَجَعَلْتُمْ سِقَايَةَ الْحَاجِّ وَعِمَارَةَ الْمَسْجِدِ الْحَرَامِ كَمَنْ آمَنَ بِاللَّهِ وَالْيَوْمِ الْآخِرِ }الْآيَةَ إِلَى آخِرِهَاو حَدَّثَنِيهِ عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا مُعَاوِيَةُ أَخْبَرَنِي زَيْدٌ أَنَّهُ سَمِعَ أَبَا سَلَّامٍ قَالَ حَدَّثَنِي النُّعْمَانُ بْنُ بَشِيرٍ قَالَ كُنْتُ عِنْدَ مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ أَبِي تَوْبَةَ","trj":"Telah menceritakan kepadaku [Hasan bin Ali Al Khulwani] telah menceritakan kepada kami [Abu Taubah] telah menceritakan kepada kami [Mu'awiyah bin Salam] dari [Zaid bin Salam] bahwa dia mendengar [Abu Salam] berkata; telah menceritakan kepadaku [An Nu'man bin Basyir] dia berkata, \"Saya pernah berada di sisi mimbar Rasulullah shallallahu 'alaihi wasallam, tiba-tiba saya mendengar seorang laki-laki berkata, \"Saya tidak mementingkan suatu amalan setelah saya masuk Islam kecuali menjamu para Jama'ah haji.\" Sedangkan yang lain mengatakan, \"Saya tidak mementingkan suatu amalan setelah saya masuk Islam kecuali memakmurkan Masjidil Haram.\" Dan yang lainnya lagi mengatakan, \"Jihad fi sabilillah itu lebih baik dari apa yang kalian katakan tadi.\" Lalu mereka ditegur oleh Umar saraya berkata, \"Janganlah kalian meninggikan suara kalian di sisi mimbar Rasulullah shallallahu 'alaihi wasallam, bukankah hari ini adalah hari Jum'at?\" Setelah selesai shalat Jum'at, saya datang menemui beliau untuk meminta fatwa tentang apa yang diperselisihkan mereka, maka turunkah ayat: '(Apakah (orang-orang) yang memberi minuman orang-orang yang mengerjakan haji dan mengurus Masjidilharam kamu samakan dengan orang-orang yang beriman kepada Allah dan hari Kemudian serta bejihad di jalan Allah? …) ' (Qs. At Taubah: 19) sampai akhir ayat.\" Dan telah menceritakan kepadaku [Abdullah bin Abdurrahman Ad Darimi] telah menceritakan kepada kami [Yahya bin Hasan] telah menceritakan kepada kami [Mu'awiyah] telah mengabarkan kepadaku [Zaid] bahwa dia mendengar [Abu Salam] berkata; telah menceritakan kepadaku [An Nu'man bin Basyir] dia berkata, \"Ketika saya berada di sisi mimbar Rasulullah shallallahu 'alaihi wasallam…seperti hadits Abu Taubah.\""}],"9:28":[{"p":"Nasa'i","n":1963,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مُحَمَّدٌ وَهُوَ ابْنُ ثَوْرٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِيهِ قَالَلَمَّا حَضَرَتْ أَبَا طَالِبٍ الْوَفَاةُ دَخَلَ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ فَقَالَ أَيْ عَمِّ قُلْ لَا إِلَهَ إِلَّا اللَّهُ كَلِمَةً أُحَاجُّ لَكَ بِهَا عِنْدَ اللَّهِ عَزَّ وَجَلَّ فَقَالَ لَهُ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ يَا أَبَا طَالِبٍ أَتَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ فَلَمْ يَزَالَا يُكَلِّمَانِهِ حَتَّى كَانَ آخِرُ شَيْءٍ كَلَّمَهُمْ بِهِ عَلَى مِلَّةِ عَبْدِ الْمُطَّلِبِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْكَ فَنَزَلَتْ{ مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ }وَنَزَلَتْ{ إِنَّكَ لَا تَهْدِي مَنْ أَحْبَبْتَ }","trj":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Muhammad bin Tsaur] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [bapaknya] dia berkata; \"Ketika Abu Thalib mendekati ajalnya, Rasulullah shallallahu 'alaihi wasallam masuk menemuinya dan di dekatnya ada Abu Jahal dan Abdullah bin Abu Umayyah. Lalu beliau bersabda: \"Wahai pamanku, ucapkanlah 'Laa Ilaaha Illallah (tidak ada sesembahan yang berhak di sembah selain Allah) ' satu kalimat yang dengannya aku akan berhujah untukmu di sisi Allah -Azza wa Jalla-.\" Maka Abu Jahal dan Abdullah bin Umayyah berkata kepadanya; \"Wahai Abu Thalib, Apakah kamu benci dengan agama Abdul Muthalib?\" dan keduanya tetap mangatakan hal itu kepadanya, hingga kalimat terakhir yang ia ucapkan kepada mereka ialah, bahwa ia tetap berpegang pada agama Abdul Muthalib! Maka Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Sungguh akan aku akan mintakan ampunan untukmu selama aku tidak dilarang.\" Lalu turunlah ayat, \"Tidak sepatutnya bagi Nabi dan orang-orang yang beriman memintakan ampun (kepada Allah) bagi orang-orang musyrik.\" (Qs. At Taubah 9; 113) Dan turun ayat, \" Kamu tidak akan dapat memberi petunjuk kepada orang yang kamu kasihi.\" (Qs. Al Qashash 28: 56)."}],"9:36":[{"p":"Ahmad","n":2783,"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ عَنْ أَبِي حُرَّةَ الرَّقَاشِيِّ عَنْ عَمِّهِ قَالَكُنْتُ آخِذًا بِزِمَامِ نَاقَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَوْسَطِ أَيَّامِ التَّشْرِيقِ أَذُودُ عَنْهُ النَّاسَ فَقَالَ يَا أَيُّهَا النَّاسُ أَتَدْرُونَ فِي أَيِّ شَهْرٍ أَنْتُمْ وَفِي أَيِّ يَوْمٍ أَنْتُمْ وَفِي أَيِّ بَلَدٍ أَنْتُمْ قَالُوا فِي يَوْمٍ حَرَامٍ وَشَهْرٍ حَرَامٍ وَبَلَدٍ حَرَامٍ قَالَ فَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ وَأَعْرَاضَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا إِلَى يَوْمِ تَلْقَوْنَهُ ثُمَّ قَالَ اسْمَعُوا مِنِّي تَعِيشُوا أَلَا لَا تَظْلِمُوا أَلَا لَا تَظْلِمُوا أَلَا لَا تَظْلِمُوا إِنَّهُ لَا يَحِلُّ مَالُ امْرِئٍ إِلَّا بِطِيبِ نَفْسٍ مِنْهُ أَلَا وَإِنَّ كُلَّ دَمٍ وَمَالٍ وَمَأْثَرَةٍ كَانَتْ فِي الْجَاهِلِيَّةِ تَحْتَ قَدَمِي هَذِهِ إِلَى يَوْمِ الْقِيَامَةِ وَإِنَّ أَوَّلَ دَمٍ يُوضَعُ دَمُ رَبِيعَةَ بْنِ الْحَارِثِ بْنِ عَبْدِ الْمُطَّلِبِ كَانَ مُسْتَرْضِعًا فِي بَنِي لَيْثٍ فَقَتَلَتْهُ هُذَيْلٌ أَلَا وَإِنَّ كُلَّ رِبًا كَانَ فِي الْجَاهِلِيَّةِ مَوْضُوعٌ وَإِنَّ اللَّهَ عَزَّ وَجَلَّ قَضَى أَنَّ أَوَّلَ رِبًا يُوضَعُ رِبَا الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ لَكُمْ رُءُوسُ أَمْوَالِكُمْ لَا تَظْلِمُونَ وَلَا تُظْلَمُونَ أَلَا وَإِنَّ الزَّمَانَ قَدْ اسْتَدَارَ كَهَيْئَتِهِ يَوْمَ خَلَقَ اللَّهُ السَّمَوَاتِ وَالْأَرْضَ ثُمَّ قَرَأَ{ إِنَّ عِدَّةَ الشُّهُورِ عِنْدَ اللَّهِ اثْنَا عَشَرَ شَهْرًا فِي كِتَابِ اللَّهِ يَوْمَ خَلَقَ السَّمَوَاتِ وَالْأَرْضَ مِنْهَا أَرْبَعَةٌ حُرُمٌ ذَلِكَ الدِّينُ الْقَيِّمُ فَلَا تَظْلِمُوا فِيهِنَّ أَنْفُسَكُمْ }أَلَا لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ أَلَا إِنَّ الشَّيْطَانَ قَدْ أَيِسَ أَنْ يَعْبُدَهُ الْمُصَلُّونَ وَلَكِنَّهُ فِي التَّحْرِيشِ بَيْنَكُمْ فَاتَّقُوا اللَّهَ عَزَّ وَجَلَّ فِي النِّسَاءِ فَإِنَّهُنَّ عِنْدَكُمْ عَوَانٌ لَا يَمْلِكْنَ لِأَنْفُسِهِنَّ شَيْئًا وَإِنَّ لَهُنَّ عَلَيْكُمْ وَلَكُمْ عَلَيْهِنَّ حَقًّا أَنْ لَا يُوطِئْنَ فُرُشَكُمْ أَحَدًا غَيْرَكُمْ وَلَا يَأْذَنَّ فِي بُيُوتِكُمْ لِأَحَدٍ تَكْرَهُونَهُ فَإِنْ خِفْتُمْ نُشُوزَهُنَّ فَعِظُوهُنَّ وَاهْجُرُوهُنَّ فِي الْمَضَاجِعِ وَاضْرِبُوهُنَّ ضَرْبًا غَيْرَ مُبَرِّحٍ قَالَ حُمَيْدٌ قُلْتُ لِلْحَسَنِ مَا الْمُبَرِّحُ قَالَ الْمُؤَثِّرُ وَلَهُنَّ رِزْقُهُنَّ وَكِسْوَتُهُنَّ بِالْمَعْرُوفِ وَإِنَّمَا أَخَذْتُمُوهُنَّ بِأَمَانَةِ اللَّهِ وَاسْتَحْلَلْتُمْ فُرُوجَهُنَّ بِكَلِمَةِ اللَّهِ عَزَّ وَجَلَّ وَمَنْ كَانَتْ عِنْدَهُ أَمَانَةٌ فَلْيُؤَدِّهَا إِلَى مَنْ ائْتَمَنَهُ عَلَيْهَا وَبَسَطَ يَدَيْهِ فَقَالَ أَلَا هَلْ بَلَّغْتُ أَلَا هَلْ بَلَّغْتُ أَلَا هَلْ بَلَّغْتُ ثُمَّ قَالَ لِيُبَلِّغْ الشَّاهِدُ الْغَائِبَ فَإِنَّهُ رُبَّ مُبَلَّغٍ أَسْعَدُ مِنْ سَامِعٍقَالَ حُمَيْدٌ قَالَ الْحَسَنُ حِينَ بَلَّغَ هَذِهِ الْكَلِمَةَ قَدْ وَاللَّهِ بَلَّغُوا أَقْوَامًا كَانُوا أَسْعَدَ بِهِ","trj":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad bin Salamah], telah mengabarkan kepada kami [Ali bin Zaid] dari [Abu Hurrah Ar Raqasyi] dari [Pamannya] dia berkata; \"Aku memegang tali kekang unta Rasulullah Shallalahu 'Alaihi Wasallam pada pertengahan hari Tasyrik (yaitu tanggal sebelas, dua belas dan tiga belas Dzulhijjah), aku mendesak orang-orang dari beliau, beliau bertanya: \"Wahai manusia, tahukah kalian di bulan apa kalian sekarang, di hari dan negeri mana kalian sekarang?.\" Para sahabat menjawab; \"Di hari haram, bulan haram dan negeri haram, \" beliau bersabda: \"Sungguh darah, harta dan kehormatan kalian adalah haram atas kalian, sebagaimana sucinya hari, bulan dan negeri kalian ini sampai datangnya hari kalian bertemu Allah.\" Beliau melanjutkan: \"Dengarkanlah aku, hiduplah kalian dan janganlah berbuat kezhaliman, ingatlah jangan berbuat dzalim, Sungguh tidak halal harta seseorang kecuali dengan kerelaan hati darinya, ketahuilah sesungguhnya setiap darah, harta dan kebanggaan yang ada pada masa jahiliyah, berada di bawah telapak kakiku ini sampai hari Kiamat, dan sesungguhnya darah yang pertama kali akan diletakkan adalah darah Rabi'ah bin Al Harits bin Abdul Muthallib, dia mencari seorang wanita yang bisa menyusui di Bani Laits, kemudian dibunuh oleh orang-orang Hudzail, ketahuilah sesungguhnya setiap riba di masa jahiliyah adalah jelek, dan sesungguhnya Allah 'azza wajalla telah memutuskan bahwa riba yang pertama kali akan diletakkan adalah riba Al Abbas bin Abdul Muthallib, bagi kalian adalah pokok harta kalian, janganlah kalian menzhalimi dan jangan pula terzhalimi, ketahuilah sesungguhnya zaman telah berputar sebagaimana perputaran pada hari Allah menciptakan langit dan bumi, kemudian beliau membaca ayat \"INNA 'IDDATASY SYUHUURI 'INDALLAAHI ITSNAA 'ASYARA SYAHRAN FII KITAABILLAAHI YAUMA KHOLAQAS SAMAAWAATI WAL ARDLA MINHAA ARBA'ATUN HURUM DZAALIKAD DIINUL QAYYIMU FALAA TADLIMUU FIIHINNA ANFUSAKUM (Sesungguhnya bilangan bulan pada sisi Allah adalah dua belas bulan, dalam ketetapan Allah di waktu dia menciptakan langit dan bumi, di antaranya empat bulan haram. Itulah (ketetapan) agama yang lurus, Maka janganlah kamu menganiaya diri kamu dalam bulan yang empat itu) \". QS At Taubah: 36, ketahuilah janganlah kalian kembali kepada kekafiran sepeninggalku, dengan saling membunuh satu sama lain, ketahuilah sesungguhnya setan telah putus asa untuk disembah oleh orang-orang yang shalat, akan tetapi dia tidak berputus asa untuk mengadu domba diantara kalian, maka takutlah kepada Allah 'azza wajalla dalam masalah wanita, karena sesungguhnya mereka di sisi kalian ibarat tawanan yang tidak dapat menguasai diri mereka sedikitpun, dan sungguh mereka mempunyai hak dari kalian dan kalianpun mempunyai hak atas mereka, janganlah mereka memasukkan kedalam rumah kalian selain kalian sendiri, janganlah mereka mengizinkan masuk ke dalam rumah kalian seseorang yang tidak kalian sukai, jika kalian khawatir akan nusyuz (durhaka) mereka, maka nasehatilah mereka lalu jauhilah mereka di tempat tidur dan pukulah mereka dengan pukulan yang tidak menyakitkan.\" [Humaid] berkata; Aku bertanya kepada [Al Hasan]; \"Apa yang dimaksud dengan \"Al Mubarrih?.\" dia menjawab; \"Yang membekas, \" dan hak bagi mereka adalah mendapatkan makan dan pakaian dengan cara ma'ruf, hanyasannya kalian mengambil mereka adalah dengan amanat dari Allah dan kalian menghalalkan farji (kehormatan) mereka adalah dengan kalimat Allah 'azza wajalla, dan barangsiapa mendapat amanat, maka sampaikanlah amanat itu kepada orang yang diamanati.\" Kemudian beliau membentangkan kedua tangannya seraya bersabda; \"ketahuilah bukankah aku telah menyampaikan, ketahuilah bukankah aku telah menyampaikan, ketahuilah bukankah aku telah menyampaikan?.\" Kemudian beliau melanjutkan sabdanya: \"Hendaknya orang yang hadir menyampaikan kepada yang tidak hadir, karena betapa banyak orang yang disampaikan berita kepadanya, dia lebih faham dari orang yang mendengar langsung.\" Humaid berkata; \" Al Hasan berkata ketika menyampaikan kalimat ini; \"Sungguh, demi Allah, mereka menyampaikan kepada suatu kaum dan mereka lebih bahagia dengannya.\""}],"9:56":[{"p":"Bukhari","n":3438,"ar":"حَدَّثَنَا مَحْمُودٌ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِيهِأَنَّ أَبَا طَالِبٍ لَمَّا حَضَرَتْهُ الْوَفَاةُ دَخَلَ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ أَبُو جَهْلٍ فَقَالَ أَيْ عَمِّ قُلْ لَا إِلَهَ إِلَّا اللَّهُ كَلِمَةً أُحَاجُّ لَكَ بِهَا عِنْدَ اللَّهِ فَقَالَ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ يَا أَبَا طَالِبٍ تَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ فَلَمْ يَزَالَا يُكَلِّمَانِهِ حَتَّى قَالَ آخِرَ شَيْءٍ كَلَّمَهُمْ بِهِ عَلَى مِلَّةِ عَبْدِ الْمُطَّلِبِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْهُ فَنَزَلَتْ{ مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ وَلَوْ كَانُوا أُولِي قُرْبَى مِنْ بَعْدِ مَا تَبَيَّنَ لَهُمْ أَنَّهُمْ أَصْحَابُ الْجَحِيمِ }وَنَزَلَتْ{ إِنَّكَ لَا تَهْدِي مَنْ أَحْبَبْتَ }","trj":"Telah menceritakan kepada kami [Mahmud] telah menceritakan kepada kami ['Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnu Al Musayyab] dari [bapaknya] bahwa ketika menjelang wafatnya Abu Thalib, Nabi shallallahu 'alaihi wasallam masuk menemuinya sementara di sampingnya ada Abu Jahal. Beliau berkata: \"Wahai pamanku, katakanlah laa ilaaha illallah. Suatu kalimat yang akan aku pergunakan untuk menyelamatkan engkau di sisi Allah\". Maka berkata Abu Jahal dan Abdullah bin Abu Umayyah; \"Wahai Abu Thalib, apakah kamu akan meninggalkan agama 'Abdul Muthallib?\". Keduanya terus saja mengajak Abu Thalib berbicara hingga kalimat terakhir yang diucapkannya kepada mereka adalah dia tetap mengikuti agama 'Abdul Muthallib. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Aku akan tetap memintakan ampun untukmu selama aku tidak dilarang\". Maka turunlah firman Allah Ta'ala dalam QS AT-Taubah ayat 113 yang artinya: (\"Tidak patut bagi Nabi dan orang-orang beriman untuk memohonkan ampun bagi orang-orangmusyrik sekalipun mereka itu adalah kerabat-kerabat mereka setelah jelas bagi mereka (kaum mu'minin) bahwa mereka adalah penghuni neraka jahim..\"). Dan turun pula firman Allah Ta'ala dalam QS al Qashsash ayat 56 yang artinya: (\"Sesungguhnya engkau (wahai Muhammad) tidak akan dapat memberi petunjuk kepada orang yang engkau cintai...\") "},{"p":"Muslim","n":35,"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى التُّجِيبِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ عَنْ أَبِيهِ قَالَلَمَّا حَضَرَتْ أَبَا طَالِبٍ الْوَفَاةُ جَاءَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدَ عِنْدَهُ أَبَا جَهْلٍ وَعَبْدَ اللَّهِ بْنَ أَبِي أُمَيَّةَ بْنِ الْمُغِيرَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَمِّ قُلْ لَا إِلَهَ إِلَّا اللَّهُ كَلِمَةً أَشْهَدُ لَكَ بِهَا عِنْدَ اللَّهِ فَقَالَ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ يَا أَبَا طَالِبٍ أَتَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ فَلَمْ يَزَلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْرِضُهَا عَلَيْهِ وَيُعِيدُ لَهُ تِلْكَ الْمَقَالَةَ حَتَّى قَالَ أَبُو طَالِبٍ آخِرَ مَا كَلَّمَهُمْ هُوَ عَلَى مِلَّةِ عَبْدِ الْمُطَّلِبِ وَأَبَى أَنْ يَقُولَ لَا إِلَهَ إِلَّا اللَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا وَاللَّهِ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْكَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ وَلَوْ كَانُوا أُولِي قُرْبَى مِنْ بَعْدِ مَا تَبَيَّنَ لَهُمْ أَنَّهُمْ أَصْحَابُ الْجَحِيمِ }وَأَنْزَلَ اللَّهُ تَعَالَى فِي أَبِي طَالِبٍ فَقَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِنَّكَ لَا تَهْدِي مَنْ أَحْبَبْتَ وَلَكِنَّ اللَّهَ يَهْدِي مَنْ يَشَاءُ وَهُوَ أَعْلَمُ بِالْمُهْتَدِينَ }و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ ح و حَدَّثَنَا حَسَنٌ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا حَدَّثَنَا يَعْقُوبُ وَهُوَ ابْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ حَدَّثَنِي أَبِي عَنْ صَالِحٍ كِلَاهُمَا عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ مِثْلَهُ غَيْرَ أَنَّ حَدِيثَ صَالِحٍ انْتَهَى عِنْدَ قَوْلِهِ فَأَنْزَلَ الل��َهُ عَزَّ وَجَلَّ فِيهِ وَلَمْ يَذْكُرْ الْآيَتَيْنِ وَقَالَ فِي حَدِيثِهِ وَيَعُودَانِ فِي تِلْكَ الْمَقَالَةِ وَفِي حَدِيثِ مَعْمَرٍ مَكَانَ هَذِهِ الْكَلِمَةِ فَلَمْ يَزَالَا بِهِ","trj":"Dan telah menceritakan kepadaku [Harmalah bin Yahya at-Tujibi] telah mengabarkan kepadaku [Abdullah bin Wahb] dia berkata, telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dia berkata, telah mengabarkan kepadaku [Said bin al-Musayyab] dari [bapaknya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menziarahi Abu Thalib di saat-saat dirinya tengah menghadapi sakaratul maut. Beliau mendapati Abu Jahal dan Abdullah bin Abu Umaiyyah bin al-Mughirah turut berada di sana. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Paman! Ucaplah Dua Kalimah Syahadat, aku akan menjadi saksi kamu di hadapan Allah.\" Lalu Abu Jahal dan Abdullah bin Abu Umayyah mencelah, 'Wahai Abu Thalib sanggupkah kamu meninggalkan agama Abdul Muththalib? ' Rasulullah shallallahu 'alaihi wasallam tidak berputus asa malah tetap mengajarnya mengucap Dua Kalimah Syahadat serta berkali-kali mengulanginya. Sehingga Abu Thalib menjawab sebagai ucapan terakhir kepada mereka, bahwa dia tetap bersama dengan agama Abdul MuThalib, dan enggan mengucapkan Kalimah Syahadat. Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Demi Allah, aku akan mohonkan ampunan dari Allah untukmu, \" sehingga Allah menurunkan ayat: '(Tidak dibenarkan bagi Nabi dan orang-orang yang beriman meminta ampun bagi orang-orang yang syirik sekalipun orang itu kaum kerabat sendiri setelah nyata bagi mereka bahwa orang-orang syirik itu adalah ahli Neraka) ' (Qs. AtTaubah: 113). Lalu Allah menurunkan firman-Nya berkenaan dengan peristiwa Abu Thalib: '(Sesungguhnya kamu wahai Muhammad tidak berkuasa memberi hidayat petunjuk kepada siapa yang kamu kasihi supaya dia menerima Islam tetapi Allah jualah yang berkuasa memberi petunjuk kepada orang yang dikehendaki-Nya, dan Dia jualah yang lebih mengetahui siapakah orang-orang yang (bersedia) untuk mendapat petunjuk memeluk Islam) '. (Qs. Al Qashash: 56). Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Abd bin Humaid] keduanya berkata, telah mengabarkan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar]. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Hasan al-Hulwani] dan [Abd bin Humaid] keduanya berkata, telah menceritakan kepada kami [Ya'qub] -yaitu Ibnu Ibrahim bin Sa'ad- dia berkata, telah menceritakan kepada kami [bapakku] dari [Shalih] keduanya dari [az-Zuhri] dengan sanad ini semisalnya. Hanya saja hadits Shalih selesai pada perkataannya, 'lalu Allah menurunkan firman-Nya tentangnya, ' dan dia tidak menyebutkan dua ayat tersebut. Dan dia menyebutkan di dalam haditsnya, 'Dan keduanya kembali mengucapkan perkataan tersebut, ' pada hadits Ma'mar adalah sebagai pengganti kalimat ini. Dan mereka berdua tetap berpedoman padanya.\""},{"p":"Nasa'i","n":1963,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مُحَمَّدٌ وَهُوَ ابْنُ ثَوْرٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِيهِ قَالَلَمَّا حَضَرَتْ أَبَا طَالِبٍ الْوَفَاةُ دَخَلَ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ فَقَالَ أَيْ عَمِّ قُلْ لَا إِلَهَ إِلَّا اللَّهُ كَلِمَةً أُحَاجُّ لَكَ بِهَا عِنْدَ اللَّهِ عَزَّ وَجَلَّ فَقَالَ لَهُ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ يَا أَبَا طَالِبٍ أَتَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ فَلَمْ يَزَالَا يُكَلِّمَانِهِ حَتَّى كَانَ آخِرُ شَيْءٍ كَلَّمَهُمْ بِهِ عَلَى مِلَّةِ عَبْدِ الْمُطَّلِبِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْكَ فَنَزَلَتْ{ مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ }وَنَزَلَتْ{ إِنَّكَ لَا تَهْدِي مَنْ أَحْبَبْتَ }","trj":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Muhammad bin Tsaur] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [bapaknya] dia berkata; \"Ketika Abu Thalib mendekati ajalnya, Rasulullah shallallahu 'alaihi wasallam masuk menemuinya dan di dekatnya ada Abu Jahal dan Abdullah bin Abu Umayyah. Lalu beliau bersabda: \"Wahai pamanku, ucapkanlah 'Laa Ilaaha Illallah (tidak ada sesembahan yang berhak di sembah selain Allah) ' satu kalimat yang dengannya aku akan berhujah untukmu di sisi Allah -Azza wa Jalla-.\" Maka Abu Jahal dan Abdullah bin Umayyah berkata kepadanya; \"Wahai Abu Thalib, Apakah kamu benci dengan agama Abdul Muthalib?\" dan keduanya tetap mangatakan hal itu kepadanya, hingga kalimat terakhir yang ia ucapkan kepada mereka ialah, bahwa ia tetap berpegang pada agama Abdul Muthalib! Maka Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Sungguh akan aku akan mintakan ampunan untukmu selama aku tidak dilarang.\" Lalu turunlah ayat, \"Tidak sepatutnya bagi Nabi dan orang-orang yang beriman memintakan ampun (kepada Allah) bagi orang-orang musyrik.\" (Qs. At Taubah 9; 113) Dan turun ayat, \" Kamu tidak akan dapat memberi petunjuk kepada orang yang kamu kasihi.\" (Qs. Al Qashash 28: 56)."}],"9:58":[{"p":"Bukhari","n":6087,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ قَالَبَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْسِمُ جَاءَ عَبْدُ اللَّهِ بْنُ ��ِي الْخُوَيْصِرَةِ التَّمِيمِيُّ فَقَالَ اعْدِلْ يَا رَسُولَ اللَّهِ فَقَالَ وَيْلَكَ وَمَنْ يَعْدِلُ إِذَا لَمْ أَعْدِلْ قَالَ عُمَرُ بْنُ الْخَطَّابِ دَعْنِي أَضْرِبْ عُنُقَهُ قَالَ دَعْهُ فَإِنَّ لَهُ أَصْحَابًا يَحْقِرُ أَحَدُكُمْ صَلَاتَهُ مَعَ صَلَاتِهِ وَصِيَامَهُ مَعَ صِيَامِهِ يَمْرُقُونَ مِنْ الدِّينِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ يُنْظَرُ فِي قُذَذِهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ ثُمَّ يُنْظَرُ فِي نَصْلِهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ ثُمَّ يُنْظَرُ فِي رِصَافِهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ ثُمَّ يُنْظَرُ فِي نَضِيِّهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ قَدْ سَبَقَ الْفَرْثَ وَالدَّمَ آيَتُهُمْ رَجُلٌ إِحْدَى يَدَيْهِ أَوْ قَالَ ثَدْيَيْهِ مِثْلُ ثَدْيِ الْمَرْأَةِ أَوْ قَالَ مِثْلُ الْبَضْعَةِ تَدَرْدَرُ يَخْرُجُونَ عَلَى حِينِ فُرْقَةٍ مِنْ النَّاسِ قَالَ أَبُو سَعِيدٍ أَشْهَدُ سَمِعْتُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَشْهَدُ أَنَّ عَلِيًّا قَتَلَهُمْ وَأَنَا مَعَهُ جِيءَ بِالرَّجُلِ عَلَى النَّعْتِ الَّذِي نَعَتَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَنَزَلَتْ فِيهِ{ وَمِنْهُمْ مَنْ يَلْمِزُكَ فِي الصَّدَقَاتِ }","trj":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dai [Abu Sa'id] mengatakan; Ketika Nabi shallallahu 'alaihi wasallam sedang membagi (harta rampasan), tiba-tiba Adbdullah bin Dzil huwaishirah At Tamimi datang seraya menegur Nabi; 'Hendaklah engkau berbuat adil! ' Spontan Nabi menjawab: \"siapa lagi yang berbuat adil jika aku tak berbuat adil?\" Umar kemudian berujar; 'Biarkan aku yang memenggal lehernya! ' Nabi bersabda; \"Biarkan saja dia, sebab dia mempunyai beberapa kawan yang salah seorang diantara kalian meremehkan shalatnya dibanding dengan shalatnya, dan meremehkan puasanya dibanding puasanya, mereka keluar dari agama sebagaimana anak panah keluar dari busur, ia melihat bulu anak panahnya namun tak ada apa-apa, kemudian memperhatikan mata anak panahnya namun tidak ditemukan apa-apa, kemudian melihat kain panahnya namun tidak didapatkan apa-apa, dan telah didahulu oleh kotoran dan darah. Tanda-tanda mereka adalah salah satu diantara kedua tangannya -atau- diantara kedua putingnya seperti puting kaum perempuan atau ia seperti daging yang bergerak-gerak, mereka muncul ketika manusia mengalami perpecahan.\" Sedang Abu Sa'id mengatakan; aku bersaksi bahwa aku mendengar dari Nabi shallallahu 'alaihi wasallam shallallahu 'alaihi wasallam, dan aku bersaksi bahwa 'Ali membunuh mereka dan aku bersamanya ketika didatangkan seseorang yang ciri-cirinya seperti yang disifatkan Nabi shallallahu 'alaihi wasallam, lantas diturunlah ayat; 'Diantara mereka ada yang mengolok-olokmu karena sedekah yang kamu infakkan' (QS. Attaubah 58)."},{"p":"Darimi","n":92,"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ قَالَ إِنَّ أَهْلَ الْأَهْوَاءِ أَهْلُ الضَّلَالَةِ وَلَا أَرَى مَصِيرَهُمْ إِلَّا النَّارَ فَجَرِّبْهُمْ فَلَيْسَ أَحَدٌ مِنْهُمْ يَنْتَحِلُ قَوْلًا أَوْ قَالَ حَدِيثًا فَيَتَنَاهَى بِهِ الْأَمْرُ دُونَ السَّيْفِ وَإِنَّ النِّفَاقَ كَانَ ضُرُوبًا ثُمَّ تَلَا { وَمِنْهُمْ مَنْ عَاهَدَ اللَّهَ } { وَمِنْهُمْ مَنْ يَلْمِزُكَ فِي الصَّدَقَاتِ } { وَمِنْهُمْ الَّذِينَ يُؤْذُونَ النَّبِيَّ } فَاخْتَلَفَ قَوْلُهُمْ وَاجْتَمَعُوا فِي الشَّكِّ وَالتَّكْذِيبِ وَإِنَّ هَؤُلَاءِ اخْتَلَفَ قَوْلُهُمْ وَاجْتَمَعُوا فِي السَّيْفِ وَلَا أَرَى مَصِيرَهُمْ إِلَّا النَّارَ قَالَ حَمَّادٌ ثُمَّ قَالَ أَيُّوبُ عِنْدَ ذَا الْحَدِيثِ أَوْ عِنْدَ الْأَوَّلِ وَكَانَ وَاللَّهِ مِنْ الْفُقَهَاءِ ذَوِي الْأَلْبَابِ يَعْنِي أَبَا قِلَابَةَ","trj":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] ia berkata: \" Sesungguhnya pemuja hawa nafsu adalah orang-orang yang sesat, dan aku tidak melihat akhir perjalanan yang mereka tempuh kecuali neraka. Ujilah mereka itu. Tidak ada seorang pun dari mereka yang menyitir perkataan atau berkata, hingga persoalannya tiada lain adalah pedang. Sesungguhnya kemunafikan sudah menjadi ciri khas mereka. Kemudian ia membaca ayat \"WA MINHUM MAN 'AHADALLAHA' (Dan diantara mereka ada orang yang telah berikrar kepada Allah Subhaanallahu wa Ta'ala) -Qs. At Taubah: 75-, dan ayat \"WA MINHUM MAN YALMIZUKA FIS SHADAQAAT' (Dan diantara mereka ada orang yang mencelamu tentang (pembagian) zakat) -Qs. At Taubah: 58-, dan ayat \"WAMINHUMULLADZINA YU`DZUUNANABIYYA' (Dan diantara mereka 'orang-orang munafik' ada yang menyakiti Nabi shallallahu 'alaihi wasallam) -Qs. Attaubah: 116-,. Kemudian mereka berbeda pendapat dan berselisih, dan akhirnya mereka berkumpul dalam keraguan dan kedustaan,. Sesungguhnya mereka berbeda pendapat dan bersatu dalam gelayut pedang. Dan aku tidak melihat perjalanan mereka kecuali ke neraka\". Hammad berkata: \"Ayyub berkata tentang hadits ini atau hadits awal, demi Allah Subhaanallahu wa Ta'ala, ia termasuk salah seorang pakar fikih yang sangat cerdas, maksudku adalah Abu Qilabah\"."}],"9:75":[{"p":"Darimi","n":92,"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ قَالَ إِنَّ أَهْلَ الْأَهْوَاءِ أَهْلُ الضَّلَالَةِ وَلَا أَرَى مَصِيرَهُمْ إِلَّا النَّارَ فَجَرِّبْهُمْ فَلَيْسَ أَحَدٌ مِنْهُمْ يَنْتَحِلُ قَوْلًا أَوْ قَالَ حَدِيثًا فَيَتَنَاهَى بِهِ الْأَمْرُ دُونَ السَّيْفِ وَإِنَّ النِّفَاقَ كَانَ ضُرُوبًا ثُمَّ تَلَا { وَمِنْهُمْ مَنْ عَاهَدَ اللَّهَ } { وَمِنْهُمْ مَنْ يَلْمِزُكَ فِي الصَّدَقَاتِ } { وَمِنْهُمْ الَّذِينَ يُؤْذُونَ النَّبِيَّ } فَاخْتَلَفَ قَوْلُهُمْ وَاجْتَمَعُوا فِي الشَّكِّ وَالتَّكْذِيبِ وَإِنَّ هَؤُلَاءِ اخْتَلَفَ قَوْلُهُمْ وَاجْتَمَعُوا فِي السَّيْفِ وَلَا أَرَى مَصِيرَهُمْ إِلَّا النَّارَ قَالَ حَمَّادٌ ثُمَّ قَالَ أَيُّوبُ عِنْدَ ذَا الْحَدِيثِ أَوْ عِنْدَ الْأَوَّلِ وَكَانَ وَاللَّهِ مِنْ الْفُقَهَاءِ ذَوِي الْأَلْبَابِ يَعْنِي أَبَا قِلَابَةَ","trj":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] ia berkata: \" Sesungguhnya pemuja hawa nafsu adalah orang-orang yang sesat, dan aku tidak melihat akhir perjalanan yang mereka tempuh kecuali neraka. Ujilah mereka itu. Tidak ada seorang pun dari mereka yang menyitir perkataan atau berkata, hingga persoalannya tiada lain adalah pedang. Sesungguhnya kemunafikan sudah menjadi ciri khas mereka. Kemudian ia membaca ayat \"WA MINHUM MAN 'AHADALLAHA' (Dan diantara mereka ada orang yang telah berikrar kepada Allah Subhaanallahu wa Ta'ala) -Qs. At Taubah: 75-, dan ayat \"WA MINHUM MAN YALMIZUKA FIS SHADAQAAT' (Dan diantara mereka ada orang yang mencelamu tentang (pembagian) zakat) -Qs. At Taubah: 58-, dan ayat \"WAMINHUMULLADZINA YU`DZUUNANABIYYA' (Dan diantara mereka 'orang-orang munafik' ada yang menyakiti Nabi shallallahu 'alaihi wasallam) -Qs. Attaubah: 116-,. Kemudian mereka berbeda pendapat dan berselisih, dan akhirnya mereka berkumpul dalam keraguan dan kedustaan,. Sesungguhnya mereka berbeda pendapat dan bersatu dalam gelayut pedang. Dan aku tidak melihat perjalanan mereka kecuali ke neraka\". Hammad berkata: \"Ayyub berkata tentang hadits ini atau hadits awal, demi Allah Subhaanallahu wa Ta'ala, ia termasuk salah seorang pakar fikih yang sangat cerdas, maksudku adalah Abu Qilabah\"."}],"9:79":[{"p":"Bukhari","n":3995,"ar":"حَدَّثَنِي بِشْرُ بْنُ خَالِدٍ أَبُو مُحَمَّدٍ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مَسْعُودٍ قَالَلَمَّا أُمِرْنَا بِالصَّدَقَةِ كُنَّا نَتَحَامَلُ فَجَاءَ أَبُو عَقِيلٍ بِنِصْفِ صَاعٍ وَجَاءَ إِنْسَانٌ بِأَكْثَرَ مِنْهُ فَقَالَ الْمُنَافِقُونَ إِنَّ اللَّهَ لَغَنِيٌّ عَنْ صَدَقَةِ هَذَا وَمَا فَعَلَ هَذَا الْآخَرُ إِلَّا رِئَاءً فَنَزَلَتْ{ الَّذِينَ يَلْمِزُونَ الْمُطَّوِّعِينَ مِنْ الْمُؤْمِنِينَ فِي الصَّدَقَاتِ وَالَّذِينَ لَا يَجِدُونَ إِلَّا جُهْدَهُمْ }الْآيَةَ","trj":"Telah menceritakan kepadaku [Bisyr bin Khalid Abu Muhammad]; Telah mengabarkan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman] dari [Abu Wail] dari [Abu Mas'ud] dia berkata; Setelah Rasulullah Shalallahu 'Alaihi Wa Sallam memerintahkan kami untuk bersedekah, maka kami saling membawakan sedekah tersebut agar kami mendapatkan pahala darinya, lalu Abu Uqail bersedekah dengan setengah sha', kemudian datang seseorang dengan membawa lebih banyak dari itu, lalu orang-orang munafik berkata; \" Allah Azza Wa Jalla benar-benar tidak membutuhkan sedekah orang ini, orang ini tidak melakukannya kecuali dengan riya'. Lalu turun ayat: 'Orang-orang munafik itu yaitu orang-orang yang mencela orang-orang mukmin yang memberi sedekah dengan sukarela dan (mencela) orang-orang yang tidak memperoleh (untuk disedekahkan) selain sekadar kesanggupannya.\" (Qs. At Taubah: 79)."},{"p":"Nasa'i","n":2398,"ar":"أَخْبَرَنَا بِشْرُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مَسْعُودٍ قَالَلَمَّا أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالصَّدَقَةِ فَتَصَدَّقَ أَبُو عَقِيلٍ بِنِصْفِ صَاعٍ وَجَاءَ إِنْسَانٌ بِشَيْءٍ أَكْثَرَ مِنْهُ فَقَالَ الْمُنَافِقُونَ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَغَنِيٌّ عَنْ صَدَقَةِ هَذَا وَمَا فَعَلَ هَذَا الْآخَرُ إِلَّا رِيَاءً فَنَزَلَتْ{ الَّذِينَ يَلْمِزُونَ الْمُطَّوِّعِينَ مِنْ الْمُؤْمِنِينَ فِي الصَّدَقَاتِ وَالَّذِينَ لَا يَجِدُونَ إِلَّا جُهْدَهُمْ }","trj":"Telah mengabarkan kepada kami [Bisyr bin Khalid] dia berkata; Telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Sulaiman] dari [Abu Wa'il] dari [Abu Mas'ud] dia berkata; \"Setelah Rasulullah Shalallahu 'Alaihi Wa Sallam memerintahkan kami untuk bersedekah, maka Abu Uqail bersedekah dengan satu sha', dan datang seseorang dengan membawa lebih banyak dari itu, lalu orang-orang munafik berkata; \" Allah Azza Wa Jalla benar-benar tidak membutuhkan sedekah orang ini, orang ini tidak melakukannya kecuali dengan riya'. Lalu turun ayat: 'Orang-orang munafik itu yaitu orang-orang yang mencela orang-orang mukmin yang memberi sedekah dengan sukarela dan (mencela) orang-orang yang tidak memperoleh (untuk disedekahkan) selain sekadar kesanggupannya.\" (Qs. At Taubah 9: 79)."}],"9:80":[{"p":"Ahmad","n":20,"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ حَدَّثَنِي الزُّهْرِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يَقُولُلَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ دُعِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلصَّلَاةِ عَلَيْهِ فَقَامَ إِلَيْهِ فَلَمَّا وَقَفَ عَلَيْهِ يُرِيدُ الصَّلَاةَ تَحَوَّلْتُ حَتَّى قُمْتُ فِي صَدْرِهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَعَلَى عَدُوِّ اللَّهِ عَبْدِ اللَّهِ بْنِ أُبَيٍّ الْقَائِلِ يَوْمَ كَذَا كَذَا وَكَذَا يُعَدِّدُ أَيَّامَهُ قَالَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَبَسَّمُ حَتَّى إِذَا أَكْثَرْتُ عَلَيْهِ قَالَ أَخِّرْ عَنِّي يَا عُمَرُ إِنِّي خُيِّرْتُ فَاخْتَرْتُ وَقَدْ قِيلَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً فَلَنْ يَغْفِرَ اللَّهُ لَهُمْ }لَوْ أَعْلَمُ أَنِّي إِنْ زِدْتُ عَلَى السَّبْعِينَ غُفِرَ لَهُ لَزِدْتُ قَالَ ثُمَّ صَلَّى عَلَيْهِ وَمَشَى مَعَهُ فَقَامَ عَلَى قَبْرِهِ حَتَّى فُرِغَ مِنْهُ قَالَ فَعَجَبٌ لِي وَجَرَاءَتِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَوَاللَّهِ مَا كَانَ إِلَّا يَسِيرًا حَتَّى نَزَلَتْ هَاتَانِ الْآيَتَانِ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ إِنَّهُمْ كَفَرُوا بِاللَّهِ وَرَسُولِهِ وَمَاتُوا وَهُمْ فَاسِقُونَ }فَمَا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَهُ عَلَى مُنَافِقٍ وَلَا قَامَ عَلَى قَبْرِهِ حَتَّى قَبَضَهُ اللَّهُ عَزَّ وَجَلَّ","trj":"Telah menceritakan kepada kami [Ya'qub] Telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] Telah menceritakan kepadaku [Az Zuhri] dari [Ubaidullah Bin Abdullah Bin 'Utbah Bin Mas'ud] dari [Abdullah bin Abbas], dia berkata; aku mendengar [Umar Bin Khattab] berkata; ketika Abdullah Bin Ubai meninggal, Rasulullah shallallahu 'alaihi wasallam dipanggil untuk menshalatinya, maka beliau bergegas mendatanginya, tatkala beliau berdiri dihadapannya untuk menshalatinya aku menghalanginya sehingga aku berdiri dihadapan beliau dan berkata; \"Wahai Rasulullah, Abdullah Bin Ubai adalah dedengkot musuh Allah yang mengatakan pada hari ini dan ini, \" dia menyebutkan nama nama harinya, kemudian Umar melanjutkan; akan tetapi Rasulullah shallallahu 'alaihi wasallam hanya tersenyum sampai ketika aku mengulang-ngulang perkataanku beliau berkata: \"Minggirlah dariku wahai Umar, sesungguhnya aku di beri pilihan maka aku memilih, dan sudah di sebutkan: \"Kamu memohonkan ampun bagi mereka atau tidak kamu mohonkan ampun bagi mereka (adalah sama saja). kendatipun kamu memohonkan ampun bagi mereka tujuh puluh kali, namun Allah sekali-kali tidak akan memberi ampunan kepada mereka.'\" (QS Al Anfal ayat 80) seandainya aku tahu apabila aku menambah permohonanku sampai tujuh puluh kali dia akan mendapat ampunan niscaya aku akan tambah\" Umar berkata; kemudian beliau menshalatinya dan mengantarkan jenazahnya lalu berdiri di atas kuburannya sampai selesai dimakamkan, \" Umar berkata; \"aku heran dengan diriku atas lancangnya diriku kepada Rasulullah shallallahu 'alaihi wasallam, padahal Allah dan Rasul-Nya lebih tahu\" Umar berkata lagi; \"maka demi Allah tidak lama kemudian turunlah dua ayat ini (QS At Taubah ayat 80, 84).\"Dan janganlah kamu sekali-kali menyembahyangkan (jenazah) seorang yang mati di antara mereka, dan janganlah kamu berdiri (mendoakan) di kuburnya. Sesungguhnya mereka Telah kafir kepada Allah dan rasul-Nya dan mereka mati dalam keadaan fasik\". Kemudian Rasulullah shallallahu 'alaihi wasallam setelah itu tidak pernah lagi menshalati orang munafiq dan tidak juga berdiri di atas quburannya."},{"p":"Bukhari","n":1190,"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ عَبْدَ اللَّهِ بْنَ أُبَيٍّ لَمَّا تُوُفِّيَ جَاءَ ابْنُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَعْطِنِي قَمِيصَكَ أُكَفِّنْهُ فِيهِ وَصَلِّ عَلَيْهِ وَاسْتَغْفِرْ لَهُ فَأَعْطَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَمِيصَهُ فَقَالَ آذِنِّي أُصَلِّي عَلَيْهِ فَآذَنَهُ فَلَمَّا أَرَادَ أَنْ يُصَلِّيَ عَلَيْهِ جَذَبَهُ عُمَرُ رَضِيَ اللَّهُ عَنْهُ فَقَالَ أَلَيْسَ اللَّهُ نَهَاكَ أَنْ تُصَلِّيَ عَلَى الْمُنَافِقِينَ فَقَالَ أَنَا بَيْنَ خِيَرَتَيْنِ قَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً فَلَنْ يَغْفِرَ اللَّهُ لَهُمْ }فَصَلَّى عَلَيْهِ فَنَزَلَتْ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }","trj":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] berkata, telah menceritakan kepada saya [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] bahwa ketika 'Abdullah bin Ubay wafat, anaknya datang menemui Nabi shallallahu 'alaihi wasallam lalu berkata: \"Wahai Rasulullah shallallahu 'alaihi wasallam: \"Berikanlah kepadaku baju anda untuk aku gunakan mengafani (ayahku) dan shalatlah untuknya serta mohonkanlah ampunan baginya\". Maka Nabi shallallahu 'alaihi wasallam memberikan bajunya kepadanya lalu berkata: \"izinkanlah aku untuk menshalatkannya\". Ketika Beliau hendak menshalatkannya tiba-tiba 'Umar bin Al Khaththab radliallahu 'anhu datang menarik Beliau seraya berkata: \"Bukankah Allah telah melarang anda untuk menshalatkan orang munafiq?\" Maka Beliau bersabda: \"Aku berada pada dua pilihan dari firman Allah Ta'ala (QS. At-Taubah ayat 80, yang artinya): \"Kamu mohonkan ampun buat mereka atau kamu tidak mohonkan ampun buat mereka (sama saja bagi mereka). Sekalipun kamu memohonkan ampun buat mereka sebanyak tujuh puluh kali, Allah sekali-kali tidak akan mengampuni mereka\". Maka Beliau shallallahu 'alaihi wasallam menshalatkannya. Lalu turunlah ayat: (QS. At-Taubah ayat 84 yang artinya): \"Janganlah kamu shalatkan seorangpun yang mati dari mereka selamanya dan janganlah kamu berdiri di atas kuburannya\"."},{"p":"Bukhari","n":3997,"ar":"حَدَّثَنِي عُبَيْدُ بْنُ إِسْمَاعِيلَ عَنْ أَبِي أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ جَاءَ ابْنُهُ عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ أَنْ يُعْطِيَهُ قَمِيصَهُ يُكَفِّنُ فِيهِ أَبَاهُ فَأَعْطَاهُ ثُمَّ سَأَلَهُ أَنْ يُصَلِّيَ عَلَيْهِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَقَامَ عُمَرُ فَأَخَذَ بِثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ تُصَلِّي عَلَيْهِ وَقَدْ نَهَاكَ رَبُّكَ أَنْ تُصَلِّيَ عَلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا خَيَّرَنِي اللَّهُ فَقَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً }وَسَأَزِيدُهُ عَلَى السَّبْعِينَ قَالَ إِنَّهُ مُنَافِقٌ قَالَ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }","trj":"Telah menceritakan kepadaku ['Ubaid bin Isma'il] dari [Abu Usamah] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dia berkata; \"Ketika Abdullah bin Ubay meninggal dunia. anak laki-lakinya -yaitu Abdulah bin Abdullah- datang kepada Rasulullah shallallahu 'alaihi wasallam seraya memohon kepada beIiau agar sudi memberikan baju beliau kepada Abdullah untuk kain kafan ayahnya, Abdullah bin Ubay bin Salul. Lalu Rasulullah shallallahu 'alaihi wasallam memberikan bajunya kepada Abdullah. setelah itu, Abdullah juga memohon Rasulullah agar beliau berkenan menshalati jenazah ayahnya. Kemudian Rasulullah pun bersiap-siap untuk menshalati jenazah Abdullah bin Ubay, hingga akhirnya Umar berdiri dan menarik baju Rasulullah seraya berkata, \"Ya Rasulullah, apakah engkau akan menshalati jenazah Abdullah bin Ubay sedangkan Allah telah melarang untuk menshalatinya?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Sesungguhnya Allah Subhanahu wa Ta'ala telah memberikan pilihan kepadaku.\" Lalu beliau membacakan ayat yang berbunyi; \"Kamu memohonkun ampun bagi orang-orang munafik atau tidak kamu mohonkan ampun bagi mereka, maka hal itu adalah sama saja. sekalipun kamu memohonkan ampun bagi mereka tujuh puluh kali (Qs. At-Taubah 9: 80). Oleh karena itu, aku akan menambah istighfar lebih dari tujuh puluh kali untuknya.\" Umar bin Khaththab berkata, \"Ya Rasulullah, sesungguhnya Ia adalah orang munafik?.\" Tetapi, rupanya Rasulullah shallallahu 'alaihi wasallam tetap saja menshalatinya, hingga Allah menurunkan ayat Al Qur'an: \"Janganlah kamu sekali-kali menshalati jenazah seorang di antara orang-orang munafik dan janganlah kamu berdiri di atas kuburnya.\" (Qs. At-Taubah 9: 84)."},{"p":"Bukhari","n":3999,"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ قَالَ لَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ جَاءَ ابْنُهُ عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَاهُ قَمِيصَهُ وَأَمَرَهُ أَنْ يُكَفِّنَهُ فِيهِ ثُمَّ قَامَ يُصَلِّي عَلَيْهِ فَأَخَذَ عُمَرُ بْنُ الْخَطَّابِ بِثَوْبِهِ فَقَالَ تُصَلِّي عَلَيْهِ وَهُوَ مُنَافِقٌ وَقَدْ نَهَاكَ اللَّهُ أَنْ تَسْتَغْفِرَ لَهُمْ قَالَ إِنَّمَا خَيَّرَنِي اللَّهُ أَوْ أَخْبَرَنِي اللَّهُ فَقَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً فَلَنْ يَغْفِرَ اللَّهُ لَهُمْ }فَقَالَ سَأَزِيدُهُ عَلَى سَبْعِينَ قَالَ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَلَّيْنَا مَعَهُ ثُمَّ أَنْزَلَ اللَّهُ عَلَيْهِ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ إِنَّهُمْ كَفَرُوا بِاللَّهِ وَرَسُولِهِ وَمَاتُوا وَهُمْ فَاسِقُونَ }","trj":"Telah menceritakan kepadaku [Ibrahim bin Al Mundzir] Telah menceritakan kepada kami [Anas bin 'Iyadl] dari ['Ubaidillah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dia berkata; \"Ketika Abdullah bin Ubay meninggal dunia. anak laki-lakinya -yaitu Abdulah bin Abdullah- datang kepada Rasulullah shallallahu 'alaihi wasallam dan beliau berikan bajunya dan beliau perintahkannya untuk mengafani ayahnya dengan bajunya tersebut. Lalu Rasulullah shallallahu 'alaihi wasallam menshalati jenazah ayah Abdullah bin Abdullah bin Ubbay. Hingga akhirnya Umar menarik baju Rasulullah seraya berkata; \"Ya Rasulullah, apakah engkau akan menshalati jenazah Abdullah bin Ubay sedangkan dia itu orang munafik? Padahal Allah telah melarang engkau memintakan ampun untuknya?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Sesungguhnya Allah Subhanahu wa Ta'ala telah memberikan pilihan kepadaku atau mengabariku.\" Lalu beliau membacakan ayat yang berbunyi; \"Kamu memohonkun ampun bagi orang-orang munafik atau tidak kamu mohonkan ampun bagi mereka, maka hal itu adalah sama saja. sekalipun kamu memohonkan ampun bagi mereka tujuh puluh kali sekali-kali Allah tidak akan mengampuni mereka (Qs. At-Taubah 9: 80). Rasulullah shallallahu 'alaihi wasallam bersabda: Aku akan menambah istighfar lebih dari tujuh puluh kali untuknya.\" Maka Rasulullah shallallahu 'alaihi wasallam tetap saja menshalatinya dan kami pun shalat bersamanya hingga Allah menurunkan ayat Al Qur'an: \"Janganlah kamu sekali-kali menshalati jenazah seorang di antara orang-orang munafik dan janganlah kamu berdiri di atas kuburnya, sesungguhnya mereka telah kafir kepada Allah dan Rasul-Nya dan mereka mati dalam keadaan munafiq.\" (Qs. At-Taubah 9: 84)."},{"p":"Muslim","n":4077,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَلَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ جَاءَ ابْنُهُ عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ أَنْ يُعْطِيَهُ قَمِيصَهُ أَنْ يُكَفِّنَ فِيهِ أَبَاهُ فَأَعْطَاهُ ثُمَّ سَأَلَهُ أَنْ يُصَلِّيَ عَلَيْهِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَقَامَ عُمَرُ فَأَخَذَ بِثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَتُصَلِّي عَلَيْهِ وَقَدْ نَهَاكَ اللَّهُ أَنْ تُصَلِّيَ عَلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا خَيَّرَنِي اللَّهُ فَقَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً }وَسَأَزِيدُ عَلَى سَبْعِينَ قَالَ إِنَّهُ مُنَافِقٌ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }و حَدَّثَنَاه مُحَمَّدُ بْنُ الْمُثَنَّى وَعُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا يَحْيَى وَهُوَ الْقَطَّانُ عَنْ عُبَيْدِ اللَّهِ بِهَذَا الْإِسْنَادِ فِي مَعْنَى حَدِيثِ أَبِي أُسَامَةَ وَزَادَ قَالَ فَتَرَكَ الصَّلَاةَ عَلَيْهِمْ","trj":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah]; Telah menceritakan kepada kami [Abu Usamah]; Telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar] dia berkata; \"Ketika Abdullah bin Ubay bin Salul meninggal dunia. anak laki-lakinya -yaitu Abdulah bin Abdullah- datang kepada Rasulullah shallallahu 'alaihi wasallam seraya memohon kepada beIiau agar sudi memberikan baju beliau kepada Abdullah untuk kain kafan ayahnya, Abdullah bin Ubay bin Salul. Lalu Rasulullah shallallahu 'alaihi wasallam memberikan bajunya kepada Abdullah. Setelah itu, Abdullah juga memohon Rasulullah agar beliau berkenan menshalati jenazah ayahnya. Kemudian Rasulullah pun bersiap-siap untuk menshalati jenazah Abdullah bin Ubay, hingga akhirnya Umar berdiri dan menarik baju Rasulullah seraya berkata, \"Ya Rasulullah, apakah engkau akan menshalati jenazah Abdullah bin Ubay sedangkan Allah telah melarang untuk menshalatinya?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Sesungguhnya Allah Subhanahu wa Ta'ala telah memberikan pilihan kepadaku.\" Lalu beliau membacakan ayat yang berbunyi; \"Kamu memohonkun ampun bagi orang-orang munafik atau tidak kamu mohonkan ampun bagi mereka, maka hal itu adalah sama saja. sekalipun kamu memohonkan ampun bagi mereka tujuh puluh kali (Qs. At-Taubah 9: 80). Oleh karena itu, aku akan menambah istighfar lebih dari tujuh puluh kali untuknya.\" Umar bin Khaththab berkata, \"Ya Rasulullah, sesungguhnya Ia adalah orang munafik?.\" Tetapi, rupanya Rasulullah shallallahu 'alaihi wasallam tetap saja menshalatinya, hingga Allah menurunkan ayat Al Qur'an: \"Janganlah kamu sekali-kali menshalati jenazah seorang di antara orang-orang munafik dan janganlah kamu berdiri di atas kuburnya.\" (Qs. At-Taubah 9: 84). Dan telah menceritakannya kepada kami [Muhammad bin Al Mutsanna] dan ['Ubaidullah bin Sa'id] keduanya berkata; Telah menceritakan kepada kami [Yahya] yaitu Al Qaththan dari ['Ubaidillah] melalui jalur ini mengenai Hadits yang semakna dengan Abu Usamah namun ada tambahan; 'Kemudian beliau meninggalkan shalat untuk mereka (orang-orang munafik)."}],"9:84":[{"p":"Bukhari","n":1190,"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ عَبْدَ اللَّهِ بْنَ أُبَيٍّ لَمَّا تُوُفِّيَ جَاءَ ابْنُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَعْطِنِي قَمِيصَكَ أُكَفِّنْهُ فِيهِ وَصَلِّ عَلَيْهِ وَاسْتَغْفِرْ لَهُ فَأَعْطَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَمِيصَهُ فَقَالَ آذِنِّي أُصَلِّي عَلَيْهِ فَآذَنَهُ فَلَمَّا أَرَادَ أَنْ يُصَلِّيَ عَلَيْهِ جَذَبَهُ عُمَرُ رَضِيَ اللَّهُ عَنْهُ فَقَالَ أَلَيْسَ اللَّهُ نَهَاكَ أَنْ تُصَلِّيَ عَلَى الْمُنَافِقِينَ فَقَالَ أَنَا بَيْنَ خِيَرَتَيْنِ قَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً فَلَنْ يَغْفِرَ اللَّهُ لَهُمْ }فَصَلَّى عَلَيْهِ فَنَزَلَتْ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }","trj":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] berkata, telah menceritakan kepada saya [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] bahwa ketika 'Abdullah bin Ubay wafat, anaknya datang menemui Nabi shallallahu 'alaihi wasallam lalu berkata: \"Wahai Rasulullah shallallahu 'alaihi wasallam: \"Berikanlah kepadaku baju anda untuk aku gunakan mengafani (ayahku) dan shalatlah untuknya serta mohonkanlah ampunan baginya\". Maka Nabi shallallahu 'alaihi wasallam memberikan bajunya kepadanya lalu berkata: \"izinkanlah aku untuk menshalatkannya\". Ketika Beliau hendak menshalatkannya tiba-tiba 'Umar bin Al Khaththab radliallahu 'anhu datang menarik Beliau seraya berkata: \"Bukankah Allah telah melarang anda untuk menshalatkan orang munafiq?\" Maka Beliau bersabda: \"Aku berada pada dua pilihan dari firman Allah Ta'ala (QS. At-Taubah ayat 80, yang artinya): \"Kamu mohonkan ampun buat mereka atau kamu tidak mohonkan ampun buat mereka (sama saja bagi mereka). Sekalipun kamu memohonkan ampun buat mereka sebanyak tujuh puluh kali, Allah sekali-kali tidak akan mengampuni mereka\". Maka Beliau shallallahu 'alaihi wasallam menshalatkannya. Lalu turunlah ayat: (QS. At-Taubah ayat 84 yang artinya): \"Janganlah kamu shalatkan seorangpun yang mati dari mereka selamanya dan janganlah kamu berdiri di atas kuburannya\"."},{"p":"Bukhari","n":1277,"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنِي اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُمْ أَنَّهُ قَالَلَمَّا مَاتَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ دُعِيَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَلَمَّا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَثَبْتُ إِلَيْهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَتُصَلِّي عَلَى ابْنِ أُبَيٍّ وَقَدْ قَالَ يَوْمَ كَذَا وَكَذَا كَذَا وَكَذَا أُعَدِّدُ عَلَيْهِ قَوْلَهُ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَخِّرْ عَنِّي يَا عُمَرُ فَلَمَّا أَكْثَرْتُ عَلَيْهِ قَالَ إِنِّي خُيِّرْتُ فَاخْتَرْتُ لَوْ أَعْلَمُ أَنِّي إِنْ زِدْتُ عَلَى السَّبْعِينَ يُغْفَرُ لَهُ لَزِدْتُ عَلَيْهَا قَالَ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ انْصَرَفَ فَلَمْ يَمْكُثْ إِلَّا يَسِيرًا حَتَّى نَزَلَتْ الْآيَتَانِ مِنْ بَرَاءَةٌ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا إِلَى قَوْلِهِ وَهُمْ فَاسِقُونَ }قَالَ فَعَجِبْتُ بَعْدُ مِنْ جُرْأَتِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ وَاللَّهُ وَرَسُولُهُ أَعْلَمُ","trj":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada saya [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah] dari [Ibnu 'Abbas] dari ['Umar bin Al Khaththab radliallahu 'anhu] bahwasanya dia berkata,: \"Ketika 'Abdullah bin Ubay bin Salul meninggal dunia, Rasulullah Shallallahu'alaihiwasallam diminta untuk menyolatkannya. Ketika Beliau sudah berdiri hendak shalat aku hampiri Beliau lalu aku berkata: \"Wahai Rasulullah, apakah anda akan menyolatkan anak Ubay padahal dia suatu hari pernah mengatakan begini begini, begini dan begini, (aku mengulang-ulang ucapan bin Ubay yang dahulu pernah dilontarkan kepada Nabi) \". Ternyata Rasulullah Shallallahu'alaihiwasallam malah tersenyum seraya berkata,: \"Cukupkanlah ucapanmu dariku wahai 'Umar. Ketika aku terus berbicara kepada Beliau, Beliau berkata,: \"Sungguh aku diberi pilihan dan aku memilih seandainya aku mengetahui bila aku menambah lebih dari tujuh puluh kali permohonan ampun baginya dia akan diampuni, pasti aku akan tambah (permohonan ampun baginya) \". 'Umar berkata,: \"Maka kemudian Rasulullah Shallallahu'alaihiwasallam menyolatkannya hingga selesai, tak lama setelah Beliau terdiam, turunlah firman Allah subhanahu wata'ala QS At-Taubah ayat 84 yang artinya (\"Dan janganlah kamu menyolatkan siapa yang mati dari mereka selamanya\" hingga ayat \"mereka mati dalam keadaan fasiq\")."},{"p":"Bukhari","n":3997,"ar":"حَدَّثَنِي عُبَيْدُ بْنُ إِسْمَاعِيلَ عَنْ أَبِي أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ جَاءَ ابْنُهُ عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ أَنْ يُعْطِيَهُ قَمِيصَهُ يُكَفِّنُ فِيهِ أَبَاهُ فَأَعْطَاهُ ثُمَّ سَأَلَهُ أَنْ يُصَلِّيَ عَلَيْهِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَقَامَ عُمَرُ فَأَخَذَ بِثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ تُصَلِّي عَلَيْهِ وَقَدْ نَهَاكَ رَبُّكَ أَنْ تُصَلِّيَ عَلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا خَيَّرَنِي اللَّهُ فَقَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً }وَسَأَزِيدُهُ عَلَى السَّبْعِينَ قَالَ إِنَّهُ مُنَافِقٌ قَالَ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }","trj":"Telah menceritakan kepadaku ['Ubaid bin Isma'il] dari [Abu Usamah] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dia berkata; \"Ketika Abdullah bin Ubay meninggal dunia. anak laki-lakinya -yaitu Abdulah bin Abdullah- datang kepada Rasulullah shallallahu 'alaihi wasallam seraya memohon kepada beIiau agar sudi memberikan baju beliau kepada Abdullah untuk kain kafan ayahnya, Abdullah bin Ubay bin Salul. Lalu Rasulullah shallallahu 'alaihi wasallam memberikan bajunya kepada Abdullah. setelah itu, Abdullah juga memohon Rasulullah agar beliau berkenan menshalati jenazah ayahnya. Kemudian Rasulullah pun bersiap-siap untuk menshalati jenazah Abdullah bin Ubay, hingga akhirnya Umar berdiri dan menarik baju Rasulullah seraya berkata, \"Ya Rasulullah, apakah engkau akan menshalati jenazah Abdullah bin Ubay sedangkan Allah telah melarang untuk menshalatinya?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Sesungguhnya Allah Subhanahu wa Ta'ala telah memberikan pilihan kepadaku.\" Lalu beliau membacakan ayat yang berbunyi; \"Kamu memohonkun ampun bagi orang-orang munafik atau tidak kamu mohonkan ampun bagi mereka, maka hal itu adalah sama saja. sekalipun kamu memohonkan ampun bagi mereka tujuh puluh kali (Qs. At-Taubah 9: 80). Oleh karena itu, aku akan menambah istighfar lebih dari tujuh puluh kali untuknya.\" Umar bin Khaththab berkata, \"Ya Rasulullah, sesungguhnya Ia adalah orang munafik?.\" Tetapi, rupanya Rasulullah shallallahu 'alaihi wasallam tetap saja menshalatinya, hingga Allah menurunkan ayat Al Qur'an: \"Janganlah kamu sekali-kali menshalati jenazah seorang di antara orang-orang munafik dan janganlah kamu berdiri di atas kuburnya.\" (Qs. At-Taubah 9: 84)."},{"p":"Bukhari","n":3998,"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ و قَالَ غَيْرُهُ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُأَنَّهُ قَالَ لَمَّا مَاتَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ دُعِيَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَلَمَّا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَثَبْتُ إِلَيْهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَتُصَلِّي عَلَى ابْنِ أُبَيٍّ وَقَدْ قَالَ يَوْمَ كَذَا كَذَا وَكَذَا قَالَ أُعَدِّدُ عَلَيْهِ قَوْلَهُ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَخِّرْ عَنِّي يَا عُمَرُ فَلَمَّا أَكْثَرْتُ عَلَيْهِ قَالَ إِنِّي خُيِّرْتُ فَاخْتَرْتُ لَوْ أَعْلَمُ أَنِّي إِنْ زِدْتُ عَلَى السَّبْعِينَ يُغْفَرْ لَهُ لَزِدْتُ عَلَيْهَا قَالَ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ انْصَرَفَ فَلَمْ يَمْكُثْ إِلَّا يَسِيرًا حَتَّى نَزَلَتْ الْآيَتَانِ مِنْ بَرَاءَةَ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا إِلَى قَوْلِهِ وَهُمْ فَاسِقُونَ }قَالَ فَعَجِبْتُ بَعْدُ مِنْ جُرْأَتِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهُ وَرَسُولُهُ أَعْلَمُ","trj":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari ['Uqail]. -dan yang lainnya berkata- Telah menceritakan kepadaku Al Laits Telah menceritakan kepadaku Uqail dari [Ibnu Syihab] dia berkata; Telah mengabarkan kepadaku ['Ubaidullah bin 'Abdullah] dari [Ibnu 'Abbas] dari ['Umar bin Al Khaththab radliallahu 'anhu] Tatkala Abdullah bin Ubai bin Salul meninggal dunia, Rasulullah shallallahu 'alaihi wasallam diundang untuk menshalatinya. Setelah Rasulullah shallallahu 'alaihi wasallam berdiri untuk melaksanakan Shalat, aku meloncat ke arah beliau, lalu aku berkata, \"Wahai Rasulullah shallallahu 'alaihi wasallam, kenapa engkau menshalati Ibnu Ubay, padahal ia telah mengatakan di hari ini-itu begini dan begitu?! Aku hitung-hitung kejelekannya, Rasulullah shallallahu 'alaihi wasallam tersenyum seraya bersabda: \"Tundalah -perkataanmu- dariku wahai Umar!\" setelah aku mengulang menyebut-nyebut kejelekannya, beliau bersabda: \" Aku telah diberikan pilihan, aku memilih. Andaikata aku tahu kalau aku menambahnya lebih dari tujuh puluh ia akan diampuni, niscaya aku menambahnya!.\"Lalu Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat atasnya, kemudian beliau pergi dan tidak berada di tempat itu kecuali hanya sejenak, hingga turun dua ayat dari surah Bara'ah, \"(Dan janganlah kamu sekali-kali menshalatkan (jenazah) seorang yang mati di antara mereka, dan janganlah kamu berdiri (mendo'akan) di kuburnya. mereka telah kafir kepada Allah dan RasulNya dan mereka mati dalam keadaan fasik.\" (Qs. At-Taubah: 84). Setelah itu aku heran atas keberanianku terhadap Rasulullah shallallahu 'alaihi wasallam ketika itu. Dan hanya Allah dan Rasul-Nya yang lebih mengatahui.\""},{"p":"Bukhari","n":3999,"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ قَالَ لَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ جَاءَ ابْنُهُ عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَاهُ قَمِيصَهُ وَأَمَرَهُ أَنْ يُكَفِّنَهُ فِيهِ ثُمَّ قَامَ يُصَلِّي عَلَيْهِ فَأَخَذَ عُمَرُ بْنُ الْخَطَّابِ بِثَوْبِهِ فَقَالَ تُصَلِّي عَلَيْهِ وَهُوَ مُنَافِقٌ وَقَدْ نَهَاكَ اللَّهُ أَنْ تَسْتَغْفِرَ لَهُمْ قَالَ إِنَّمَا خَيَّرَنِي اللَّهُ أَوْ أَخْبَرَنِي اللَّهُ فَقَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً فَلَنْ يَغْفِرَ اللَّهُ لَهُمْ }فَقَالَ سَأَزِيدُهُ عَلَى سَبْعِينَ قَالَ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَلَّيْنَا مَعَهُ ثُمَّ أَنْزَلَ اللَّهُ عَلَيْهِ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ إِنَّهُمْ كَفَرُوا بِاللَّهِ وَرَسُولِهِ وَمَاتُوا وَهُمْ فَاسِقُونَ }","trj":"Telah menceritakan kepadaku [Ibrahim bin Al Mundzir] Telah menceritakan kepada kami [Anas bin 'Iyadl] dari ['Ubaidillah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dia berkata; \"Ketika Abdullah bin Ubay meninggal dunia. anak laki-lakinya -yaitu Abdulah bin Abdullah- datang kepada Rasulullah shallallahu 'alaihi wasallam dan beliau berikan bajunya dan beliau perintahkannya untuk mengafani ayahnya dengan bajunya tersebut. Lalu Rasulullah shallallahu 'alaihi wasallam menshalati jenazah ayah Abdullah bin Abdullah bin Ubbay. Hingga akhirnya Umar menarik baju Rasulullah seraya berkata; \"Ya Rasulullah, apakah engkau akan menshalati jenazah Abdullah bin Ubay sedangkan dia itu orang munafik? Padahal Allah telah melarang engkau memintakan ampun untuknya?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Sesungguhnya Allah Subhanahu wa Ta'ala telah memberikan pilihan kepadaku atau mengabariku.\" Lalu beliau membacakan ayat yang berbunyi; \"Kamu memohonkun ampun bagi orang-orang munafik atau tidak kamu mohonkan ampun bagi mereka, maka hal itu adalah sama saja. sekalipun kamu memohonkan ampun bagi mereka tujuh puluh kali sekali-kali Allah tidak akan mengampuni mereka (Qs. At-Taubah 9: 80). Rasulullah shallallahu 'alaihi wasallam bersabda: Aku akan menambah istighfar lebih dari tujuh puluh kali untuknya.\" Maka Rasulullah shallallahu 'alaihi wasallam tetap saja menshalatinya dan kami pun shalat bersamanya hingga Allah menurunkan ayat Al Qur'an: \"Janganlah kamu sekali-kali menshalati jenazah seorang di antara orang-orang munafik dan janganlah kamu berdiri di atas kuburnya, sesungguhnya mereka telah kafir kepada Allah dan Rasul-Nya dan mereka mati dalam keadaan munafiq.\" (Qs. At-Taubah 9: 84)."},{"p":"Muslim","n":4077,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَلَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ جَاءَ ابْنُهُ عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ أَنْ يُعْطِيَهُ قَمِيصَهُ أَنْ يُكَفِّنَ فِيهِ أَبَاهُ فَأَعْطَاهُ ثُمَّ سَأَلَهُ أَنْ يُصَلِّيَ عَلَيْهِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَقَامَ عُمَرُ فَأَخَذَ بِثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَتُصَلِّي عَلَيْهِ وَقَدْ نَهَاكَ اللَّهُ أَنْ تُصَلِّيَ عَلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا خَيَّرَنِي اللَّهُ فَقَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً }وَسَأَزِيدُ عَلَى سَبْعِينَ قَالَ إِنَّهُ مُنَافِقٌ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }و حَدَّثَنَاه مُحَمَّدُ بْنُ الْمُثَنَّى وَعُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا يَحْيَى وَهُوَ الْقَطَّانُ عَنْ عُبَيْدِ اللَّهِ بِهَذَا الْإِسْنَادِ فِي مَعْنَى حَدِيثِ أَبِي أُسَامَةَ وَزَادَ قَالَ فَتَرَكَ الصَّلَاةَ عَلَيْهِمْ","trj":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah]; Telah menceritakan kepada kami [Abu Usamah]; Telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar] dia berkata; \"Ketika Abdullah bin Ubay bin Salul meninggal dunia. anak laki-lakinya -yaitu Abdulah bin Abdullah- datang kepada Rasulullah shallallahu 'alaihi wasallam seraya memohon kepada beIiau agar sudi memberikan baju beliau kepada Abdullah untuk kain kafan ayahnya, Abdullah bin Ubay bin Salul. Lalu Rasulullah shallallahu 'alaihi wasallam memberikan bajunya kepada Abdullah. Setelah itu, Abdullah juga memohon Rasulullah agar beliau berkenan menshalati jenazah ayahnya. Kemudian Rasulullah pun bersiap-siap untuk menshalati jenazah Abdullah bin Ubay, hingga akhirnya Umar berdiri dan menarik baju Rasulullah seraya berkata, \"Ya Rasulullah, apakah engkau akan menshalati jenazah Abdullah bin Ubay sedangkan Allah telah melarang untuk menshalatinya?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Sesungguhnya Allah Subhanahu wa Ta'ala telah memberikan pilihan kepadaku.\" Lalu beliau membacakan ayat yang berbunyi; \"Kamu memohonkun ampun bagi orang-orang munafik atau tidak kamu mohonkan ampun bagi mereka, maka hal itu adalah sama saja. sekalipun kamu memohonkan ampun bagi mereka tujuh puluh kali (Qs. At-Taubah 9: 80). Oleh karena itu, aku akan menambah istighfar lebih dari tujuh puluh kali untuknya.\" Umar bin Khaththab berkata, \"Ya Rasulullah, sesungguhnya Ia adalah orang munafik?.\" Tetapi, rupanya Rasulullah shallallahu 'alaihi wasallam tetap saja menshalatinya, hingga Allah menurunkan ayat Al Qur'an: \"Janganlah kamu sekali-kali menshalati jenazah seorang di antara orang-orang munafik dan janganlah kamu berdiri di atas kuburnya.\" (Qs. At-Taubah 9: 84). Dan telah menceritakannya kepada kami [Muhammad bin Al Mutsanna] dan ['Ubaidullah bin Sa'id] keduanya berkata; Telah menceritakan kepada kami [Yahya] yaitu Al Qaththan dari ['Ubaidillah] melalui jalur ini mengenai Hadits yang semakna dengan Abu Usamah namun ada tambahan; 'Kemudian beliau meninggalkan shalat untuk mereka (orang-orang munafik)."},{"p":"Nasa'i","n":1895,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا حُجَيْنُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَلَمَّا مَاتَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ دُعِيَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَلَمَّا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَثَبْتُ إِلَيْهِ فَقُلْتُ يَا رَسُولَ اللَّهِ تُصَلِّي عَلَى ابْنِ أُبَيٍّ وَقَدْ قَالَ يَوْمَ كَذَا وَكَذَا كَذَا وَكَذَا أُعَدِّدُ عَلَيْهِ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَخِّرْ عَنِّي يَا عُمَرُ فَلَمَّا أَكْثَرْتُ عَلَيْهِ قَالَ إِنِّي قَدْ خُيِّرْتُ فَاخْتَرْتُ فَلَوْ عَلِمْتُ أَنِّي لَوْ زِدْتُ عَلَى السَّبْعِينَ غُفِرَ لَهُ لَزِدْتُ عَلَيْهَا فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ انْصَرَفَ فَلَمْ يَمْكُثْ إِلَّا يَسِيرًا حَتَّى نَزَلَتْ الْآيَتَانِ مِنْ بَرَاءَةَ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ إِنَّهُمْ كَفَرُوا بِاللَّهِ وَرَسُولِهِ وَمَاتُوا وَهُمْ فَاسِقُونَ }فَعَجِبْتُ بَعْدُ مِنْ جُرْأَتِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ وَاللَّهُ وَرَسُولُهُ أَعْلَمُ","trj":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Hujain bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah] dari ['Abdullah bin 'Abbas] dari ['Umar bin Al Khaththab] dia berkata; Setelah Abdullah bin Ubai bin Salul meninggal dunia, Rasulullah shallallahu 'alaihi wasallam diundang untuk menshalatinya. Setelah Rasulullah shallallahu 'alaihi wasallam berdiri untuk melaksanakan Shalat, aku meloncat ke arah beliau, lalu aku berkata, \"Wahai Rasulullah shallallahu 'alaihi wasallam, engkau menshalati Ibnu Ubbay, padahal ia telah mengatakan hari ini dan itu begini dan itu begitu?! Aku menyebut kejelekannya, Rasulullah shallallahu 'alaihi wasallam tersenyum seraya bersabda: \"Tundalah -perkataanmu- dariku wahai Umar!\" setelah aku mengulang menyebut-nyebut kejelekannya, beliau bersabda: \" Aku telah diberikan pilihan, aku memilih. Andaikata aku tahu, kalau aku menambahnya lebih dari tujuh puluh ia akan diampuni, niscaya aku menambahnya!.\"Lalu Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat atasnya, kemudian beliau pergi dan tidak berada di tempat itu kecuali hanya sejenak, hingga turun dua ayat dari surah Bara'ah, \"(Dan janganlah kamu sekali-kali menshalatkan (jenazah) seorang yang mati di antara mereka, dan janganlah kamu berdiri (mendo'akan) di kuburnya. mereka telah kafir kepada Allah dan RasulNya dan mereka mati dalam keadaan fasik.\" (Qs. At-Taubah 9: 84). Setelah itu aku heran atas keberanianku terhadap Rasulullah shallallahu 'alaihi wasallam ketika itu. Dan hanya Allah dan Rasul-Nya yang lebih mengatahui.\""}],"9:92":[{"p":"Abu Dawud","n":3867,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا ثَوْرُ بْنُ يَزِيدَ قَالَ حَدَّثَنِي خَالِدُ بْنُ مَعْدَانَ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَمْرٍو السُّلَمِيُّ وَحُجْرُ بْنُ حُجْرٍ قَالَاأَتَيْنَا الْعِرْبَاضَ بْنَ سَارِيَةَ وَهُوَ مِمَّنْ نَزَلَ فِيهِ{ وَلَا عَلَى الَّذِينَ إِذَا مَا أَتَوْكَ لِتَحْمِلَهُمْ قُلْتَ لَا أَجِدُ مَا أَحْمِلُكُمْ عَلَيْهِ }فَسَلَّمْنَا وَقُلْنَا أَتَيْنَاكَ زَائِرِينَ وَعَائِدِينَ وَمُقْتَبِسِينَ فَقَالَ الْعِرْبَاضُ صَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ ثُمَّ أَقْبَلَ عَلَيْنَا فَوَعَظَنَا مَوْعِظَةً بَلِيغَةً ذَرَفَتْ مِنْهَا الْعُيُونُ وَوَجِلَتْ مِنْهَا الْقُلُوبُ فَقَالَ قَائِلٌ يَا رَسُولَ اللَّهِ كَأَنَّ هَذِهِ مَوْعِظَةُ مُوَدِّعٍ فَمَاذَا تَعْهَدُ إِلَيْنَا فَقَالَ أُوصِيكُمْ بِتَقْوَى اللَّهِ وَالسَّمْعِ وَالطَّاعَةِ وَإِنْ عَبْدًا حَبَشِيًّا فَإِنَّهُ مَنْ يَعِشْ مِنْكُمْ بَعْدِي فَسَيَرَى اخْتِلَافًا كَثِيرًا فَعَلَيْكُمْ بِسُنَّتِي وَسُنَّةِ الْخُلَفَاءِ الْمَهْدِيِّينَ الرَّاشِدِينَ تَمَسَّكُوا بِهَا وَعَضُّوا عَلَيْهَا بِالنَّوَاجِذِ وَإِيَّاكُمْ وَمُحْدَثَاتِ الْأُمُورِ فَإِنَّ كُلَّ مُحْدَثَةٍ بِدْعَةٌ وَكُلَّ بِدْعَةٍ ضَلَالَةٌ","trj":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Tsaur bin Yazid] ia berkata; telah menceritakan kepadaku [Khalid bin Ma'dan] ia berkata; telah menceritakan kepadaku ['Abdurrahman bin Amru As Sulami] dan [Hujr bin Hujr] keduanya berkata, \"Kami mendatangi [Irbadh bin Sariyah], dan ia adalah termasuk seseorang yang turun kepadanya ayat: '(dan tiada (pula dosa) atas orang-orang yang apabila mereka datang kepadamu, suapaya kami memberi mereka kendaraan, lalu kamu berkata, \"Aku tidak memperoleh kendaraan orang yang membawamu) ' -Qs. At Taubah: 92- kami mengucapkan salam kepadanya dan berkata, \"Kami datang kepadamu untuk ziarah, duduk-duduk mendengar sesuatu yang berharga darimu.\" Irbadh berkata, \"Suatu ketika Rasulullah shallallahu 'alaihi wasallam shalat bersama kami, beliau lantas menghadap ke arah kami dan memberikan sebuah nasihat yang sangat menyentuh yang membuat mata menangis dan hati bergetar. Lalu seseorang berkata, \"Wahai Rasulullah, seakan-akan ini adalah nasihat untuk perpisahan! Lalu apa yang engkau washiatkan kepada kami?\" Beliau mengatakan: \"Aku wasiatkan kepada kalian untuk bertakwa kepada Allah, senantiasa taat dan mendengar meskipun yang memerintah adalah seorang budak habsyi yang hitam. Sesungguhnya orang-orang yang hidup setelahku akan melihat perselisihan yang banyak. Maka, hendaklah kalian berpegang dengan sunahku, sunah para khalifah yang lurus dan mendapat petunjuk, berpegang teguhlah dengannya dan gigitlah dengan gigi geraham. Jauhilah oleh kalian perkara-perkara baru (dalam urusan agama), sebab setiap perkara yang baru adalah bid'ah dan setaip bid'ah adalah sesat.\""},{"p":"Ahmad","n":2676,"ar":"حَدَّثَنَا وَكِيعٌ عَنْ أَبِي جَعْفَرٍ الرَّازِيِّ عَنِ الرَّبِيعِ بْنِ أَنَسٍ عَنْ أَبِي الْعَالِيَةِ أَوْ عَنْ غَيْرِهِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ وَكَانَ أَحَدَ الرَّهْطِ الَّذِينَ نَزَلَتْ فِيهِمْ هَذِهِ الْآيَةُ{ وَلَا عَلَى الَّذِينَ إِذَا مَا أَتَوْكَ لِتَحْمِلَهُمْ }إِلَى آخِرِ الْآيَةِ قَالَإِنِّي لَآخِذٌ بِغُصْنٍ مِنْ أَغْصَانِ الشَّجَرَةِ أُظِلُّ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمْ يُبَايِعُونَهُ فَقَالُوا نُبَايِعُكَ عَلَى الْمَوْتِ قَالَ لَا وَلَكِنْ لَا تَفِرُّوا","trj":"Telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Abu Ja'far Ar Razi] dari [Rabi' bin Anas] dari [Abu 'Aliyah] atau yang lain dari [Abdullah bin Mughaffal] -dia adalah salah seorang yang diturunkan ayat ini kepada mereka, yaitu; \"WALAA 'ALAL LADZIINA IDZA MAA ATAUKA LITAHMILAHUM (Dan tiada pula berdosa atas orang-orang yang apabila mereka datang kepadamu, supaya kamu memberi mereka kendaraan).\" (QS At Taubah: 92) sampai akhir ayat, Abdullah bin Mughaffal berkata; \"Sesungguhnya aku pernah mengambil dahan pohon untuk kujadikan tempat naungan Nabi shallallahu 'alaihi wasallam dan para sahabat ketika mereka berbai'at kepada beliau, lalu mereka berkata; \"Apakah kami berbai'at kepadamu untuk mati.\" beliau bersabda: \"Akan tetapi (berbai'atlah) untuk tidak lari.\""}],"9:95":[{"p":"Bukhari","n":4000,"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ كَعْبِ بْنِ مَالِكٍ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍحِينَ تَخَلَّفَ عَنْ تَبُوكَ وَاللَّهِ مَا أَنْعَمَ اللَّهُ عَلَيَّ مِنْ نِعْمَةٍ بَعْدَ إِذْ هَدَانِي أَعْظَمَ مِنْ صِدْقِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا أَكُونَ كَذَبْتُهُ فَأَهْلِكَ كَمَا هَلَكَ الَّذِينَ كَذَبُوا حِينَ أُنْزِلَ الْوَحْيُ{ سَيَحْلِفُونَ بِاللَّهِ لَكُمْ إِذَا انْقَلَبْتُمْ إِلَيْهِمْ إِلَى قَوْلِهِ الْفَاسِقِينَ }","trj":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Abdur Rahman bin 'Abdullah] sesungguhnya [Abdullah bin Ka'ab bin Malik] berkata; Aku mendengar [Ka'ab bin Malik] ketika dia tertinggal dari perang Tabuk; 'Demi Allah, tidak ada nikmat yang telah di berikan Allah kepada saya, setelah Allah menunjukan kepada saya Islam, yang saya anggap lebih besar daripada kejujuranku kepada Rasulullah shallallahu 'alaihi wasallam, Seandainya saya berdusta kepada beliau, maka saya akan celaka sebagaimana orang-orang yang telah berdusta ketika diturunkan wahyu yang berbunyi: 'Kelak mereka akan bersumpah kepadamu dengan nama Allah apabila kamu kembali kepada mereka supaya kamu berpaling dari mereka. Maka berpalinglah kamu dari mereka, karena sesungguhnya mereka itu najis dan tempat mereka adalah jahannam sebagai balasan dari apa yang telah mereka kerjakan. Mereka akan bersumpah kepadamu supaya kamu ridla kepada mereka, maka sesungguhnya Allah tidak ridla kepada orang-orang yang fasik itu.' (Qs. At-taubah (9): 95-96)."}],"9:113":[{"p":"Bukhari","n":1272,"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنِي أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ عَنْ أَبِيهِ أَنَّهُ أَخْبَرَهُ أَنَّهُلَمَّا حَضَرَتْ أَبَا طَالِبٍ الْوَفَاةُ جَاءَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدَ عِنْدَهُ أَبَا جَهْلِ بْنَ هِشَامٍ وَعَبْدَ اللَّهِ بْنَ أَبِي أُمَيَّةَ بْنِ الْمُغِيرَةِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَبِي طَالِبٍ يَا عَمِّ قُلْ لَا إِلَهَ إِلَّا اللَّهُ كَلِمَةً أَشْهَدُ لَكَ بِهَا عِنْدَ اللَّهِ فَقَالَ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ يَا أَبَا طَالِبٍ أَتَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ فَلَمْ يَزَلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْرِضُهَا عَلَيْهِ وَيَعُودَانِ بِتِلْكَ الْمَقَالَةِ حَتَّى قَالَ أَبُو طَالِبٍ آخِرَ مَا كَلَّمَهُمْ هُوَ عَلَى مِلَّةِ عَبْدِ الْمُطَّلِبِ وَأَبَى أَنْ يَقُولَ لَا إِلَهَ إِلَّا اللَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا وَاللَّهِ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْكَ فَأَنْزَلَ اللَّهُ تَعَالَى فِيهِ{ مَا كَانَ لِلنَّبِيِّ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Ya'qub bin Ibrahim] berkata, telah menceritakan [apakku] kepadaku dari [Shalih] dari [Ibnu Syihab] berkata, telah mengabarkan kepada saya telah mengabarkan kepada saya [Sa'id bin Al Musayyab] dari [bapaknya] bahwasanya dia mengabarkan kepadanya: \"Ketika menjelang wafatnya Abu Tholib, Rasulullah Shallallahu'alaihiwasallam mendatanginya dan ternyata sudah ada Abu Jahal bin Hisyam dan 'Abdullah bin Abu Umayyah bin Al Mughirah. Maka Rasulullah Shallallahu'alaihiwasallam berkata, kepada Abu Tholib: \"Wahai pamanku katakanlah laa ilaaha illallah, suatu kalimat yang dengannya aku akan menjadi saksi atasmu di sisi Allah\". Maka berkata, Abu Jahal dan 'Abdullah bin Abu Umayyah: \"Wahai Abu Thalib, apakah kamu akan meninggalkan agama 'Abdul Muthalib?\". Rasulullah Shallallahu'alaihiwasallam terus menawarkan kalimat syahadat kepada Abu Tholib dan bersamaan itu pula kedua orang itu mengulang pertanyaannya yang berujung Abu Tholib pada akhir ucapannya tetap mengikuti agama 'Abdul Muthalib dan enggan untuk mengucapkan laa ilaaha illallah. Maka berkatalah Rasulullah Shallallahu'alaihiwasallam: \"Adapun aku akan tetap memintakan ampun buatmu selama aku tidak dilarang\". Maka turunlah firman Allah subhanahu wata'ala tentang peristiwa ini: (\"Tidak patut bagi Nabi …\") dalam QS AT-Taubah ayat 113)."},{"p":"Bukhari","n":3438,"ar":"حَدَّثَنَا مَحْمُودٌ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِيهِأَنَّ أَبَا طَالِبٍ لَمَّا حَضَرَتْهُ الْوَفَاةُ دَخَلَ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ أَبُو جَهْلٍ فَقَالَ أَيْ عَمِّ قُلْ لَا إِلَهَ إِلَّا اللَّهُ كَلِمَةً أُحَاجُّ لَكَ بِهَا عِنْدَ اللَّهِ فَقَالَ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ يَا أَبَا طَالِبٍ تَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ فَلَمْ يَزَالَا يُكَلِّمَانِهِ حَتَّى قَالَ آخِرَ شَيْءٍ كَلَّمَهُمْ بِهِ عَلَى مِلَّةِ عَبْدِ الْمُطَّلِبِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْهُ فَنَزَلَتْ{ مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ وَلَوْ كَانُوا أُولِي قُرْبَى مِنْ بَعْدِ مَا تَبَيَّنَ لَهُمْ أَنَّهُمْ أَصْحَابُ الْجَحِيمِ }وَنَزَلَتْ{ إِنَّكَ لَا تَهْدِي مَنْ أَحْبَبْتَ }","trj":"Telah menceritakan kepada kami [Mahmud] telah menceritakan kepada kami ['Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnu Al Musayyab] dari [bapaknya] bahwa ketika menjelang wafatnya Abu Thalib, Nabi shallallahu 'alaihi wasallam masuk menemuinya sementara di sampingnya ada Abu Jahal. Beliau berkata: \"Wahai pamanku, katakanlah laa ilaaha illallah. Suatu kalimat yang akan aku pergunakan untuk menyelamatkan engkau di sisi Allah\". Maka berkata Abu Jahal dan Abdullah bin Abu Umayyah; \"Wahai Abu Thalib, apakah kamu akan meninggalkan agama 'Abdul Muthallib?\". Keduanya terus saja mengajak Abu Thalib berbicara hingga kalimat terakhir yang diucapkannya kepada mereka adalah dia tetap mengikuti agama 'Abdul Muthallib. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Aku akan tetap memintakan ampun untukmu selama aku tidak dilarang\". Maka turunlah firman Allah Ta'ala dalam QS AT-Taubah ayat 113 yang artinya: (\"Tidak patut bagi Nabi dan orang-orang beriman untuk memohonkan ampun bagi orang-orangmusyrik sekalipun mereka itu adalah kerabat-kerabat mereka setelah jelas bagi mereka (kaum mu'minin) bahwa mereka adalah penghuni neraka jahim..\"). Dan turun pula firman Allah Ta'ala dalam QS al Qashsash ayat 56 yang artinya: (\"Sesungguhnya engkau (wahai Muhammad) tidak akan dapat memberi petunjuk kepada orang yang engkau cintai...\") "},{"p":"Muslim","n":35,"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى التُّجِيبِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ عَنْ أَبِيهِ قَالَلَمَّا حَضَرَتْ أَبَا طَالِبٍ الْوَفَاةُ جَاءَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدَ عِنْدَهُ أَبَا جَهْلٍ وَعَبْدَ اللَّهِ بْنَ أَبِي أُمَيَّةَ بْنِ الْمُغِيرَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَمِّ قُلْ لَا إِلَهَ إِلَّا اللَّهُ كَلِمَةً أَشْهَدُ لَكَ بِهَا عِنْدَ اللَّهِ فَقَالَ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ يَا أَبَا طَالِبٍ أَتَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ فَلَمْ يَزَلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْرِضُهَا عَلَيْهِ وَيُعِيدُ لَهُ تِلْكَ الْمَقَالَةَ حَتَّى قَالَ أَبُو طَالِبٍ آخِرَ مَا كَلَّمَهُمْ هُوَ عَلَى مِلَّةِ عَبْدِ الْمُطَّلِبِ وَأَبَى أَنْ يَقُولَ لَا إِلَهَ إِلَّا اللَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا وَاللَّهِ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْكَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ وَلَوْ كَانُوا أُولِي قُرْبَى مِنْ بَعْدِ مَا تَبَيَّنَ لَهُمْ أَنَّهُمْ أَصْحَابُ الْجَحِيمِ }وَأَنْزَلَ اللَّهُ تَعَالَى فِي أَبِي طَالِبٍ فَقَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِنَّكَ لَا تَهْدِي مَنْ أَحْبَبْتَ وَلَكِنَّ اللَّهَ يَهْدِي مَنْ يَشَاءُ وَهُوَ أَعْلَمُ بِالْمُهْتَدِينَ }و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ ح و حَدَّثَنَا حَسَنٌ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا حَدَّثَنَا يَعْقُوبُ وَهُوَ ابْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ حَدَّثَنِي أَبِي عَنْ صَالِحٍ كِلَاهُمَا عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ مِثْلَهُ غَيْرَ أَنَّ حَدِيثَ صَالِحٍ انْتَهَى عِنْدَ قَوْلِهِ فَأَنْزَلَ الل��َهُ عَزَّ وَجَلَّ فِيهِ وَلَمْ يَذْكُرْ الْآيَتَيْنِ وَقَالَ فِي حَدِيثِهِ وَيَعُودَانِ فِي تِلْكَ الْمَقَالَةِ وَفِي حَدِيثِ مَعْمَرٍ مَكَانَ هَذِهِ الْكَلِمَةِ فَلَمْ يَزَالَا بِهِ","trj":"Dan telah menceritakan kepadaku [Harmalah bin Yahya at-Tujibi] telah mengabarkan kepadaku [Abdullah bin Wahb] dia berkata, telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dia berkata, telah mengabarkan kepadaku [Said bin al-Musayyab] dari [bapaknya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menziarahi Abu Thalib di saat-saat dirinya tengah menghadapi sakaratul maut. Beliau mendapati Abu Jahal dan Abdullah bin Abu Umaiyyah bin al-Mughirah turut berada di sana. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Paman! Ucaplah Dua Kalimah Syahadat, aku akan menjadi saksi kamu di hadapan Allah.\" Lalu Abu Jahal dan Abdullah bin Abu Umayyah mencelah, 'Wahai Abu Thalib sanggupkah kamu meninggalkan agama Abdul Muththalib? ' Rasulullah shallallahu 'alaihi wasallam tidak berputus asa malah tetap mengajarnya mengucap Dua Kalimah Syahadat serta berkali-kali mengulanginya. Sehingga Abu Thalib menjawab sebagai ucapan terakhir kepada mereka, bahwa dia tetap bersama dengan agama Abdul MuThalib, dan enggan mengucapkan Kalimah Syahadat. Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Demi Allah, aku akan mohonkan ampunan dari Allah untukmu, \" sehingga Allah menurunkan ayat: '(Tidak dibenarkan bagi Nabi dan orang-orang yang beriman meminta ampun bagi orang-orang yang syirik sekalipun orang itu kaum kerabat sendiri setelah nyata bagi mereka bahwa orang-orang syirik itu adalah ahli Neraka) ' (Qs. AtTaubah: 113). Lalu Allah menurunkan firman-Nya berkenaan dengan peristiwa Abu Thalib: '(Sesungguhnya kamu wahai Muhammad tidak berkuasa memberi hidayat petunjuk kepada siapa yang kamu kasihi supaya dia menerima Islam tetapi Allah jualah yang berkuasa memberi petunjuk kepada orang yang dikehendaki-Nya, dan Dia jualah yang lebih mengetahui siapakah orang-orang yang (bersedia) untuk mendapat petunjuk memeluk Islam) '. (Qs. Al Qashash: 56). Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Abd bin Humaid] keduanya berkata, telah mengabarkan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar]. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Hasan al-Hulwani] dan [Abd bin Humaid] keduanya berkata, telah menceritakan kepada kami [Ya'qub] -yaitu Ibnu Ibrahim bin Sa'ad- dia berkata, telah menceritakan kepada kami [bapakku] dari [Shalih] keduanya dari [az-Zuhri] dengan sanad ini semisalnya. Hanya saja hadits Shalih selesai pada perkataannya, 'lalu Allah menurunkan firman-Nya tentangnya, ' dan dia tidak menyebutkan dua ayat tersebut. Dan dia menyebutkan di dalam haditsnya, 'Dan keduanya kembali mengucapkan perkataan tersebut, ' pada hadits Ma'mar adalah sebagai pengganti kalimat ini. Dan mereka berdua tetap berpedoman padanya.\""}],"9:114":[{"p":"Nasa'i","n":1964,"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْخَلِيلِ عَنْ عَلِيٍّ قَالَسَمِعْتُ رَجُلًا يَسْتَغْفِرُ لِأَبَوَيْهِ وَهُمَا مُشْرِكَانِ فَقُلْتُ أَتَسْتَغْفِرُ لَهُمَا وَهُمَا مُشْرِكَانِ فَقَالَ أَوَ لَمْ يَسْتَغْفِرْ إِبْرَاهِيمُ لِأَبِيهِ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَنَزَلَتْ{ وَمَا كَانَ اسْتِغْفَارُ إِبْرَاهِيمَ لِأَبِيهِ إِلَّا عَنْ مَوْعِدَةٍ وَعَدَهَا إِيَّاهُ }","trj":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dari [Sufyan] dari [Abu Ishaq] dari [Abul Khalil] dari ['Ali] dia berkata; Aku mendengar seseorang memintakan ampunan bagi kedua orang tuanya sedang keduanya musyrik, maka aku bertanya kepadanya; \"Apakah engkau memintakan ampunan untuk mereka berdua, padahal mereka musyrik?\" ia menjawab, \"Bukankah Nabi Ibrahim juga memintakan ampunan untuk bapaknya?\" lalu aku menemui Nabi shallallahu 'alaihi wasallam dan aku ceritakan hal itu kepada beliau, lalu turunlah ayat, \"Dan permintaan ampun dari Ibrahim (kepada Allah) untuk bapaknya tidak lain hanyalah karena suatu janji yang telah diikrarkannya kepada bapaknya itu.\" (Qs. At Taubah 9: 114)"}],"9:116":[{"p":"Darimi","n":92,"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ قَالَ إِنَّ أَهْلَ الْأَهْوَاءِ أَهْلُ الضَّلَالَةِ وَلَا أَرَى مَصِيرَهُمْ إِلَّا النَّارَ فَجَرِّبْهُمْ فَلَيْسَ أَحَدٌ مِنْهُمْ يَنْتَحِلُ قَوْلًا أَوْ قَالَ حَدِيثًا فَيَتَنَاهَى بِهِ الْأَمْرُ دُونَ السَّيْفِ وَإِنَّ النِّفَاقَ كَانَ ضُرُوبًا ثُمَّ تَلَا { وَمِنْهُمْ مَنْ عَاهَدَ اللَّهَ } { وَمِنْهُمْ مَنْ يَلْمِزُكَ فِي الصَّدَقَاتِ } { وَمِنْهُمْ الَّذِينَ يُؤْذُونَ النَّبِيَّ } فَاخْتَلَفَ قَوْلُهُمْ وَاجْتَمَعُوا فِي الشَّكِّ وَالتَّكْذِيبِ وَإِنَّ هَؤُلَاءِ اخْتَلَفَ قَوْلُهُمْ وَاجْتَمَعُوا فِي السَّيْفِ وَلَا أَرَى مَصِيرَهُمْ إِلَّا النَّارَ قَالَ حَمَّادٌ ثُمَّ قَالَ أَيُّوبُ عِنْدَ ذَا الْحَدِيثِ أَوْ عِنْدَ الْأَوَّلِ وَكَانَ وَاللَّهِ مِنْ الْفُقَهَاءِ ذَوِي الْأَلْبَابِ يَعْنِي أَبَا قِلَابَةَ","trj":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] ia berkata: \" Sesungguhnya pemuja hawa nafsu adalah orang-orang yang sesat, dan aku tidak melihat akhir perjalanan yang mereka tempuh kecuali neraka. Ujilah mereka itu. Tidak ada seorang pun dari mereka yang menyitir perkataan atau berkata, hingga persoalannya tiada lain adalah pedang. Sesungguhnya kemunafikan sudah menjadi ciri khas mereka. Kemudian ia membaca ayat \"WA MINHUM MAN 'AHADALLAHA' (Dan diantara mereka ada orang yang telah berikrar kepada Allah Subhaanallahu wa Ta'ala) -Qs. At Taubah: 75-, dan ayat \"WA MINHUM MAN YALMIZUKA FIS SHADAQAAT' (Dan diantara mereka ada orang yang mencelamu tentang (pembagian) zakat) -Qs. At Taubah: 58-, dan ayat \"WAMINHUMULLADZINA YU`DZUUNANABIYYA' (Dan diantara mereka 'orang-orang munafik' ada yang menyakiti Nabi shallallahu 'alaihi wasallam) -Qs. Attaubah: 116-,. Kemudian mereka berbeda pendapat dan berselisih, dan akhirnya mereka berkumpul dalam keraguan dan kedustaan,. Sesungguhnya mereka berbeda pendapat dan bersatu dalam gelayut pedang. Dan aku tidak melihat perjalanan mereka kecuali ke neraka\". Hammad berkata: \"Ayyub berkata tentang hadits ini atau hadits awal, demi Allah Subhaanallahu wa Ta'ala, ia termasuk salah seorang pakar fikih yang sangat cerdas, maksudku adalah Abu Qilabah\"."}],"9:117":[{"p":"Bukhari","n":4005,"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ وَكَانَ قَائِدَ كَعْبِ بْنِ مَالِكٍ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍيُحَدِّثُ حِينَ تَخَلَّفَ عَنْ قِصَّةِ تَبُوكَ فَوَاللَّهِ مَا أَعْلَمُ أَحَدًا أَبْلَاهُ اللَّهُ فِي صِدْقِ الْحَدِيثِ أَحْسَنَ مِمَّا أَبْلَانِي مَا تَعَمَّدْتُ مُنْذُ ذَكَرْتُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى يَوْمِي هَذَا كَذِبًا وَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ لَقَدْ تَابَ اللَّهُ عَلَى النَّبِيِّ وَالْمُهَاجِرِينَ وَالْأَنْصَارِ إِلَى قَوْلِهِ وَكُونُوا مَعَ الصَّادِقِينَ }","trj":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Abdur Rahman bin 'Abdullah bin Ka'ab bin Malik] dari ['Abdullah bin Ka'ab bin Malik] -dia adalah penuntun Ka'ab bin Malik- dia berkata; Aku mendengar [Ka'ab bin Malik] bercerita mengenai ketertinggalannya dari perang Tabuk. Demi Allah, setahu saya tidak ada seorang muslim yang telah di uji Allah dalam kejujuran ucapannya, yang ia lebih baik dari pada apa yang telah diujikan Allah kepada saya sejak saya ceritakan hal ini kepada Rasulullah shallallahu 'alaihi wasallam, saya tidak pernah bermaksud untuk berdusta kepada Rasulullah hingga sekarang ini. Allah Azza wa Jalla berfirman kepada Rasulullah-Nya shallallahu 'alaihi wasallam: \"Sesungguhnya Allah telah menerima taubat Nabi, orang-orang Muhajirin, dan orang-orang Anshar… hingga ayat: 'dan hendaklah kamu bersama orang-orang yang jujur.' (Qs. At-Taubah (9): 117-119)."}],"9:128":[{"p":"Bukhari","n":4006,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي ابْنُ السَّبَّاقِ أَنَّ زَيْدَ بْنَ ثَابِتٍ الْأَنْصَارِيَّ رَضِيَ اللَّهُ عَنْهُوَكَانَ مِمَّنْ يَكْتُبُ الْوَحْيَ قَالَ أَرْسَلَ إِلَيَّ أَبُو بَكْرٍ مَقْتَلَ أَهْلِ الْيَمَامَةِ وَعِنْدَهُ عُمَرُ فَقَالَ أَبُو بَكْرٍ إِنَّ عُمَرَ أَتَانِي فَقَالَ إِنَّ الْقَتْلَ قَدْ اسْتَحَرَّ يَوْمَ الْيَمَامَةِ بِالنَّاسِ وَإِنِّي أَخْشَى أَنْ يَسْتَحِرَّ الْقَتْلُ بِالْقُرَّاءِ فِي الْمَوَاطِنِ فَيَذْهَبَ كَثِيرٌ مِنْ الْقُرْآنِ إِلَّا أَنْ تَجْمَعُوهُ وَإِنِّي لَأَرَى أَنْ تَجْمَعَ الْقُرْآنَ قَالَ أَبُو بَكْرٍ قُلْتُ لِعُمَرَ كَيْفَ أَفْعَلُ شَيْئًا لَمْ يَفْعَلْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عُمَرُ هُوَ وَاللَّهِ خَيْرٌ فَلَمْ يَزَلْ عُمَرُ يُرَاجِعُنِي فِيهِ حَتَّى شَرَحَ اللَّهُ لِذَلِكَ صَدْرِي وَرَأَيْتُ الَّذِي رَأَى عُمَرُ قَالَ زَيْدُ بْنُ ثَابِتٍ وَعُمَرُ عِنْدَهُ جَالِسٌ لَا يَتَكَلَّمُ فَقَالَ أَبُو بَكْرٍ إِنَّكَ رَجُلٌ شَابٌّ عَاقِلٌ وَلَا نَتَّهِمُكَ كُنْتَ تَكْتُبُ الْوَحْيَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَتَبَّعْ الْقُرْآنَ فَاجْمَعْهُ فَوَاللَّهِ لَوْ كَلَّفَنِي نَقْلَ جَبَلٍ مِنْ الْجِبَالِ مَا كَانَ أَثْقَلَ عَلَيَّ مِمَّا أَمَرَنِي بِهِ مِنْ جَمْعِ الْقُرْآنِ قُلْتُ كَيْفَ تَفْعَلَانِ شَيْئًا لَمْ يَفْعَلْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ هُوَ وَاللَّهِ خَيْرٌ فَلَمْ أَزَلْ أُرَاجِعُهُ حَتَّى شَرَحَ اللَّهُ صَدْرِي لِلَّذِي شَرَحَ اللَّهُ لَهُ صَدْرَ أَبِي بَكْرٍ وَعُمَرَ فَقُمْتُ فَتَتَبَّعْتُ الْقُرْآنَ أَجْمَعُهُ مِنْ الرِّقَاعِ وَالْأَكْتَافِ وَالْعُسُبِ وَصُدُورِ الرِّجَالِ حَتَّى وَجَدْتُ مِنْ سُورَةِ التَّوْبَةِ آيَتَيْنِ مَعَ خُزَيْمَةَ الْأَنْصَارِيِّ لَمْ أَجِدْهُمَا مَعَ أَحَدٍ غَيْرِهِ{ لَقَدْ جَاءَكُمْ رَسُولٌ مِنْ أَنْفُسِكُمْ عَزِيزٌ عَلَيْهِ مَا عَنِتُّمْ حَرِيصٌ عَلَيْكُمْ }إِلَى آخِرِهِمَا وَكَانَتْ الصُّحُفُ الَّتِي جُمِعَ فِيهَا الْقُرْآنُ عِنْدَ أَبِي بَكْرٍ حَتَّى تَوَفَّاهُ اللَّهُ ثُمَّ عِنْدَ عُمَرَ حَتَّى تَوَفَّاهُ اللَّهُ ثُمَّ عِنْدَ حَفْصَةَ بِنْتِ عُمَرَتَابَعَهُ عُثْمَانُ بْنُ عُمَرَ وَاللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ وَقَالَ اللَّيْثُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ وَقَالَ مَعَ أَبِي خُزَيْمَةَ الْأَنْصَارِيِّ وَقَالَ مُوسَى عَنْ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ شِهَابٍ مَعَ أَبِي خُزَيْمَةَ وَتَابَعَهُ يَعْقُوبُ بْنُ إِبْرَاهِيمَ عَنْ أَبِيهِ وَقَالَ أَبُو ثَابِتٍ حَدَّثَنَا إِبْرَاهِيمُ وَقَالَ مَعَ خُزَيْمَةَ أَوْ أَبِي خُزَيْمَةَ","trj":"Telah menceritakan kepada kami [Abu Al Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; Telah mengabarkan kepadaku [Ibnu As Sabbaq] bahwa [Zaid bin Tsabit Al Anshari radliallahu 'anhu] -salah seorang penulis wahyu- dia berkata; Abu Bakar As shiddiq datang kepadaku pada waktu perang Yamamah, ketika itu Umar disampingnya. Abu Bakr berkata bahwasanya Umar mendatangiku dan mengatakan; \"Sesungguhnya perang Yamamah telah berkecamuk (menimpa) para sahabat, dan aku khawatir akan menimpa para penghafal Qur'an di negeri-negeri lainnya sehingga banyak yang gugur dari mereka kecuali engkau memerintahkan pengumpulan (pendokumentasian) al Qur`an.\" Abu Bakar berkata kepada Umar; \"Bagaimana aku mengerjakan suatu proyek yang tidak pernah dikerjakan Rasulullah shallallahu 'alaihi wasallam?\" Umar menjawab; \"Demi Allah hal itu adalah sesuatu yang baik.\" Ia terus mengulangi hal itu sampai Allah melapangkan dadaku sebagaimana melapangkan dada Umar dan aku sependapat dengannya. Zaid berkata; Abu Bakar berkata; -pada waktu itu disampingnya ada Umar sedang duduk, dan dia tidak berkata apa-apa.- \"Sesungguhnya kamu adalah pemuda yang cerdas, kami tidak meragukanmu, dan kamu juga menulis wahyu untuk Rasulullah shallallahu 'alaihi wasallam, karena itu kumpulkanlah al Qur'an (dengan seksama).\" Zaid berkata; \"Demi Allah, seandainya mereka menyuruhku untuk memindahkan gunung dari gunung-gunung yang ada, maka hal itu tidak lebih berat bagiku dari pada (pengumpulan atau pendokumentasian al Qur'an). kenapa kalian mengerjakan sesuatu yang tidak pernah dikerjakan Rasulullah shallallahu 'alaihi wasallam?\" Abu Bakar menjawab; \"Demi Allah hal itu adalah baik.\" Aku pun terus mengulanginya, sehingga Allah melapangkan dadaku sebagaimana melapangkan dada keduanya (Abu Bakar dan Umar). Lalu aku kumpulkan al Qur'an (yang ditulis) pada kulit, pelepah kurma, dan batu putih lunak, juga dada (hafalan) para sahabat. Hingga aku mendapatkan dua ayat dari surat Taubah berada pada Khuzaimah yang tidak aku temukan pada sahabat mana pun. Yaitu ayat: Sungguh telah datang kepadamu seorang Rasul dari kaummu sendiri, berat terasa olehnya penderitaanmu, sangat menginginkan (keimanan dan keselamatan) bagimu, amat belas kasihan lagi penyayang terhadap orang-orang mukmin. Jika mereka berpaling (dari keimanan), maka katakanlah: \"Cukuplah Allah bagiku; tidak ada Tuhan selain Dia. Hanya kepada-Nya aku bertawakkal dan Dia adalah Tuhan yang memiliki 'Arsy yang agung.\" (9: 128-129). Dan mushaf yang telah aku kumpulkan itu berada pada Abu Bakr hingga dia wafat, kemudian berada pada Umar hingga dia wafat, setelah itu berada pada Hafshah putri Umar. Diriwiyatkan pula oleh ['Utsman bin 'Umar] dan [Al Laits] dari [Yunus] dari [Ibnu Syihab]; Al Laits berkata; Telah menceritakan kepadaku ['Abdur Rahman bin Khalid] dari [Ibnu Syihab]; dia berkata; ada pada Abu Huzaimah Al Anshari. Sedang [Musa] berkata; Dari [Ibrahim] Telah menceritakan kepada kami [Ibnu Syihab]; 'Ada pada Abu Khuzaimah.' Juga diriwayatkan oleh [Ya'qub bin Ibrahim] dari [Bapaknya]. [Abu Tsabit] berkata; Telah menceritakan kepada kami [Ibrahim] dia berkata; 'Ada pada Khuzaimah atau Abu Khuzaimah."},{"p":"Bukhari","n":6320,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ أَبُو ثَابِتٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ بْنِ السَّبَّاقِ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَبَعَثَ إِلَيَّ أَبُو بَكْرٍ لِمَقْتَلِ أَهْلِ الْيَمَامَةِ وَعِنْدَهُ عُمَرُ فَقَالَ أَبُو بَكْرٍ إِنَّ عُمَرَ أَتَانِي فَقَالَ إِنَّ الْقَتْلَ قَدْ اسْتَحَرَّ يَوْمَ الْيَمَامَةِ بِقُرَّاءِ الْقُرْآنِ وَإِنِّي أَخْشَى أَنْ يَسْتَحِرَّ الْقَتْلُ بِقُرَّاءِ الْقُرْآنِ فِي الْمَوَاطِنِ كُلِّهَا فَيَذْهَبَ قُرْآنٌ كَثِيرٌ وَإِنِّي أَرَى أَنْ تَأْمُرَ بِجَمْعِ الْقُرْآنِ قُلْتُ كَيْفَ أَفْعَلُ شَيْئًا لَمْ يَفْعَلْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عُمَرُ هُوَ وَاللَّهِ خَيْرٌ فَلَمْ يَزَلْ عُمَرُ يُرَاجِعُنِي فِي ذَلِكَ حَتَّى شَرَحَ اللَّهُ صَدْرِي لِلَّذِي شَرَحَ لَهُ صَدْرَ عُمَرَ وَرَأَيْتُ فِي ذَلِكَ الَّذِي رَأَى عُمَرُ قَالَ زَيْدٌ قَالَ أَبُو بَكْرٍ وَإِنَّكَ رَجُلٌ شَابٌّ عَاقِلٌ لَا نَتَّهِمُكَ قَدْ كُنْتَ تَكْتُبُ الْوَحْيَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَتَبَّعْ الْقُرْآنَ فَاجْمَعْهُ قَالَ زَيْدٌ فَوَاللَّهِ لَوْ كَلَّفَنِي نَقْلَ جَبَلٍ مِنْ الْجِبَالِ مَا كَانَ بِأَثْقَلَ عَلَيَّ مِمَّا كَلَّفَنِي مِنْ جَمْعِ الْقُرْآنِ قُلْتُ كَيْفَ تَفْعَلَانِ شَيْئًا لَمْ يَفْعَلْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو بَكْرٍ هُوَ وَاللَّهِ خَيْرٌ فَلَمْ يَزَلْ يَحُثُّ مُرَاجَعَتِي حَتَّى شَرَحَ اللَّهُ صَدْرِي لِلَّذِي شَرَحَ اللَّهُ لَهُ صَدْرَ أَبِي بَكْرٍ وَعُمَرَ وَرَأَيْتُ فِي ذَلِكَ الَّذِي رَأَيَا فَتَتَبَّعْتُ الْقُرْآنَ أَجْمَعُهُ مِنْ الْعُسُبِ وَالرِّقَاعِ وَاللِّخَافِ وَصُدُورِ الرِّجَالِ فَوَجَدْتُ فِي آخِرِ سُورَةِ التَّوْبَةِ{ لَقَدْ جَاءَكُمْ رَسُولٌ مِنْ أَنْفُسِكُمْ }إِلَى آخِرِهَا مَعَ خُزَيْمَةَ أَوْ أَبِي خُزَيْمَةَ فَأَلْحَقْتُهَا فِي سُورَتِهَا وَكَانَتْ الصُّحُفُ عِنْدَ أَبِي بَكْرٍ حَيَاتَهُ حَتَّى تَوَفَّاهُ اللَّهُ عَزَّ وَجَلَّ ثُمَّ عِنْدَ عُمَرَ حَيَاتَهُ حَتَّى تَوَفَّاهُ اللَّهُ ثُمَّ عِنْدَ حَفْصَةَ بِنْتِ عُمَرَقَالَ مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ اللِّخَافُ يَعْنِي الْخَزَفَ","trj":"Telah menceritakan kepada kami [Muhammad bin Ubaidullah] Abu Tsabit, telah menceritakan kepada kami [Ibrahim bin sa'd] dari [Ibnu Syihab] dari [Ubaid bin Sibaq] dari [Zaid bin tsabit] mengatakan, Abu bakar mengutus seseorang menemuiku karena banyaknya korban yang gugur pada perang Yamamah, ketika itu Abu bakar bersama Umar. Abu Bakar berkata; 'Umar mendatangiku dan mengatakan; 'Korban perang telah meluas pada perang yamamah hingga merenggut qurra` (penghafal) alquran, dan saya khawatir jangan-jangan dengan meninggalnya qurra` alquran di banyak tempat, mengakibatkan sekian banyak ayat quran akan menghilang, dan saya berpendapat jika engkau perintahkan untuk mengumpulkan alquran.' Maka Saya menjawab; 'bagaimana aku lakukan sesuatu yang belum pernah Rasulullah lakukan? ' Umar kontan mengemukakan pendapatnya; 'Demi Allah, ini adalah suatu kebaikan, ' Umar tiada henti-hentinya mendorongku untuk melakukan pekerjaan ini, hingga Allah melapangkan dadaku untuk melakukan pekerjaan yang dada Umar telah lebih dahulu dilapangkan terhadapnya, dan aku sependapat dengan pendapat Umar.' Zaid mengatakan, Abu Bakar berkata; 'Sungguh engkau adalah laki-laki yang masih muda, cerdas, dan kami sama sekali tidak menyangsikan kemampuanmu, sebab engkau sudah terbiasa menulis wahyu untuk Rasulullah. Maka susurilah alquran (yang masih terpencar-pencar) dan kumpulkanlah.' Maka Zaid menjawab; \"Demi Allah, sekiranya Abu bakar menugasiku untuk memindahkan sebuah gunung, itu tidak lebih berat bagiku daripada menugasiku untuk menghimpun alquran. Maka aku berkata; 'Bagaimana mungkin anda berdua melakukan sesuatu yang tidak pernah di lakukan Rasulullah Shallallahu'alaihiwasallam? ' Abu Bakar menjawab; 'demi Alllah, pekerjaan ini adalah kebaikan.' Tiada henti-hentinya Abu Bakar memotivasi pertimbanganku hingga Allah melapangkan dadaku untuk melakukan suatu hal yang Allah telah melapangkan dada Abu Bakar dan Umar untuk melakukannya. Dan aku sependapat dengan keduanya, maka kutelusuri alquran yang terpencar-pencar dan kuhimpun dari pelepah, kulit, tembikar, tulang dan dada para penghapal, dan kutemukan di akhir surat at taubah ayat yang berbunyi; 'Telah datang kepada kalian seorang rasul dari jenis kamu sendiri,,,, hingga akhir ayat (QS. Attaubah 128) bersama Khuzaimah atau Abu Khuzaemah, sehingga aku masukkan dalam suratnya. Kemudian shuhuf (manuskrip pencatatan asli alquran) ini berada di Abu Bakar ketika hidupnya sampai Allah mewafatkannya, kemudian keberadaan shuhuf ini pada Umar 'azza wajalla semasa hidupnya sampai Allah mewafatkannya, kemudian pada Hafshah binti Umar.' Muhammad bin Ubaidullah mengatakan; maksud al likhaf ialah tembikar (tanah liat yang dibakar)."},{"p":"Bukhari","n":6522,"ar":"حَدَّثَنَا مُوسَى عَنْ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ عُبَيْدِ بْنِ السَّبَّاقِ أَنَّ زَيْدَ بْنَ ثَابِتٍ وَقَالَ اللَّيْثُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ السَّبَّاقِ أَنَّ زَيْدَ بْنَ ثَابِتٍ حَدَّثَهُ قَالَأَرْسَلَ إِلَيَّ أَبُو بَكْرٍ فَتَتَبَّعْتُ الْقُرْآنَ حَتَّى وَجَدْتُ آخِرَ سُورَةِ التَّوْبَةِ مَعَ أَبِي خُزَيْمَةَ الْأَنْصَارِيِّ لَمْ أَجِدْهَا مَعَ أَحَدٍ غَيْرِهِ{ لَقَدْ جَاءَكُمْ رَسُولٌ مِنْ أَنْفُسِكُمْ }حَتَّى خَاتِمَةِ بَرَاءَةٌحَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ بِهَذَا وَقَالَ مَعَ أَبِي خُزَيْمَةَ الْأَنْصَارِيِّ","trj":"Telah menceritakan kepada kami [Musa] dari [Ibrahim] telah menceritakan kepada kami [Ibn Syihab] dari ['Ubaid bin Sibaq] bahwa [Zaid bin Tsabit], sedang [Al Laits] berkata, telah menceritakan kepadaku [Abdurrahman bin Khalid] dari [Ibn Syihab] dari [Ibn Sibaq Zaid bin Tsabit] menceritakannya dengan berkata, \"Abu Bakar mengutus seseorang kepadaku dan Abu Khuzaimah Al Anshari, sehingga aku telusuri alquran dan hingga aku temukan akhir surat At Taubah, yang aku tidak menemukannya dengan seorang pun selain bersamanya, yaitu ayat: '(Telah datang kepada kalian seorang rasul dari kalian sendiri) ' (QS. Attaubah 128), hingga penghabisan surat al Bara'ah (surat At Taubah).\" Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Yunus] dengan hadis ini, dan beliau berkata; telah menceritakan kepada kami Yahya bin Bukair telah menceritakan kepada kami Al Laits dari Yunus dengan hadis ini, dan ia menyebutkan, 'Bersama Abu Khuzaimah Al anshari.\""}],"9:129":[{"p":"Bukhari","n":4006,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي ابْنُ السَّبَّاقِ أَنَّ زَيْدَ بْنَ ثَابِتٍ الْأَنْصَارِيَّ رَضِيَ اللَّهُ عَنْهُوَكَانَ مِمَّنْ يَكْتُبُ الْوَحْيَ قَالَ أَرْسَلَ إِلَيَّ أَبُو بَكْرٍ مَقْتَلَ أَهْلِ الْيَمَامَةِ وَعِنْدَهُ عُمَرُ فَقَالَ أَبُو بَكْرٍ إِنَّ عُمَرَ أَتَانِي فَقَالَ إِنَّ الْقَتْلَ قَدْ اسْتَحَرَّ يَوْمَ الْيَمَامَةِ بِالنَّاسِ وَإِنِّي أَخْشَى أَنْ يَسْتَحِرَّ الْقَتْلُ بِالْقُرَّاءِ فِي الْمَوَاطِنِ فَيَذْهَبَ كَثِيرٌ مِنْ الْقُرْآنِ إِلَّا أَنْ تَجْمَعُوهُ وَإِنِّي لَأَرَى أَنْ تَجْمَعَ الْقُرْآنَ قَالَ أَبُو بَكْرٍ قُلْتُ لِعُمَرَ كَيْفَ أَفْعَلُ شَيْئًا لَمْ يَفْعَلْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عُمَرُ هُوَ وَاللَّهِ خَيْرٌ فَلَمْ يَزَلْ عُمَرُ يُرَاجِعُنِي فِيهِ حَتَّى شَرَحَ اللَّهُ لِذَلِكَ صَدْرِي وَرَأَيْتُ الَّذِي رَأَى عُمَرُ قَالَ زَيْدُ بْنُ ثَابِتٍ وَعُمَرُ عِنْدَهُ جَالِسٌ لَا يَتَكَلَّمُ فَقَالَ أَبُو بَكْرٍ إِنَّكَ رَجُلٌ شَابٌّ عَاقِلٌ وَلَا نَتَّهِمُكَ كُنْتَ تَكْتُبُ الْوَحْيَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَتَبَّعْ الْقُرْآنَ فَاجْمَعْهُ فَوَاللَّهِ لَوْ كَلَّفَنِي نَقْلَ جَبَلٍ مِنْ الْجِبَالِ مَا كَانَ أَثْقَلَ عَلَيَّ مِمَّا أَمَرَنِي بِهِ مِنْ جَمْعِ الْقُرْآنِ قُلْتُ كَيْفَ تَفْعَلَانِ شَيْئًا لَمْ يَفْعَلْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ هُوَ وَاللَّهِ خَيْرٌ فَلَمْ أَزَلْ أُرَاجِعُهُ حَتَّى شَرَحَ اللَّهُ صَدْرِي لِلَّذِي شَرَحَ اللَّهُ لَهُ صَدْرَ أَبِي بَكْرٍ وَعُمَرَ فَقُمْتُ فَتَتَبَّعْتُ الْقُرْآنَ أَجْمَعُهُ مِنْ الرِّقَاعِ وَالْأَكْتَافِ وَالْعُسُبِ وَصُدُورِ الرِّجَالِ حَتَّى وَجَدْتُ مِنْ سُورَةِ التَّوْبَةِ آيَتَيْنِ مَعَ خُزَيْمَةَ الْأَنْصَارِيِّ لَمْ أَجِدْهُمَا مَعَ أَحَدٍ غَيْرِهِ{ لَقَدْ جَاءَكُمْ رَسُولٌ مِنْ أَنْفُسِكُمْ عَزِيزٌ عَلَيْهِ مَا عَنِتُّمْ حَرِيصٌ عَلَيْكُمْ }إِلَى آخِرِهِمَا وَكَانَتْ الصُّحُفُ الَّتِي جُمِعَ فِيهَا الْقُرْآنُ عِنْدَ أَبِي بَكْرٍ حَتَّى تَوَفَّاهُ اللَّهُ ثُمَّ عِنْدَ عُمَرَ حَتَّى تَوَفَّاهُ اللَّهُ ثُمَّ عِنْدَ حَفْصَةَ بِنْتِ عُمَرَتَابَعَهُ عُثْمَانُ بْنُ عُمَرَ وَاللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ وَقَالَ اللَّيْثُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ وَقَالَ مَعَ أَبِي خُزَيْمَةَ الْأَنْصَارِيِّ وَقَالَ مُوسَى عَنْ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ شِهَابٍ مَعَ أَبِي خُزَيْمَةَ وَتَابَعَهُ يَعْقُوبُ بْنُ إِبْرَاهِيمَ عَنْ أَبِيهِ وَقَالَ أَبُو ثَابِتٍ حَدَّثَنَا إِبْرَاهِيمُ وَقَالَ مَعَ خُزَيْمَةَ أَوْ أَبِي خُزَيْمَةَ","trj":"Telah menceritakan kepada kami [Abu Al Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; Telah mengabarkan kepadaku [Ibnu As Sabbaq] bahwa [Zaid bin Tsabit Al Anshari radliallahu 'anhu] -salah seorang penulis wahyu- dia berkata; Abu Bakar As shiddiq datang kepadaku pada waktu perang Yamamah, ketika itu Umar disampingnya. Abu Bakr berkata bahwasanya Umar mendatangiku dan mengatakan; \"Sesungguhnya perang Yamamah telah berkecamuk (menimpa) para sahabat, dan aku khawatir akan menimpa para penghafal Qur'an di negeri-negeri lainnya sehingga banyak yang gugur dari mereka kecuali engkau memerintahkan pengumpulan (pendokumentasian) al Qur`an.\" Abu Bakar berkata kepada Umar; \"Bagaimana aku mengerjakan suatu proyek yang tidak pernah dikerjakan Rasulullah shallallahu 'alaihi wasallam?\" Umar menjawab; \"Demi Allah hal itu adalah sesuatu yang baik.\" Ia terus mengulangi hal itu sampai Allah melapangkan dadaku sebagaimana melapangkan dada Umar dan aku sependapat dengannya. Zaid berkata; Abu Bakar berkata; -pada waktu itu disampingnya ada Umar sedang duduk, dan dia tidak berkata apa-apa.- \"Sesungguhnya kamu adalah pemuda yang cerdas, kami tidak meragukanmu, dan kamu juga menulis wahyu untuk Rasulullah shallallahu 'alaihi wasallam, karena itu kumpulkanlah al Qur'an (dengan seksama).\" Zaid berkata; \"Demi Allah, seandainya mereka menyuruhku untuk memindahkan gunung dari gunung-gunung yang ada, maka hal itu tidak lebih berat bagiku dari pada (pengumpulan atau pendokumentasian al Qur'an). kenapa kalian mengerjakan sesuatu yang tidak pernah dikerjakan Rasulullah shallallahu 'alaihi wasallam?\" Abu Bakar menjawab; \"Demi Allah hal itu adalah baik.\" Aku pun terus mengulanginya, sehingga Allah melapangkan dadaku sebagaimana melapangkan dada keduanya (Abu Bakar dan Umar). Lalu aku kumpulkan al Qur'an (yang ditulis) pada kulit, pelepah kurma, dan batu putih lunak, juga dada (hafalan) para sahabat. Hingga aku mendapatkan dua ayat dari surat Taubah berada pada Khuzaimah yang tidak aku temukan pada sahabat mana pun. Yaitu ayat: Sungguh telah datang kepadamu seorang Rasul dari kaummu sendiri, berat terasa olehnya penderitaanmu, sangat menginginkan (keimanan dan keselamatan) bagimu, amat belas kasihan lagi penyayang terhadap orang-orang mukmin. Jika mereka berpaling (dari keimanan), maka katakanlah: \"Cukuplah Allah bagiku; tidak ada Tuhan selain Dia. Hanya kepada-Nya aku bertawakkal dan Dia adalah Tuhan yang memiliki 'Arsy yang agung.\" (9: 128-129). Dan mushaf yang telah aku kumpulkan itu berada pada Abu Bakr hingga dia wafat, kemudian berada pada Umar hingga dia wafat, setelah itu berada pada Hafshah putri Umar. Diriwiyatkan pula oleh ['Utsman bin 'Umar] dan [Al Laits] dari [Yunus] dari [Ibnu Syihab]; Al Laits berkata; Telah menceritakan kepadaku ['Abdur Rahman bin Khalid] dari [Ibnu Syihab]; dia berkata; ada pada Abu Huzaimah Al Anshari. Sedang [Musa] berkata; Dari [Ibrahim] Telah menceritakan kepada kami [Ibnu Syihab]; 'Ada pada Abu Khuzaimah.' Juga diriwayatkan oleh [Ya'qub bin Ibrahim] dari [Bapaknya]. [Abu Tsabit] berkata; Telah menceritakan kepada kami [Ibrahim] dia berkata; 'Ada pada Khuzaimah atau Abu Khuzaimah."}]},"mapping_surah":[{"p":"Abu Dawud","n":3867,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا ثَوْرُ بْنُ يَزِيدَ قَالَ حَدَّثَنِي خَالِدُ بْنُ مَعْدَانَ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَمْرٍو السُّلَمِيُّ وَحُجْرُ بْنُ حُجْرٍ قَالَاأَتَيْنَا الْعِرْبَاضَ بْنَ سَارِيَةَ وَهُوَ مِمَّنْ نَزَلَ فِيهِ{ وَلَا عَلَى الَّذِينَ إِذَا مَا أَتَوْكَ لِتَحْمِلَهُمْ قُلْتَ لَا أَجِدُ مَا أَحْمِلُكُمْ عَلَيْهِ }فَسَلَّمْنَا وَقُلْنَا أَتَيْنَاكَ زَائِرِينَ وَعَائِدِينَ وَمُقْتَبِسِينَ فَقَالَ الْعِرْبَاضُ صَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ ثُمَّ أَقْبَلَ عَلَيْنَا فَوَعَظَنَا مَوْعِظَةً بَلِيغَةً ذَرَفَتْ مِنْهَا الْعُيُونُ وَوَجِلَتْ مِنْهَا الْقُلُوبُ فَقَالَ قَائِلٌ يَا رَسُولَ اللَّهِ كَأَنَّ هَذِهِ مَوْعِظَةُ مُوَدِّعٍ فَمَاذَا تَعْهَدُ إِلَيْنَا فَقَالَ أُوصِيكُمْ بِتَقْوَى اللَّهِ وَالسَّمْعِ وَالطَّاعَةِ وَإِنْ عَبْدًا حَبَشِيًّا فَإِنَّهُ مَنْ يَعِشْ مِنْكُمْ بَعْدِي فَسَيَرَى اخْتِلَافًا كَثِيرًا فَعَلَيْكُمْ بِسُنَّتِي وَسُنَّةِ الْخُلَفَاءِ الْمَهْدِيِّينَ الرَّاشِدِينَ تَمَسَّكُوا بِهَا وَعَضُّوا عَلَيْهَا بِالنَّوَاجِذِ وَإِيَّاكُمْ وَمُحْدَثَاتِ الْأُمُورِ فَإِنَّ كُلَّ مُحْدَثَةٍ بِدْعَةٌ وَكُلَّ بِدْعَةٍ ضَلَالَةٌ","trj":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah menceritakan kepada kami [Tsaur bin Yazid] ia berkata; telah menceritakan kepadaku [Khalid bin Ma'dan] ia berkata; telah menceritakan kepadaku ['Abdurrahman bin Amru As Sulami] dan [Hujr bin Hujr] keduanya berkata, \"Kami mendatangi [Irbadh bin Sariyah], dan ia adalah termasuk seseorang yang turun kepadanya ayat: '(dan tiada (pula dosa) atas orang-orang yang apabila mereka datang kepadamu, suapaya kami memberi mereka kendaraan, lalu kamu berkata, \"Aku tidak memperoleh kendaraan orang yang membawamu) ' -Qs. At Taubah: 92- kami mengucapkan salam kepadanya dan berkata, \"Kami datang kepadamu untuk ziarah, duduk-duduk mendengar sesuatu yang berharga darimu.\" Irbadh berkata, \"Suatu ketika Rasulullah shallallahu 'alaihi wasallam shalat bersama kami, beliau lantas menghadap ke arah kami dan memberikan sebuah nasihat yang sangat menyentuh yang membuat mata menangis dan hati bergetar. Lalu seseorang berkata, \"Wahai Rasulullah, seakan-akan ini adalah nasihat untuk perpisahan! Lalu apa yang engkau washiatkan kepada kami?\" Beliau mengatakan: \"Aku wasiatkan kepada kalian untuk bertakwa kepada Allah, senantiasa taat dan mendengar meskipun yang memerintah adalah seorang budak habsyi yang hitam. Sesungguhnya orang-orang yang hidup setelahku akan melihat perselisihan yang banyak. Maka, hendaklah kalian berpegang dengan sunahku, sunah para khalifah yang lurus dan mendapat petunjuk, berpegang teguhlah dengannya dan gigitlah dengan gigi geraham. Jauhilah oleh kalian perkara-perkara baru (dalam urusan agama), sebab setiap perkara yang baru adalah bid'ah dan setaip bid'ah adalah sesat.\""},{"p":"Ahmad","n":20,"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ حَدَّثَنِي الزُّهْرِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يَقُولُلَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ دُعِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلصَّلَاةِ عَلَيْهِ فَقَامَ إِلَيْهِ فَلَمَّا وَقَفَ عَلَيْهِ يُرِيدُ الصَّلَاةَ تَحَوَّلْتُ حَتَّى قُمْتُ فِي صَدْرِهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَعَلَى عَدُوِّ اللَّهِ عَبْدِ اللَّهِ بْنِ أُبَيٍّ الْقَائِلِ يَوْمَ كَذَا كَذَا وَكَذَا يُعَدِّدُ أَيَّامَهُ قَالَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَبَسَّمُ حَتَّى إِذَا أَكْثَرْتُ عَلَيْهِ قَالَ أَخِّرْ عَنِّي يَا عُمَرُ إِنِّي خُيِّرْتُ فَاخْتَرْتُ وَقَدْ قِيلَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً فَلَنْ يَغْفِرَ اللَّهُ لَهُمْ }لَوْ أَعْلَمُ أَنِّي إِنْ زِدْتُ عَلَى السَّبْعِينَ غُفِرَ لَهُ لَزِدْتُ قَالَ ثُمَّ صَلَّى عَلَيْهِ وَمَشَى مَعَهُ فَقَامَ عَلَى قَبْرِهِ حَتَّى فُرِغَ مِنْهُ قَالَ فَعَجَبٌ لِي وَجَرَاءَتِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَوَاللَّهِ مَا كَانَ إِلَّا يَسِيرًا حَتَّى نَزَلَتْ هَاتَانِ الْآيَتَانِ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ إِنَّهُمْ كَفَرُوا بِاللَّهِ وَرَسُولِهِ وَمَاتُوا وَهُمْ فَاسِقُونَ }فَمَا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَهُ عَلَى مُنَافِقٍ وَلَا قَامَ عَلَى قَبْرِهِ حَتَّى قَبَضَهُ اللَّهُ عَزَّ وَجَلَّ","trj":"Telah menceritakan kepada kami [Ya'qub] Telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] Telah menceritakan kepadaku [Az Zuhri] dari [Ubaidullah Bin Abdullah Bin 'Utbah Bin Mas'ud] dari [Abdullah bin Abbas], dia berkata; aku mendengar [Umar Bin Khattab] berkata; ketika Abdullah Bin Ubai meninggal, Rasulullah shallallahu 'alaihi wasallam dipanggil untuk menshalatinya, maka beliau bergegas mendatanginya, tatkala beliau berdiri dihadapannya untuk menshalatinya aku menghalanginya sehingga aku berdiri dihadapan beliau dan berkata; \"Wahai Rasulullah, Abdullah Bin Ubai adalah dedengkot musuh Allah yang mengatakan pada hari ini dan ini, \" dia menyebutkan nama nama harinya, kemudian Umar melanjutkan; akan tetapi Rasulullah shallallahu 'alaihi wasallam hanya tersenyum sampai ketika aku mengulang-ngulang perkataanku beliau berkata: \"Minggirlah dariku wahai Umar, sesungguhnya aku di beri pilihan maka aku memilih, dan sudah di sebutkan: \"Kamu memohonkan ampun bagi mereka atau tidak kamu mohonkan ampun bagi mereka (adalah sama saja). kendatipun kamu memohonkan ampun bagi mereka tujuh puluh kali, namun Allah sekali-kali tidak akan memberi ampunan kepada mereka.'\" (QS Al Anfal ayat 80) seandainya aku tahu apabila aku menambah permohonanku sampai tujuh puluh kali dia akan mendapat ampunan niscaya aku akan tambah\" Umar berkata; kemudian beliau menshalatinya dan mengantarkan jenazahnya lalu berdiri di atas kuburannya sampai selesai dimakamkan, \" Umar berkata; \"aku heran dengan diriku atas lancangnya diriku kepada Rasulullah shallallahu 'alaihi wasallam, padahal Allah dan Rasul-Nya lebih tahu\" Umar berkata lagi; \"maka demi Allah tidak lama kemudian turunlah dua ayat ini (QS At Taubah ayat 80, 84).\"Dan janganlah kamu sekali-kali menyembahyangkan (jenazah) seorang yang mati di antara mereka, dan janganlah kamu berdiri (mendoakan) di kuburnya. Sesungguhnya mereka Telah kafir kepada Allah dan rasul-Nya dan mereka mati dalam keadaan fasik\". Kemudian Rasulullah shallallahu 'alaihi wasallam setelah itu tidak pernah lagi menshalati orang munafiq dan tidak juga berdiri di atas quburannya."},{"p":"Ahmad","n":2676,"ar":"حَدَّثَنَا وَكِيعٌ عَنْ أَبِي جَعْفَرٍ الرَّازِيِّ عَنِ الرَّبِيعِ بْنِ أَنَسٍ عَنْ أَبِي الْعَالِيَةِ أَوْ عَنْ غَيْرِهِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ وَكَانَ أَحَدَ الرَّهْطِ الَّذِينَ نَزَلَتْ فِيهِمْ هَذِهِ الْآيَةُ{ وَلَا عَلَى الَّذِينَ إِذَا مَا أَتَوْكَ لِتَحْمِلَهُمْ }إِلَى آخِرِ الْآيَةِ قَالَإِنِّي لَآخِذٌ بِغُصْنٍ مِنْ أَغْصَانِ الشَّجَرَةِ أُظِلُّ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمْ يُبَايِعُونَهُ فَقَالُوا نُبَايِعُكَ عَلَى الْمَوْتِ قَالَ لَا وَلَكِنْ لَا تَفِرُّوا","trj":"Telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Abu Ja'far Ar Razi] dari [Rabi' bin Anas] dari [Abu 'Aliyah] atau yang lain dari [Abdullah bin Mughaffal] -dia adalah salah seorang yang diturunkan ayat ini kepada mereka, yaitu; \"WALAA 'ALAL LADZIINA IDZA MAA ATAUKA LITAHMILAHUM (Dan tiada pula berdosa atas orang-orang yang apabila mereka datang kepadamu, supaya kamu memberi mereka kendaraan).\" (QS At Taubah: 92) sampai akhir ayat, Abdullah bin Mughaffal berkata; \"Sesungguhnya aku pernah mengambil dahan pohon untuk kujadikan tempat naungan Nabi shallallahu 'alaihi wasallam dan para sahabat ketika mereka berbai'at kepada beliau, lalu mereka berkata; \"Apakah kami berbai'at kepadamu untuk mati.\" beliau bersabda: \"Akan tetapi (berbai'atlah) untuk tidak lari.\""},{"p":"Ahmad","n":2783,"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ عَنْ أَبِي حُرَّةَ الرَّقَاشِيِّ عَنْ عَمِّهِ قَالَكُنْتُ آخِذًا بِزِمَامِ نَاقَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَوْسَطِ أَيَّامِ التَّشْرِيقِ أَذُودُ عَنْهُ النَّاسَ فَقَالَ يَا أَيُّهَا النَّاسُ أَتَدْرُونَ فِي أَيِّ شَهْرٍ أَنْتُمْ وَفِي أَيِّ يَوْمٍ أَنْتُمْ وَفِي أَيِّ بَلَدٍ أَنْتُمْ قَالُوا فِي يَوْمٍ حَرَامٍ وَشَهْرٍ حَرَامٍ وَبَلَدٍ حَرَامٍ قَالَ فَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ وَأَعْرَاضَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا إِلَى يَوْمِ تَلْقَوْنَهُ ثُمَّ قَالَ اسْمَعُوا مِنِّي تَعِيشُوا أَلَا لَا تَظْلِمُوا أَلَا لَا تَظْلِمُوا أَلَا لَا تَظْلِمُوا إِنَّهُ لَا يَحِلُّ مَالُ امْرِئٍ إِلَّا بِطِيبِ نَفْسٍ مِنْهُ أَلَا وَإِنَّ كُلَّ دَمٍ وَمَالٍ وَمَأْثَرَةٍ كَانَتْ فِي الْجَاهِلِيَّةِ تَحْتَ قَدَمِي هَذِهِ إِلَى يَوْمِ الْقِيَامَةِ وَإِنَّ أَوَّلَ دَمٍ يُوضَعُ دَمُ رَبِيعَةَ بْنِ الْحَارِثِ بْنِ عَبْدِ الْمُطَّلِبِ كَانَ مُسْتَرْضِعًا فِي بَنِي لَيْثٍ فَقَتَلَتْهُ هُذَيْلٌ أَلَا وَإِنَّ كُلَّ رِبًا كَانَ فِي الْجَاهِلِيَّةِ مَوْضُوعٌ وَإِنَّ اللَّهَ عَزَّ وَجَلَّ قَضَى أَنَّ أَوَّلَ رِبًا يُوضَعُ رِبَا الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ لَكُمْ رُءُوسُ أَمْوَالِكُمْ لَا تَظْلِمُونَ وَلَا تُظْلَمُونَ أَلَا وَإِنَّ الزَّمَانَ قَدْ اسْتَدَارَ كَهَيْئَتِهِ يَوْمَ خَلَقَ اللَّهُ السَّمَوَاتِ وَالْأَرْضَ ثُمَّ قَرَأَ{ إِنَّ عِدَّةَ الشُّهُورِ عِنْدَ اللَّهِ اثْنَا عَشَرَ شَهْرًا فِي كِتَابِ اللَّهِ يَوْمَ خَلَقَ السَّمَوَاتِ وَالْأَرْضَ مِنْهَا أَرْبَعَةٌ حُرُمٌ ذَلِكَ الدِّينُ الْقَيِّمُ فَلَا تَظْلِمُوا فِيهِنَّ أَنْفُسَكُمْ }أَلَا لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ أَلَا إِنَّ الشَّيْطَانَ قَدْ أَيِسَ أَنْ يَعْبُدَهُ الْمُصَلُّونَ وَلَكِنَّهُ فِي التَّحْرِيشِ بَيْنَكُمْ فَاتَّقُوا اللَّهَ عَزَّ وَجَلَّ فِي النِّسَاءِ فَإِنَّهُنَّ عِنْدَكُمْ عَوَانٌ لَا يَمْلِكْنَ لِأَنْفُسِهِنَّ شَيْئًا وَإِنَّ لَهُنَّ عَلَيْكُمْ وَلَكُمْ عَلَيْهِنَّ حَقًّا أَنْ لَا يُوطِئْنَ فُرُشَكُمْ أَحَدًا غَيْرَكُمْ وَلَا يَأْذَنَّ فِي بُيُوتِكُمْ لِأَحَدٍ تَكْرَهُونَهُ فَإِنْ خِفْتُمْ نُشُوزَهُنَّ فَعِظُوهُنَّ وَاهْجُرُوهُنَّ فِي الْمَضَاجِعِ وَاضْرِبُوهُنَّ ضَرْبًا غَيْرَ مُبَرِّحٍ قَالَ حُمَيْدٌ قُلْتُ لِلْحَسَنِ مَا الْمُبَرِّحُ قَالَ الْمُؤَثِّرُ وَلَهُنَّ رِزْقُهُنَّ وَكِسْوَتُهُنَّ بِالْمَعْرُوفِ وَإِنَّمَا أَخَذْتُمُوهُنَّ بِأَمَانَةِ اللَّهِ وَاسْتَحْلَلْتُمْ فُرُوجَهُنَّ بِكَلِمَةِ اللَّهِ عَزَّ وَجَلَّ وَمَنْ كَانَتْ عِنْدَهُ أَمَانَةٌ فَلْيُؤَدِّهَا إِلَى مَنْ ائْتَمَنَهُ عَلَيْهَا وَبَسَطَ يَدَيْهِ فَقَالَ أَلَا هَلْ بَلَّغْتُ أَلَا هَلْ بَلَّغْتُ أَلَا هَلْ بَلَّغْتُ ثُمَّ قَالَ لِيُبَلِّغْ الشَّاهِدُ الْغَائِبَ فَإِنَّهُ رُبَّ مُبَلَّغٍ أَسْعَدُ مِنْ سَامِعٍقَالَ حُمَيْدٌ قَالَ الْحَسَنُ حِينَ بَلَّغَ هَذِهِ الْكَلِمَةَ قَدْ وَاللَّهِ بَلَّغُوا أَقْوَامًا كَانُوا أَسْعَدَ بِهِ","trj":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad bin Salamah], telah mengabarkan kepada kami [Ali bin Zaid] dari [Abu Hurrah Ar Raqasyi] dari [Pamannya] dia berkata; \"Aku memegang tali kekang unta Rasulullah Shallalahu 'Alaihi Wasallam pada pertengahan hari Tasyrik (yaitu tanggal sebelas, dua belas dan tiga belas Dzulhijjah), aku mendesak orang-orang dari beliau, beliau bertanya: \"Wahai manusia, tahukah kalian di bulan apa kalian sekarang, di hari dan negeri mana kalian sekarang?.\" Para sahabat menjawab; \"Di hari haram, bulan haram dan negeri haram, \" beliau bersabda: \"Sungguh darah, harta dan kehormatan kalian adalah haram atas kalian, sebagaimana sucinya hari, bulan dan negeri kalian ini sampai datangnya hari kalian bertemu Allah.\" Beliau melanjutkan: \"Dengarkanlah aku, hiduplah kalian dan janganlah berbuat kezhaliman, ingatlah jangan berbuat dzalim, Sungguh tidak halal harta seseorang kecuali dengan kerelaan hati darinya, ketahuilah sesungguhnya setiap darah, harta dan kebanggaan yang ada pada masa jahiliyah, berada di bawah telapak kakiku ini sampai hari Kiamat, dan sesungguhnya darah yang pertama kali akan diletakkan adalah darah Rabi'ah bin Al Harits bin Abdul Muthallib, dia mencari seorang wanita yang bisa menyusui di Bani Laits, kemudian dibunuh oleh orang-orang Hudzail, ketahuilah sesungguhnya setiap riba di masa jahiliyah adalah jelek, dan sesungguhnya Allah 'azza wajalla telah memutuskan bahwa riba yang pertama kali akan diletakkan adalah riba Al Abbas bin Abdul Muthallib, bagi kalian adalah pokok harta kalian, janganlah kalian menzhalimi dan jangan pula terzhalimi, ketahuilah sesungguhnya zaman telah berputar sebagaimana perputaran pada hari Allah menciptakan langit dan bumi, kemudian beliau membaca ayat \"INNA 'IDDATASY SYUHUURI 'INDALLAAHI ITSNAA 'ASYARA SYAHRAN FII KITAABILLAAHI YAUMA KHOLAQAS SAMAAWAATI WAL ARDLA MINHAA ARBA'ATUN HURUM DZAALIKAD DIINUL QAYYIMU FALAA TADLIMUU FIIHINNA ANFUSAKUM (Sesungguhnya bilangan bulan pada sisi Allah adalah dua belas bulan, dalam ketetapan Allah di waktu dia menciptakan langit dan bumi, di antaranya empat bulan haram. Itulah (ketetapan) agama yang lurus, Maka janganlah kamu menganiaya diri kamu dalam bulan yang empat itu) \". QS At Taubah: 36, ketahuilah janganlah kalian kembali kepada kekafiran sepeninggalku, dengan saling membunuh satu sama lain, ketahuilah sesungguhnya setan telah putus asa untuk disembah oleh orang-orang yang shalat, akan tetapi dia tidak berputus asa untuk mengadu domba diantara kalian, maka takutlah kepada Allah 'azza wajalla dalam masalah wanita, karena sesungguhnya mereka di sisi kalian ibarat tawanan yang tidak dapat menguasai diri mereka sedikitpun, dan sungguh mereka mempunyai hak dari kalian dan kalianpun mempunyai hak atas mereka, janganlah mereka memasukkan kedalam rumah kalian selain kalian sendiri, janganlah mereka mengizinkan masuk ke dalam rumah kalian seseorang yang tidak kalian sukai, jika kalian khawatir akan nusyuz (durhaka) mereka, maka nasehatilah mereka lalu jauhilah mereka di tempat tidur dan pukulah mereka dengan pukulan yang tidak menyakitkan.\" [Humaid] berkata; Aku bertanya kepada [Al Hasan]; \"Apa yang dimaksud dengan \"Al Mubarrih?.\" dia menjawab; \"Yang membekas, \" dan hak bagi mereka adalah mendapatkan makan dan pakaian dengan cara ma'ruf, hanyasannya kalian mengambil mereka adalah dengan amanat dari Allah dan kalian menghalalkan farji (kehormatan) mereka adalah dengan kalimat Allah 'azza wajalla, dan barangsiapa mendapat amanat, maka sampaikanlah amanat itu kepada orang yang diamanati.\" Kemudian beliau membentangkan kedua tangannya seraya bersabda; \"ketahuilah bukankah aku telah menyampaikan, ketahuilah bukankah aku telah menyampaikan, ketahuilah bukankah aku telah menyampaikan?.\" Kemudian beliau melanjutkan sabdanya: \"Hendaknya orang yang hadir menyampaikan kepada yang tidak hadir, karena betapa banyak orang yang disampaikan berita kepadanya, dia lebih faham dari orang yang mendengar langsung.\" Humaid berkata; \" Al Hasan berkata ketika menyampaikan kalimat ini; \"Sungguh, demi Allah, mereka menyampaikan kepada suatu kaum dan mereka lebih bahagia dengannya.\""},{"p":"Bukhari","n":1190,"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ عَبْدَ اللَّهِ بْنَ أُبَيٍّ لَمَّا تُوُفِّيَ جَاءَ ابْنُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَعْطِنِي قَمِيصَكَ أُكَفِّنْهُ فِيهِ وَصَلِّ عَلَيْهِ وَاسْتَغْفِرْ لَهُ فَأَعْطَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَمِيصَهُ فَقَالَ آذِنِّي أُصَلِّي عَلَيْهِ فَآذَنَهُ فَلَمَّا أَرَادَ أَنْ يُصَلِّيَ عَلَيْهِ جَذَبَهُ عُمَرُ رَضِيَ اللَّهُ عَنْهُ فَقَالَ أَلَيْسَ اللَّهُ نَهَاكَ أَنْ تُصَلِّيَ عَلَى الْمُنَافِقِينَ فَقَالَ أَنَا بَيْنَ خِيَرَتَيْنِ قَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً فَلَنْ يَغْفِرَ اللَّهُ لَهُمْ }فَصَلَّى عَلَيْهِ فَنَزَلَتْ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }","trj":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] berkata, telah menceritakan kepada saya [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] bahwa ketika 'Abdullah bin Ubay wafat, anaknya datang menemui Nabi shallallahu 'alaihi wasallam lalu berkata: \"Wahai Rasulullah shallallahu 'alaihi wasallam: \"Berikanlah kepadaku baju anda untuk aku gunakan mengafani (ayahku) dan shalatlah untuknya serta mohonkanlah ampunan baginya\". Maka Nabi shallallahu 'alaihi wasallam memberikan bajunya kepadanya lalu berkata: \"izinkanlah aku untuk menshalatkannya\". Ketika Beliau hendak menshalatkannya tiba-tiba 'Umar bin Al Khaththab radliallahu 'anhu datang menarik Beliau seraya berkata: \"Bukankah Allah telah melarang anda untuk menshalatkan orang munafiq?\" Maka Beliau bersabda: \"Aku berada pada dua pilihan dari firman Allah Ta'ala (QS. At-Taubah ayat 80, yang artinya): \"Kamu mohonkan ampun buat mereka atau kamu tidak mohonkan ampun buat mereka (sama saja bagi mereka). Sekalipun kamu memohonkan ampun buat mereka sebanyak tujuh puluh kali, Allah sekali-kali tidak akan mengampuni mereka\". Maka Beliau shallallahu 'alaihi wasallam menshalatkannya. Lalu turunlah ayat: (QS. At-Taubah ayat 84 yang artinya): \"Janganlah kamu shalatkan seorangpun yang mati dari mereka selamanya dan janganlah kamu berdiri di atas kuburannya\"."},{"p":"Bukhari","n":1272,"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنِي أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ عَنْ أَبِيهِ أَنَّهُ أَخْبَرَهُ أَنَّهُلَمَّا حَضَرَتْ أَبَا طَالِبٍ الْوَفَاةُ جَاءَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدَ عِنْدَهُ أَبَا جَهْلِ بْنَ هِشَامٍ وَعَبْدَ اللَّهِ بْنَ أَبِي أُمَيَّةَ بْنِ الْمُغِيرَةِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَبِي طَالِبٍ يَا عَمِّ قُلْ لَا إِلَهَ إِلَّا اللَّهُ كَلِمَةً أَشْهَدُ لَكَ بِهَا عِنْدَ اللَّهِ فَقَالَ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ يَا أَبَا طَالِبٍ أَتَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ فَلَمْ يَزَلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْرِضُهَا عَلَيْهِ وَيَعُودَانِ بِتِلْكَ الْمَقَالَةِ حَتَّى قَالَ أَبُو طَالِبٍ آخِرَ مَا كَلَّمَهُمْ هُوَ عَلَى مِلَّةِ عَبْدِ الْمُطَّلِبِ وَأَبَى أَنْ يَقُولَ لَا إِلَهَ إِلَّا اللَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا وَاللَّهِ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْكَ فَأَنْزَلَ اللَّهُ تَعَالَى فِيهِ{ مَا كَانَ لِلنَّبِيِّ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Ya'qub bin Ibrahim] berkata, telah menceritakan [apakku] kepadaku dari [Shalih] dari [Ibnu Syihab] berkata, telah mengabarkan kepada saya telah mengabarkan kepada saya [Sa'id bin Al Musayyab] dari [bapaknya] bahwasanya dia mengabarkan kepadanya: \"Ketika menjelang wafatnya Abu Tholib, Rasulullah Shallallahu'alaihiwasallam mendatanginya dan ternyata sudah ada Abu Jahal bin Hisyam dan 'Abdullah bin Abu Umayyah bin Al Mughirah. Maka Rasulullah Shallallahu'alaihiwasallam berkata, kepada Abu Tholib: \"Wahai pamanku katakanlah laa ilaaha illallah, suatu kalimat yang dengannya aku akan menjadi saksi atasmu di sisi Allah\". Maka berkata, Abu Jahal dan 'Abdullah bin Abu Umayyah: \"Wahai Abu Thalib, apakah kamu akan meninggalkan agama 'Abdul Muthalib?\". Rasulullah Shallallahu'alaihiwasallam terus menawarkan kalimat syahadat kepada Abu Tholib dan bersamaan itu pula kedua orang itu mengulang pertanyaannya yang berujung Abu Tholib pada akhir ucapannya tetap mengikuti agama 'Abdul Muthalib dan enggan untuk mengucapkan laa ilaaha illallah. Maka berkatalah Rasulullah Shallallahu'alaihiwasallam: \"Adapun aku akan tetap memintakan ampun buatmu selama aku tidak dilarang\". Maka turunlah firman Allah subhanahu wata'ala tentang peristiwa ini: (\"Tidak patut bagi Nabi …\") dalam QS AT-Taubah ayat 113)."},{"p":"Bukhari","n":1277,"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنِي اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُمْ أَنَّهُ قَالَلَمَّا مَاتَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ دُعِيَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَلَمَّا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَثَبْتُ إِلَيْهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَتُصَلِّي عَلَى ابْنِ أُبَيٍّ وَقَدْ قَالَ يَوْمَ كَذَا وَكَذَا كَذَا وَكَذَا أُعَدِّدُ عَلَيْهِ قَوْلَهُ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَخِّرْ عَنِّي يَا عُمَرُ فَلَمَّا أَكْثَرْتُ عَلَيْهِ قَالَ إِنِّي خُيِّرْتُ فَاخْتَرْتُ لَوْ أَعْلَمُ أَنِّي إِنْ زِدْتُ عَلَى السَّبْعِينَ يُغْفَرُ لَهُ لَزِدْتُ عَلَيْهَا قَالَ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ انْصَرَفَ فَلَمْ يَمْكُثْ إِلَّا يَسِيرًا حَتَّى نَزَلَتْ الْآيَتَانِ مِنْ بَرَاءَةٌ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا إِلَى قَوْلِهِ وَهُمْ فَاسِقُونَ }قَالَ فَعَجِبْتُ بَعْدُ مِنْ جُرْأَتِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ وَاللَّهُ وَرَسُولُهُ أَعْلَمُ","trj":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada saya [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah] dari [Ibnu 'Abbas] dari ['Umar bin Al Khaththab radliallahu 'anhu] bahwasanya dia berkata,: \"Ketika 'Abdullah bin Ubay bin Salul meninggal dunia, Rasulullah Shallallahu'alaihiwasallam diminta untuk menyolatkannya. Ketika Beliau sudah berdiri hendak shalat aku hampiri Beliau lalu aku berkata: \"Wahai Rasulullah, apakah anda akan menyolatkan anak Ubay padahal dia suatu hari pernah mengatakan begini begini, begini dan begini, (aku mengulang-ulang ucapan bin Ubay yang dahulu pernah dilontarkan kepada Nabi) \". Ternyata Rasulullah Shallallahu'alaihiwasallam malah tersenyum seraya berkata,: \"Cukupkanlah ucapanmu dariku wahai 'Umar. Ketika aku terus berbicara kepada Beliau, Beliau berkata,: \"Sungguh aku diberi pilihan dan aku memilih seandainya aku mengetahui bila aku menambah lebih dari tujuh puluh kali permohonan ampun baginya dia akan diampuni, pasti aku akan tambah (permohonan ampun baginya) \". 'Umar berkata,: \"Maka kemudian Rasulullah Shallallahu'alaihiwasallam menyolatkannya hingga selesai, tak lama setelah Beliau terdiam, turunlah firman Allah subhanahu wata'ala QS At-Taubah ayat 84 yang artinya (\"Dan janganlah kamu menyolatkan siapa yang mati dari mereka selamanya\" hingga ayat \"mereka mati dalam keadaan fasiq\")."},{"p":"Bukhari","n":1326,"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو النُّعْمَانِ الْحَكَمُ هُوَ ابْنُ عَبْدِ اللَّهِ الْبَصْرِيُّ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَتْ آيَةُ الصَّدَقَةِ كُنَّا نُحَامِلُ فَجَاءَ رَجُلٌ فَتَصَدَّقَ بِشَيْءٍ كَثِيرٍ فَقَالُوا مُرَائِي وَجَاءَ رَجُلٌ فَتَصَدَّقَ بِصَاعٍ فَقَالُوا إِنَّ اللَّهَ لَغَنِيٌّ عَنْ صَاعِ هَذَا فَنَزَلَتْ{ الَّذِينَ يَلْمِزُونَ الْمُطَّوِّعِينَ مِنْ الْمُؤْمِنِينَ فِي الصَّدَقَاتِ وَالَّذِينَ لَا يَجِدُونَ إِلَّا جُهْدَهُمْ }الْآيَةَ","trj":"Telah menceritakan kepada kami ['Ubaidullah bin Sa'id] telah menceritakan kepada kami [Abu An-Nu'man Al Hakam] dia adalah putra dari 'Abdullah Al Bashriy telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] dari [Abu Wa'il] dari [Abu Mas'ud radliallahu 'anhu] berkata; \"Ketika ayat shadaqah turun, kami berlomba-lomba, lalu datanglah seseorang dengan membawa shadaqah yang banyak dan orang-orang berkata, ia orang yang pamer. Kemudian datanglah seseorang lalu ia bershadaqah dengan satu sha'. Orang-orang berkata; \"Sesungguhnya Allah lebih kaya daripada satu sha' ini\". Maka turunlah aya QS At-Taubah ayat: \"Alladziina yalmizuunal muththawwi'iina minal mu'miniina fishshadaqati walladziina laa yajiduuna illa juhdahum\". (\"Orang-orang (munafik itu) yang mencela orang-orang beriman yang memberi sedekah dengan sukarela dan (mencela) orang-orang yang tidak memperoleh (untuk disedekahkan) selain sekedar kesanggupannya\")."},{"p":"Bukhari","n":3438,"ar":"حَدَّثَنَا مَحْمُودٌ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِيهِأَنَّ أَبَا طَالِبٍ لَمَّا حَضَرَتْهُ الْوَفَاةُ دَخَلَ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ أَبُو جَهْلٍ فَقَالَ أَيْ عَمِّ قُلْ لَا إِلَهَ إِلَّا اللَّهُ كَلِمَةً أُحَاجُّ لَكَ بِهَا عِنْدَ اللَّهِ فَقَالَ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ يَا أَبَا طَالِبٍ تَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ فَلَمْ يَزَالَا يُكَلِّمَانِهِ حَتَّى قَالَ آخِرَ شَيْءٍ كَلَّمَهُمْ بِهِ عَلَى مِلَّةِ عَبْدِ الْمُطَّلِبِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْهُ فَنَزَلَتْ{ مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ وَلَوْ كَانُوا أُولِي قُرْبَى مِنْ بَعْدِ مَا تَبَيَّنَ لَهُمْ أَنَّهُمْ أَصْحَابُ الْجَحِيمِ }وَنَزَلَتْ{ إِنَّكَ لَا تَهْدِي مَنْ أَحْبَبْتَ }","trj":"Telah menceritakan kepada kami [Mahmud] telah menceritakan kepada kami ['Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnu Al Musayyab] dari [bapaknya] bahwa ketika menjelang wafatnya Abu Thalib, Nabi shallallahu 'alaihi wasallam masuk menemuinya sementara di sampingnya ada Abu Jahal. Beliau berkata: \"Wahai pamanku, katakanlah laa ilaaha illallah. Suatu kalimat yang akan aku pergunakan untuk menyelamatkan engkau di sisi Allah\". Maka berkata Abu Jahal dan Abdullah bin Abu Umayyah; \"Wahai Abu Thalib, apakah kamu akan meninggalkan agama 'Abdul Muthallib?\". Keduanya terus saja mengajak Abu Thalib berbicara hingga kalimat terakhir yang diucapkannya kepada mereka adalah dia tetap mengikuti agama 'Abdul Muthallib. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Aku akan tetap memintakan ampun untukmu selama aku tidak dilarang\". Maka turunlah firman Allah Ta'ala dalam QS AT-Taubah ayat 113 yang artinya: (\"Tidak patut bagi Nabi dan orang-orang beriman untuk memohonkan ampun bagi orang-orangmusyrik sekalipun mereka itu adalah kerabat-kerabat mereka setelah jelas bagi mereka (kaum mu'minin) bahwa mereka adalah penghuni neraka jahim..\"). Dan turun pula firman Allah Ta'ala dalam QS al Qashsash ayat 56 yang artinya: (\"Sesungguhnya engkau (wahai Muhammad) tidak akan dapat memberi petunjuk kepada orang yang engkau cintai...\") "},{"p":"Bukhari","n":3995,"ar":"حَدَّثَنِي بِشْرُ بْنُ خَالِدٍ أَبُو مُحَمَّدٍ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مَسْعُودٍ قَالَلَمَّا أُمِرْنَا بِالصَّدَقَةِ كُنَّا نَتَحَامَلُ فَجَاءَ أَبُو عَقِيلٍ بِنِصْفِ صَاعٍ وَجَاءَ إِنْسَانٌ بِأَكْثَرَ مِنْهُ فَقَالَ الْمُنَافِقُونَ إِنَّ اللَّهَ لَغَنِيٌّ عَنْ صَدَقَةِ هَذَا وَمَا فَعَلَ هَذَا الْآخَرُ إِلَّا رِئَاءً فَنَزَلَتْ{ الَّذِينَ يَلْمِزُونَ الْمُطَّوِّعِينَ مِنْ الْمُؤْمِنِينَ فِي الصَّدَقَاتِ وَالَّذِينَ لَا يَجِدُونَ إِلَّا جُهْدَهُمْ }الْآيَةَ","trj":"Telah menceritakan kepadaku [Bisyr bin Khalid Abu Muhammad]; Telah mengabarkan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman] dari [Abu Wail] dari [Abu Mas'ud] dia berkata; Setelah Rasulullah Shalallahu 'Alaihi Wa Sallam memerintahkan kami untuk bersedekah, maka kami saling membawakan sedekah tersebut agar kami mendapatkan pahala darinya, lalu Abu Uqail bersedekah dengan setengah sha', kemudian datang seseorang dengan membawa lebih banyak dari itu, lalu orang-orang munafik berkata; \" Allah Azza Wa Jalla benar-benar tidak membutuhkan sedekah orang ini, orang ini tidak melakukannya kecuali dengan riya'. Lalu turun ayat: 'Orang-orang munafik itu yaitu orang-orang yang mencela orang-orang mukmin yang memberi sedekah dengan sukarela dan (mencela) orang-orang yang tidak memperoleh (untuk disedekahkan) selain sekadar kesanggupannya.\" (Qs. At Taubah: 79)."},{"p":"Bukhari","n":3997,"ar":"حَدَّثَنِي عُبَيْدُ بْنُ إِسْمَاعِيلَ عَنْ أَبِي أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ جَاءَ ابْنُهُ عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ أَنْ يُعْطِيَهُ قَمِيصَهُ يُكَفِّنُ فِيهِ أَبَاهُ فَأَعْطَاهُ ثُمَّ سَأَلَهُ أَنْ يُصَلِّيَ عَلَيْهِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَقَامَ عُمَرُ فَأَخَذَ بِثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ تُصَلِّي عَلَيْهِ وَقَدْ نَهَاكَ رَبُّكَ أَنْ تُصَلِّيَ عَلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا خَيَّرَنِي اللَّهُ فَقَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً }وَسَأَزِيدُهُ عَلَى السَّبْعِينَ قَالَ إِنَّهُ مُنَافِقٌ قَالَ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }","trj":"Telah menceritakan kepadaku ['Ubaid bin Isma'il] dari [Abu Usamah] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dia berkata; \"Ketika Abdullah bin Ubay meninggal dunia. anak laki-lakinya -yaitu Abdulah bin Abdullah- datang kepada Rasulullah shallallahu 'alaihi wasallam seraya memohon kepada beIiau agar sudi memberikan baju beliau kepada Abdullah untuk kain kafan ayahnya, Abdullah bin Ubay bin Salul. Lalu Rasulullah shallallahu 'alaihi wasallam memberikan bajunya kepada Abdullah. setelah itu, Abdullah juga memohon Rasulullah agar beliau berkenan menshalati jenazah ayahnya. Kemudian Rasulullah pun bersiap-siap untuk menshalati jenazah Abdullah bin Ubay, hingga akhirnya Umar berdiri dan menarik baju Rasulullah seraya berkata, \"Ya Rasulullah, apakah engkau akan menshalati jenazah Abdullah bin Ubay sedangkan Allah telah melarang untuk menshalatinya?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Sesungguhnya Allah Subhanahu wa Ta'ala telah memberikan pilihan kepadaku.\" Lalu beliau membacakan ayat yang berbunyi; \"Kamu memohonkun ampun bagi orang-orang munafik atau tidak kamu mohonkan ampun bagi mereka, maka hal itu adalah sama saja. sekalipun kamu memohonkan ampun bagi mereka tujuh puluh kali (Qs. At-Taubah 9: 80). Oleh karena itu, aku akan menambah istighfar lebih dari tujuh puluh kali untuknya.\" Umar bin Khaththab berkata, \"Ya Rasulullah, sesungguhnya Ia adalah orang munafik?.\" Tetapi, rupanya Rasulullah shallallahu 'alaihi wasallam tetap saja menshalatinya, hingga Allah menurunkan ayat Al Qur'an: \"Janganlah kamu sekali-kali menshalati jenazah seorang di antara orang-orang munafik dan janganlah kamu berdiri di atas kuburnya.\" (Qs. At-Taubah 9: 84)."},{"p":"Bukhari","n":3998,"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ و قَالَ غَيْرُهُ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُأَنَّهُ قَالَ لَمَّا مَاتَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ دُعِيَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَلَمَّا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَثَبْتُ إِلَيْهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَتُصَلِّي عَلَى ابْنِ أُبَيٍّ وَقَدْ قَالَ يَوْمَ كَذَا كَذَا وَكَذَا قَالَ أُعَدِّدُ عَلَيْهِ قَوْلَهُ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَخِّرْ عَنِّي يَا عُمَرُ فَلَمَّا أَكْثَرْتُ عَلَيْهِ قَالَ إِنِّي خُيِّرْتُ فَاخْتَرْتُ لَوْ أَعْلَمُ أَنِّي إِنْ زِدْتُ عَلَى السَّبْعِينَ يُغْفَرْ لَهُ لَزِدْتُ عَلَيْهَا قَالَ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ انْصَرَفَ فَلَمْ يَمْكُثْ إِلَّا يَسِيرًا حَتَّى نَزَلَتْ الْآيَتَانِ مِنْ بَرَاءَةَ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا إِلَى قَوْلِهِ وَهُمْ فَاسِقُونَ }قَالَ فَعَجِبْتُ بَعْدُ مِنْ جُرْأَتِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهُ وَرَسُولُهُ أَعْلَمُ","trj":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari ['Uqail]. -dan yang lainnya berkata- Telah menceritakan kepadaku Al Laits Telah menceritakan kepadaku Uqail dari [Ibnu Syihab] dia berkata; Telah mengabarkan kepadaku ['Ubaidullah bin 'Abdullah] dari [Ibnu 'Abbas] dari ['Umar bin Al Khaththab radliallahu 'anhu] Tatkala Abdullah bin Ubai bin Salul meninggal dunia, Rasulullah shallallahu 'alaihi wasallam diundang untuk menshalatinya. Setelah Rasulullah shallallahu 'alaihi wasallam berdiri untuk melaksanakan Shalat, aku meloncat ke arah beliau, lalu aku berkata, \"Wahai Rasulullah shallallahu 'alaihi wasallam, kenapa engkau menshalati Ibnu Ubay, padahal ia telah mengatakan di hari ini-itu begini dan begitu?! Aku hitung-hitung kejelekannya, Rasulullah shallallahu 'alaihi wasallam tersenyum seraya bersabda: \"Tundalah -perkataanmu- dariku wahai Umar!\" setelah aku mengulang menyebut-nyebut kejelekannya, beliau bersabda: \" Aku telah diberikan pilihan, aku memilih. Andaikata aku tahu kalau aku menambahnya lebih dari tujuh puluh ia akan diampuni, niscaya aku menambahnya!.\"Lalu Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat atasnya, kemudian beliau pergi dan tidak berada di tempat itu kecuali hanya sejenak, hingga turun dua ayat dari surah Bara'ah, \"(Dan janganlah kamu sekali-kali menshalatkan (jenazah) seorang yang mati di antara mereka, dan janganlah kamu berdiri (mendo'akan) di kuburnya. mereka telah kafir kepada Allah dan RasulNya dan mereka mati dalam keadaan fasik.\" (Qs. At-Taubah: 84). Setelah itu aku heran atas keberanianku terhadap Rasulullah shallallahu 'alaihi wasallam ketika itu. Dan hanya Allah dan Rasul-Nya yang lebih mengatahui.\""},{"p":"Bukhari","n":3999,"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ قَالَ لَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ جَاءَ ابْنُهُ عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَاهُ قَمِيصَهُ وَأَمَرَهُ أَنْ يُكَفِّنَهُ فِيهِ ثُمَّ قَامَ يُصَلِّي عَلَيْهِ فَأَخَذَ عُمَرُ بْنُ الْخَطَّابِ بِثَوْبِهِ فَقَالَ تُصَلِّي عَلَيْهِ وَهُوَ مُنَافِقٌ وَقَدْ نَهَاكَ اللَّهُ أَنْ تَسْتَغْفِرَ لَهُمْ قَالَ إِنَّمَا خَيَّرَنِي اللَّهُ أَوْ أَخْبَرَنِي اللَّهُ فَقَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً فَلَنْ يَغْفِرَ اللَّهُ لَهُمْ }فَقَالَ سَأَزِيدُهُ عَلَى سَبْعِينَ قَالَ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَلَّيْنَا مَعَهُ ثُمَّ أَنْزَلَ اللَّهُ عَلَيْهِ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ إِنَّهُمْ كَفَرُوا بِاللَّهِ وَرَسُولِهِ وَمَاتُوا وَهُمْ فَاسِقُونَ }","trj":"Telah menceritakan kepadaku [Ibrahim bin Al Mundzir] Telah menceritakan kepada kami [Anas bin 'Iyadl] dari ['Ubaidillah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dia berkata; \"Ketika Abdullah bin Ubay meninggal dunia. anak laki-lakinya -yaitu Abdulah bin Abdullah- datang kepada Rasulullah shallallahu 'alaihi wasallam dan beliau berikan bajunya dan beliau perintahkannya untuk mengafani ayahnya dengan bajunya tersebut. Lalu Rasulullah shallallahu 'alaihi wasallam menshalati jenazah ayah Abdullah bin Abdullah bin Ubbay. Hingga akhirnya Umar menarik baju Rasulullah seraya berkata; \"Ya Rasulullah, apakah engkau akan menshalati jenazah Abdullah bin Ubay sedangkan dia itu orang munafik? Padahal Allah telah melarang engkau memintakan ampun untuknya?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Sesungguhnya Allah Subhanahu wa Ta'ala telah memberikan pilihan kepadaku atau mengabariku.\" Lalu beliau membacakan ayat yang berbunyi; \"Kamu memohonkun ampun bagi orang-orang munafik atau tidak kamu mohonkan ampun bagi mereka, maka hal itu adalah sama saja. sekalipun kamu memohonkan ampun bagi mereka tujuh puluh kali sekali-kali Allah tidak akan mengampuni mereka (Qs. At-Taubah 9: 80). Rasulullah shallallahu 'alaihi wasallam bersabda: Aku akan menambah istighfar lebih dari tujuh puluh kali untuknya.\" Maka Rasulullah shallallahu 'alaihi wasallam tetap saja menshalatinya dan kami pun shalat bersamanya hingga Allah menurunkan ayat Al Qur'an: \"Janganlah kamu sekali-kali menshalati jenazah seorang di antara orang-orang munafik dan janganlah kamu berdiri di atas kuburnya, sesungguhnya mereka telah kafir kepada Allah dan Rasul-Nya dan mereka mati dalam keadaan munafiq.\" (Qs. At-Taubah 9: 84)."},{"p":"Bukhari","n":4000,"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ كَعْبِ بْنِ مَالِكٍ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍحِينَ تَخَلَّفَ عَنْ تَبُوكَ وَاللَّهِ مَا أَنْعَمَ اللَّهُ عَلَيَّ مِنْ نِعْمَةٍ بَعْدَ إِذْ هَدَانِي أَعْظَمَ مِنْ صِدْقِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا أَكُونَ كَذَبْتُهُ فَأَهْلِكَ كَمَا هَلَكَ الَّذِينَ كَذَبُوا حِينَ أُنْزِلَ الْوَحْيُ{ سَيَحْلِفُونَ بِاللَّهِ لَكُمْ إِذَا انْقَلَبْتُمْ إِلَيْهِمْ إِلَى قَوْلِهِ الْفَاسِقِينَ }","trj":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Abdur Rahman bin 'Abdullah] sesungguhnya [Abdullah bin Ka'ab bin Malik] berkata; Aku mendengar [Ka'ab bin Malik] ketika dia tertinggal dari perang Tabuk; 'Demi Allah, tidak ada nikmat yang telah di berikan Allah kepada saya, setelah Allah menunjukan kepada saya Islam, yang saya anggap lebih besar daripada kejujuranku kepada Rasulullah shallallahu 'alaihi wasallam, Seandainya saya berdusta kepada beliau, maka saya akan celaka sebagaimana orang-orang yang telah berdusta ketika diturunkan wahyu yang berbunyi: 'Kelak mereka akan bersumpah kepadamu dengan nama Allah apabila kamu kembali kepada mereka supaya kamu berpaling dari mereka. Maka berpalinglah kamu dari mereka, karena sesungguhnya mereka itu najis dan tempat mereka adalah jahannam sebagai balasan dari apa yang telah mereka kerjakan. Mereka akan bersumpah kepadamu supaya kamu ridla kepada mereka, maka sesungguhnya Allah tidak ridla kepada orang-orang yang fasik itu.' (Qs. At-taubah (9): 95-96)."},{"p":"Bukhari","n":4002,"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِيهِ قَالَلَمَّا حَضَرَتْ أَبَا طَالِبٍ الْوَفَاةُ دَخَلَ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْ عَمِّ قُلْ لَا إِلَهَ إِلَّا اللَّهُ أُحَاجُّ لَكَ بِهَا عِنْدَ اللَّهِ فَقَالَ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ يَا أَبَا طَالِبٍ أَتَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْكَ فَنَزَلَتْ{ مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ وَلَوْ كَانُوا أُولِي قُرْبَى مِنْ بَعْدِ مَا تَبَيَّنَ لَهُمْ أَنَّهُمْ أَصْحَابُ الْجَحِيمِ }","trj":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] Telah menceritakan kepada kami ['Abdur Razzaq] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Bapaknya] dia berkata; \"Ketika Abu Thalib mendekati ajalnya, Rasulullah shallallahu 'alaihi wasallam masuk menemuinya dan di dekatnya ada Abu Jahal dan Abdullah bin Abu Umayyah. Lalu beliau bersabda: \"Wahai pamanku, ucapkanlah 'Laa Ilaaha Illallah (tidak ada sesembahan yang berhak di sembah selain Allah) ' yang dengannya aku akan berhujah untuk membelamu di sisi Allah -Azza wa Jalla-.\" Maka Abu Jahal dan Abdullah bin Umayyah berkata kepadanya; \"Wahai Abu Thalib, Apakah kamu benci dengan agama Abdul Muthalib?\" Maka Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Sungguh akan aku akan mintakan ampunan untukmu selama aku tidak dilarang.\" Lalu turunlah ayat, \"Tidak sepatutnya bagi Nabi dan orang-orang yang beriman memintakan ampun (kepada Allah) bagi orang-orang musyrik walaupun orang-orang musyrik itu adalah kaum kerabat (nya), sesudah jelas bagi mereka, bahwasanya orang-orang musyrik itu adalah penghuni neraka jahanam.\" (Qs. At Taubah; 113)."},{"p":"Bukhari","n":4005,"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ وَكَانَ قَائِدَ كَعْبِ بْنِ مَالِكٍ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍيُحَدِّثُ حِينَ تَخَلَّفَ عَنْ قِصَّةِ تَبُوكَ فَوَاللَّهِ مَا أَعْلَمُ أَحَدًا أَبْلَاهُ اللَّهُ فِي صِدْقِ الْحَدِيثِ أَحْسَنَ مِمَّا أَبْلَانِي مَا تَعَمَّدْتُ مُنْذُ ذَكَرْتُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى يَوْمِي هَذَا كَذِبًا وَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ لَقَدْ تَابَ اللَّهُ عَلَى النَّبِيِّ وَالْمُهَاجِرِينَ وَالْأَنْصَارِ إِلَى قَوْلِهِ وَكُونُوا مَعَ الصَّادِقِينَ }","trj":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Abdur Rahman bin 'Abdullah bin Ka'ab bin Malik] dari ['Abdullah bin Ka'ab bin Malik] -dia adalah penuntun Ka'ab bin Malik- dia berkata; Aku mendengar [Ka'ab bin Malik] bercerita mengenai ketertinggalannya dari perang Tabuk. Demi Allah, setahu saya tidak ada seorang muslim yang telah di uji Allah dalam kejujuran ucapannya, yang ia lebih baik dari pada apa yang telah diujikan Allah kepada saya sejak saya ceritakan hal ini kepada Rasulullah shallallahu 'alaihi wasallam, saya tidak pernah bermaksud untuk berdusta kepada Rasulullah hingga sekarang ini. Allah Azza wa Jalla berfirman kepada Rasulullah-Nya shallallahu 'alaihi wasallam: \"Sesungguhnya Allah telah menerima taubat Nabi, orang-orang Muhajirin, dan orang-orang Anshar… hingga ayat: 'dan hendaklah kamu bersama orang-orang yang jujur.' (Qs. At-Taubah (9): 117-119)."},{"p":"Bukhari","n":4006,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي ابْنُ السَّبَّاقِ أَنَّ زَيْدَ بْنَ ثَابِتٍ الْأَنْصَارِيَّ رَضِيَ اللَّهُ عَنْهُوَكَانَ مِمَّنْ يَكْتُبُ الْوَحْيَ قَالَ أَرْسَلَ إِلَيَّ أَبُو بَكْرٍ مَقْتَلَ أَهْلِ الْيَمَامَةِ وَعِنْدَهُ عُمَرُ فَقَالَ أَبُو بَكْرٍ إِنَّ عُمَرَ أَتَانِي فَقَالَ إِنَّ الْقَتْلَ قَدْ اسْتَحَرَّ يَوْمَ الْيَمَامَةِ بِالنَّاسِ وَإِنِّي أَخْشَى أَنْ يَسْتَحِرَّ الْقَتْلُ بِالْقُرَّاءِ فِي الْمَوَاطِنِ فَيَذْهَبَ كَثِيرٌ مِنْ الْقُرْآنِ إِلَّا أَنْ تَجْمَعُوهُ وَإِنِّي لَأَرَى أَنْ تَجْمَعَ الْقُرْآنَ قَالَ أَبُو بَكْرٍ قُلْتُ لِعُمَرَ كَيْفَ أَفْعَلُ شَيْئًا لَمْ يَفْعَلْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عُمَرُ هُوَ وَاللَّهِ خَيْرٌ فَلَمْ يَزَلْ عُمَرُ يُرَاجِعُنِي فِيهِ حَتَّى شَرَحَ اللَّهُ لِذَلِكَ صَدْرِي وَرَأَيْتُ الَّذِي رَأَى عُمَرُ قَالَ زَيْدُ بْنُ ثَابِتٍ وَعُمَرُ عِنْدَهُ جَالِسٌ لَا يَتَكَلَّمُ فَقَالَ أَبُو بَكْرٍ إِنَّكَ رَجُلٌ شَابٌّ عَاقِلٌ وَلَا نَتَّهِمُكَ كُنْتَ تَكْتُبُ الْوَحْيَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَتَبَّعْ الْقُرْآنَ فَاجْمَعْهُ فَوَاللَّهِ لَوْ كَلَّفَنِي نَقْلَ جَبَلٍ مِنْ الْجِبَالِ مَا كَانَ أَثْقَلَ عَلَيَّ مِمَّا أَمَرَنِي بِهِ مِنْ جَمْعِ الْقُرْآنِ قُلْتُ كَيْفَ تَفْعَلَانِ شَيْئًا لَمْ يَفْعَلْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ هُوَ وَاللَّهِ خَيْرٌ فَلَمْ أَزَلْ أُرَاجِعُهُ حَتَّى شَرَحَ اللَّهُ صَدْرِي لِلَّذِي شَرَحَ اللَّهُ لَهُ صَدْرَ أَبِي بَكْرٍ وَعُمَرَ فَقُمْتُ فَتَتَبَّعْتُ الْقُرْآنَ أَجْمَعُهُ مِنْ الرِّقَاعِ وَالْأَكْتَافِ وَالْعُسُبِ وَصُدُورِ الرِّجَالِ حَتَّى وَجَدْتُ مِنْ سُورَةِ التَّوْبَةِ آيَتَيْنِ مَعَ خُزَيْمَةَ الْأَنْصَارِيِّ لَمْ أَجِدْهُمَا مَعَ أَحَدٍ غَيْرِهِ{ لَقَدْ جَاءَكُمْ رَسُولٌ مِنْ أَنْفُسِكُمْ عَزِيزٌ عَلَيْهِ مَا عَنِتُّمْ حَرِيصٌ عَلَيْكُمْ }إِلَى آخِرِهِمَا وَكَانَتْ الصُّحُفُ الَّتِي جُمِعَ فِيهَا الْقُرْآنُ عِنْدَ أَبِي بَكْرٍ حَتَّى تَوَفَّاهُ اللَّهُ ثُمَّ عِنْدَ عُمَرَ حَتَّى تَوَفَّاهُ اللَّهُ ثُمَّ عِنْدَ حَفْصَةَ بِنْتِ عُمَرَتَابَعَهُ عُثْمَانُ بْنُ عُمَرَ وَاللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ وَقَالَ اللَّيْثُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ وَقَالَ مَعَ أَبِي خُزَيْمَةَ الْأَنْصَارِيِّ وَقَالَ مُوسَى عَنْ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ شِهَابٍ مَعَ أَبِي خُزَيْمَةَ وَتَابَعَهُ يَعْقُوبُ بْنُ إِبْرَاهِيمَ عَنْ أَبِيهِ وَقَالَ أَبُو ثَابِتٍ حَدَّثَنَا إِبْرَاهِيمُ وَقَالَ مَعَ خُزَيْمَةَ أَوْ أَبِي خُزَيْمَةَ","trj":"Telah menceritakan kepada kami [Abu Al Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; Telah mengabarkan kepadaku [Ibnu As Sabbaq] bahwa [Zaid bin Tsabit Al Anshari radliallahu 'anhu] -salah seorang penulis wahyu- dia berkata; Abu Bakar As shiddiq datang kepadaku pada waktu perang Yamamah, ketika itu Umar disampingnya. Abu Bakr berkata bahwasanya Umar mendatangiku dan mengatakan; \"Sesungguhnya perang Yamamah telah berkecamuk (menimpa) para sahabat, dan aku khawatir akan menimpa para penghafal Qur'an di negeri-negeri lainnya sehingga banyak yang gugur dari mereka kecuali engkau memerintahkan pengumpulan (pendokumentasian) al Qur`an.\" Abu Bakar berkata kepada Umar; \"Bagaimana aku mengerjakan suatu proyek yang tidak pernah dikerjakan Rasulullah shallallahu 'alaihi wasallam?\" Umar menjawab; \"Demi Allah hal itu adalah sesuatu yang baik.\" Ia terus mengulangi hal itu sampai Allah melapangkan dadaku sebagaimana melapangkan dada Umar dan aku sependapat dengannya. Zaid berkata; Abu Bakar berkata; -pada waktu itu disampingnya ada Umar sedang duduk, dan dia tidak berkata apa-apa.- \"Sesungguhnya kamu adalah pemuda yang cerdas, kami tidak meragukanmu, dan kamu juga menulis wahyu untuk Rasulullah shallallahu 'alaihi wasallam, karena itu kumpulkanlah al Qur'an (dengan seksama).\" Zaid berkata; \"Demi Allah, seandainya mereka menyuruhku untuk memindahkan gunung dari gunung-gunung yang ada, maka hal itu tidak lebih berat bagiku dari pada (pengumpulan atau pendokumentasian al Qur'an). kenapa kalian mengerjakan sesuatu yang tidak pernah dikerjakan Rasulullah shallallahu 'alaihi wasallam?\" Abu Bakar menjawab; \"Demi Allah hal itu adalah baik.\" Aku pun terus mengulanginya, sehingga Allah melapangkan dadaku sebagaimana melapangkan dada keduanya (Abu Bakar dan Umar). Lalu aku kumpulkan al Qur'an (yang ditulis) pada kulit, pelepah kurma, dan batu putih lunak, juga dada (hafalan) para sahabat. Hingga aku mendapatkan dua ayat dari surat Taubah berada pada Khuzaimah yang tidak aku temukan pada sahabat mana pun. Yaitu ayat: Sungguh telah datang kepadamu seorang Rasul dari kaummu sendiri, berat terasa olehnya penderitaanmu, sangat menginginkan (keimanan dan keselamatan) bagimu, amat belas kasihan lagi penyayang terhadap orang-orang mukmin. Jika mereka berpaling (dari keimanan), maka katakanlah: \"Cukuplah Allah bagiku; tidak ada Tuhan selain Dia. Hanya kepada-Nya aku bertawakkal dan Dia adalah Tuhan yang memiliki 'Arsy yang agung.\" (9: 128-129). Dan mushaf yang telah aku kumpulkan itu berada pada Abu Bakr hingga dia wafat, kemudian berada pada Umar hingga dia wafat, setelah itu berada pada Hafshah putri Umar. Diriwiyatkan pula oleh ['Utsman bin 'Umar] dan [Al Laits] dari [Yunus] dari [Ibnu Syihab]; Al Laits berkata; Telah menceritakan kepadaku ['Abdur Rahman bin Khalid] dari [Ibnu Syihab]; dia berkata; ada pada Abu Huzaimah Al Anshari. Sedang [Musa] berkata; Dari [Ibrahim] Telah menceritakan kepada kami [Ibnu Syihab]; 'Ada pada Abu Khuzaimah.' Juga diriwayatkan oleh [Ya'qub bin Ibrahim] dari [Bapaknya]. [Abu Tsabit] berkata; Telah menceritakan kepada kami [Ibrahim] dia berkata; 'Ada pada Khuzaimah atau Abu Khuzaimah."},{"p":"Bukhari","n":4198,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ قُلْتُ لِابْنِ عَبَّاسٍسُورَةُ التَّوْبَةِ قَالَ التَّوْبَةُ هِيَ الْفَاضِحَةُ مَا زَالَتْ تَنْزِلُ وَمِنْهُمْ وَمِنْهُمْ حَتَّى ظَنُّوا أَنَّهَا لَنْ تُبْقِيَ أَحَدًا مِنْهُمْ إِلَّا ذُكِرَ فِيهَا قَالَ قُلْتُ سُورَةُ الْأَنْفَالِ قَالَ نَزَلَتْ فِي بَدْرٍ قَالَ قُلْتُ سُورَةُ الْحَشْرِ قَالَ نَزَلَتْ فِي بَنِي النَّضِيرِ","trj":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim] Telah menceritakan kepada kami [Sa'id bin Sulaiman] Telah menceritakan kepada kami [Husyaim] Telah mengabarkan kepada kami [Abu Bisyr] dari [Sa'id bin Jubair] ia berkata; Aku pernah bertanya kepada [Ibnu Abbas] mengenai surat At Taubah, maka ia pun menjelaskan, \"Surat At Taubah adalah diistilahkan Al Fadlihah (yang membongkar kejahatan kaum munafik). Ia senantiasa turun dengan ungkapan, 'WA MINHUM.., WA MINHUM.. (Dan di antara mereka.. dan di antara mereka) ' hingga mereka pun menyangka bahwa tidak ada seorang pun yang tersisa dari mereka kecuali disebutkan dalam surat tersebut.\" Kemudian aku bertanya, \"Bagaimana dengan surat Al Anfal? ' Ia menjelaskan, \"Surat itu turun pada saat terjadinya perang Badar.\" Aku bertanya lagi, \"Kalau surat Al Hasyr?\" Ia pun menjelaskan, \"Surat itu turun berkenaan dengan Bani Nadlir.\""},{"p":"Bukhari","n":4298,"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ عَنْ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ عُبَيْدِ بْنِ السَّبَّاقِ أَنَّ زَيْدَ بْنَ ثَابِتٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَرْسَلَ إِلَيَّ أَبُو بَكْرٍ مَقْتَلَ أَهْلِ الْيَمَامَةِ فَإِذَا عُمَرُ بْنُ الْخَطَّابِ عِنْدَهُ قَالَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ إِنَّ عُمَرَ أَتَانِي فَقَالَ إِنَّ الْقَتْلَ قَدْ اسْتَحَرَّ يَوْمَ الْيَمَامَةِ بِقُرَّاءِ الْقُرْآنِ وَإِنِّي أَخْشَى أَنْ يَسْتَحِرَّ الْقَتْلُ بِالْقُرَّاءِ بِالْمَوَاطِنِ فَيَذْهَبَ كَثِيرٌ مِنْ الْقُرْآنِ وَإِنِّي أَرَى أَنْ تَأْمُرَ بِجَمْعِ الْقُرْآنِ قُلْتُ لِعُمَرَ كَيْفَ تَفْعَلُ شَيْئًا لَمْ يَفْعَلْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عُمَرُ هَذَا وَاللَّهِ خَيْرٌ فَلَمْ يَزَلْ عُمَرُ يُرَاجِعُنِي حَتَّى شَرَحَ اللَّهُ صَدْرِي لِذَلِكَ وَرَأَيْتُ فِي ذَلِكَ الَّذِي رَأَى عُمَرُ قَالَ زَيْدٌ قَالَ أَبُو بَكْرٍ إِنَّكَ رَجُلٌ شَابٌّ عَاقِلٌ لَا نَتَّهِمُكَ وَقَدْ كُنْتَ تَكْتُبُ الْوَحْيَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَتَبَّعْ الْقُرْآنَ فَاجْمَعْهُ فَوَاللَّهِ لَوْ كَلَّفُونِي نَقْلَ جَبَلٍ مِنْ الْجِبَالِ مَا كَانَ أَثْقَلَ عَلَيَّ مِمَّا أَمَرَنِي بِهِ مِنْ جَمْعِ الْقُرْآنِ قُلْتُ كَيْفَ تَفْعَلُونَ شَيْئًا لَمْ يَفْعَلْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هُوَ وَاللَّهِ خَيْرٌ فَلَمْ يَزَلْ أَبُو بَكْرٍ يُرَاجِعُنِي حَتَّى شَرَحَ اللَّهُ صَدْرِي لِلَّذِي شَرَحَ لَهُ صَدْرَ أَبِي بَكْرٍ وَعُمَرَ رَضِيَ اللَّهُ عَنْهُمَا فَتَتَبَّعْتُ الْقُرْآنَ أَجْمَعُهُ مِنْ الْعُسُبِ وَاللِّخَافِ وَصُدُورِ الرِّجَالِ حَتَّى وَجَدْتُ آخِرَ سُورَةِ التَّوْبَةِ مَعَ أَبِي خُزَيْمَةَ الْأَنْصَارِيِّ لَمْ أَجِدْهَا مَعَ أَحَدٍ غَيْرِهِ{ لَقَدْ جَاءَكُمْ رَسُولٌ مِنْ أَنْفُسِكُمْ عَزِيزٌ عَلَيْهِ مَا عَنِتُّمْ }حَتَّى خَاتِمَةِ بَرَاءَةَ فَكَانَتْ الصُّحُفُ عِنْدَ أَبِي بَكْرٍ حَتَّى تَوَفَّاهُ اللَّهُ ثُمَّ عِنْدَ عُمَرَ حَيَاتَهُ ثُمَّ عِنْدَ حَفْصَةَ بِنْتِ عُمَرَ رَضِيَ اللَّهُ عَنْهُ","trj":"Telah menceritakan kepada kami [Musa bin Isa'il] dari [Ibrahim bin Sa'd] Telah menceritakan kepada kami [Ibnu Syihab] dari [Ubaid bin As Sabbaq] bahwa [Zaid bin Tsabit] radliallahu 'anhu, ia berkata; Abu Bakar mengirim para korban perang Yamamah kepadaku, dan ternyata Umar bin Al Khaththab ada di sisinya. Abu Bakar radliallahu 'anhu berkata, \"Sesungguhnya Umar mendatangiku dan berkata, 'Mayoritas korban perang Yamamah adalah para penghafal Al Qur`an. Dengan gugurnya mayoritas penghafal Al Qur`an, maka aku khawatir sebagian besar Al Qur`an juga akan hilang. Maka aku berpendapat, sebaiknya Anda segera memerintahkan guna melakukan dokumentasi alquran.' Maka aku pun bertanya kepada Umar, 'Bagaimana kamu akan melakukan sesuatu yang belum pernah dilakukan oleh Rasulullah shallallahu 'alaihi wasallam? ' Umar menjawab, 'Perkara ini, demi Allah adalah ide yang baik.' Umar selalu membujukku hingga Allah memberikan kelapangan dadaku, dan akhirnya aku sependapat dengan Umar.\" Zaid berkata; Abu Bakar berkata, \"Sesungguhnya kamu adalah seorang pemuda yang cerdas, kami sama sekali tidak curiga sedikit pun padamu. Dan sungguh, kamulah yang telah menulis wahyu untuk Rasulullah shallallahu 'alaihi wasallam. Karena itu, telusurilah Al Qur`an dan kumpulkanlah.\" Zaid berkata, \"Demi Allah, sekiranya mereka memerintahkanku untuk memindahkan gunung, niscaya hal itu tidaklah lebih berat daripada apa yang mereka perintahkan padaku, yakni dokumentasi alquran.\" Zaid bertanya, \"Bagaimana kalian melakukan sesuatu yang belum pernah dilakukan oleh Rasulullah shallallahu 'alaihi wasallam?\" Ia menjawab, \"Demi Allah, itu adalah kebaikan.\" Abu Bakar terus membujukku, hinnga Allah pun memberikan kelapangan dadaku, sebagaimana Abu Bakar dan Umar radliallahu 'anhuma. Maka aku pun mulai menelusuri Al Qur`an, mengumpulkannya dari tulang-tulang, kulit-kulit dan dari hafalan para Qari`. Dan akhirnya aku pun mendapatkan bagian akhir dari surat At Taubah bersama Abu Khuzaimah Al Anshari, yang aku tidak mendapatkannya pada seorang pun selainnya. Yakni ayat: 'Sungguh, telah datang pada kalian seorang Rasul dari kaum kalian sendiri, yang sangat berat olehnya kesulitan yang menimpa kalian..'\" hingga akhir surat Al Bara`ah. Lembaran-lembaran Al Qur`an itu pun tetap tersimpan pada Abu Bakar hingga Allah mewafatkannya. Kemudian beralih kepada Umar semasa hidupnya, lalu berpindah lagi ke tangan Hafshah binti Umar radliallahu 'anhu."},{"p":"Bukhari","n":4300,"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ أَنَّ ابْنَ السَّبَّاقِ قَالَ إِنَّ زَيْدَ بْنَ ثَابِتٍ قَالَأَرْسَلَ إِلَيَّ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ قَالَ إِنَّكَ كُنْتَ تَكْتُبُ الْوَحْيَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاتَّبِعْ الْقُرْآنَ فَتَتَبَّعْتُ حَتَّى وَجَدْتُ آخِرَ سُورَةِ التَّوْبَةِ آيَتَيْنِ مَعَ أَبِي خُزَيْمَةَ الْأَنْصَارِيِّ لَمْ أَجِدْهُمَا مَعَ أَحَدٍ غَيْرِهِ{ لَقَدْ جَاءَكُمْ رَسُولٌ مِنْ أَنْفُسِكُمْ عَزِيزٌ عَلَيْهِ مَا عَنِتُّمْ }إِلَى آخِرِهِ","trj":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari [Yunus] Telah menceritakan kepada kami [Ibnu Syihab] bahwa [Ibnu As Sabbaq] berkata; [Zaid bin Tsabit] berkata; Abu Bakar pernah mengutus seseorang padaku seraya mengatakan, \"Sesungguhnya, kamulah yang pernah menulis wahyu untuk Rasulullah shallallahu 'alaihi wasallam. Karena itu, telusurilah Al Qur`an.\" Maka aku pun segera menelusurinya, hingga aku mendapati akhir dari surat At Taubah, yakni dua ayat bersama Abu Khuzaimah Al Anshari, yang aku tidak mendapatkannya pada seorang pun selainnya. Yakni, \"LAQAD JAA`AKUM RASUULUM MIN ANFUSIKUM 'AZIIZUN 'ALAIHI MAA 'ANITTUM..\" Hingga akhir ayat."},{"p":"Bukhari","n":5863,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبٍ وَكَانَ قَائِدَ كَعْبٍ مِنْ بَنِيهِ حِينَ عَمِيَ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍفِي حَدِيثِهِ{ وَعَلَى الثَّلَاثَةِ الَّذِينَ خُلِّفُوا }فَقَالَ فِي آخِرِ حَدِيثِهِ إِنَّ مِنْ تَوْبَتِي أَنِّي أَنْخَلِعُ مِنْ مَالِي صَدَقَةً إِلَى اللَّهِ وَرَسُولِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْسِكْ عَلَيْكَ بَعْضَ مَالِكَ فَهُوَ خَيْرٌ لَكَ","trj":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku [Abdurrahman bin Abdullah bin ka'b bin Malik] dari [Abdullah bin Ka'b], ia adalah penuntun Ka'b diantara anak-anaknya ketika ia telah buta, menuturkan; aku mendengar [Ka'b bin Malik] tentang ceritanya mengenai firman Allah: 'dan atas tiga orang yang tertinggal' (QS. Attaubah; 118) -yang dalam akhir ceritanya ia mengatakan - diantara tanda ketulusan taubatku, aku melepas hartaku untuk kujadikan sebagai sedekah kepada Allah dan Rasul-NYA. Tetapi Nabi shallallahu 'alaihi wasallam bersabda: \"tahan sebagian hartamu, itu lebih baik bagimu.\""},{"p":"Bukhari","n":6087,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ قَالَبَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْسِمُ جَاءَ عَبْدُ اللَّهِ بْنُ ��ِي الْخُوَيْصِرَةِ التَّمِيمِيُّ فَقَالَ اعْدِلْ يَا رَسُولَ اللَّهِ فَقَالَ وَيْلَكَ وَمَنْ يَعْدِلُ إِذَا لَمْ أَعْدِلْ قَالَ عُمَرُ بْنُ الْخَطَّابِ دَعْنِي أَضْرِبْ عُنُقَهُ قَالَ دَعْهُ فَإِنَّ لَهُ أَصْحَابًا يَحْقِرُ أَحَدُكُمْ صَلَاتَهُ مَعَ صَلَاتِهِ وَصِيَامَهُ مَعَ صِيَامِهِ يَمْرُقُونَ مِنْ الدِّينِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ يُنْظَرُ فِي قُذَذِهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ ثُمَّ يُنْظَرُ فِي نَصْلِهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ ثُمَّ يُنْظَرُ فِي رِصَافِهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ ثُمَّ يُنْظَرُ فِي نَضِيِّهِ فَلَا يُوجَدُ فِيهِ شَيْءٌ قَدْ سَبَقَ الْفَرْثَ وَالدَّمَ آيَتُهُمْ رَجُلٌ إِحْدَى يَدَيْهِ أَوْ قَالَ ثَدْيَيْهِ مِثْلُ ثَدْيِ الْمَرْأَةِ أَوْ قَالَ مِثْلُ الْبَضْعَةِ تَدَرْدَرُ يَخْرُجُونَ عَلَى حِينِ فُرْقَةٍ مِنْ النَّاسِ قَالَ أَبُو سَعِيدٍ أَشْهَدُ سَمِعْتُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَشْهَدُ أَنَّ عَلِيًّا قَتَلَهُمْ وَأَنَا مَعَهُ جِيءَ بِالرَّجُلِ عَلَى النَّعْتِ الَّذِي نَعَتَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَنَزَلَتْ فِيهِ{ وَمِنْهُمْ مَنْ يَلْمِزُكَ فِي الصَّدَقَاتِ }","trj":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dai [Abu Sa'id] mengatakan; Ketika Nabi shallallahu 'alaihi wasallam sedang membagi (harta rampasan), tiba-tiba Adbdullah bin Dzil huwaishirah At Tamimi datang seraya menegur Nabi; 'Hendaklah engkau berbuat adil! ' Spontan Nabi menjawab: \"siapa lagi yang berbuat adil jika aku tak berbuat adil?\" Umar kemudian berujar; 'Biarkan aku yang memenggal lehernya! ' Nabi bersabda; \"Biarkan saja dia, sebab dia mempunyai beberapa kawan yang salah seorang diantara kalian meremehkan shalatnya dibanding dengan shalatnya, dan meremehkan puasanya dibanding puasanya, mereka keluar dari agama sebagaimana anak panah keluar dari busur, ia melihat bulu anak panahnya namun tak ada apa-apa, kemudian memperhatikan mata anak panahnya namun tidak ditemukan apa-apa, kemudian melihat kain panahnya namun tidak didapatkan apa-apa, dan telah didahulu oleh kotoran dan darah. Tanda-tanda mereka adalah salah satu diantara kedua tangannya -atau- diantara kedua putingnya seperti puting kaum perempuan atau ia seperti daging yang bergerak-gerak, mereka muncul ketika manusia mengalami perpecahan.\" Sedang Abu Sa'id mengatakan; aku bersaksi bahwa aku mendengar dari Nabi shallallahu 'alaihi wasallam shallallahu 'alaihi wasallam, dan aku bersaksi bahwa 'Ali membunuh mereka dan aku bersamanya ketika didatangkan seseorang yang ciri-cirinya seperti yang disifatkan Nabi shallallahu 'alaihi wasallam, lantas diturunlah ayat; 'Diantara mereka ada yang mengolok-olokmu karena sedekah yang kamu infakkan' (QS. Attaubah 58)."},{"p":"Bukhari","n":6320,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ أَبُو ثَابِتٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ بْنِ السَّبَّاقِ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَبَعَثَ إِلَيَّ أَبُو بَكْرٍ لِمَقْتَلِ أَهْلِ الْيَمَامَةِ وَعِنْدَهُ عُمَرُ فَقَالَ أَبُو بَكْرٍ إِنَّ عُمَرَ أَتَانِي فَقَالَ إِنَّ الْقَتْلَ قَدْ اسْتَحَرَّ يَوْمَ الْيَمَامَةِ بِقُرَّاءِ الْقُرْآنِ وَإِنِّي أَخْشَى أَنْ يَسْتَحِرَّ الْقَتْلُ بِقُرَّاءِ الْقُرْآنِ فِي الْمَوَاطِنِ كُلِّهَا فَيَذْهَبَ قُرْآنٌ كَثِيرٌ وَإِنِّي أَرَى أَنْ تَأْمُرَ بِجَمْعِ الْقُرْآنِ قُلْتُ كَيْفَ أَفْعَلُ شَيْئًا لَمْ يَفْعَلْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عُمَرُ هُوَ وَاللَّهِ خَيْرٌ فَلَمْ يَزَلْ عُمَرُ يُرَاجِعُنِي فِي ذَلِكَ حَتَّى شَرَحَ اللَّهُ صَدْرِي لِلَّذِي شَرَحَ لَهُ صَدْرَ عُمَرَ وَرَأَيْتُ فِي ذَلِكَ الَّذِي رَأَى عُمَرُ قَالَ زَيْدٌ قَالَ أَبُو بَكْرٍ وَإِنَّكَ رَجُلٌ شَابٌّ عَاقِلٌ لَا نَتَّهِمُكَ قَدْ كُنْتَ تَكْتُبُ الْوَحْيَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَتَبَّعْ الْقُرْآنَ فَاجْمَعْهُ قَالَ زَيْدٌ فَوَاللَّهِ لَوْ كَلَّفَنِي نَقْلَ جَبَلٍ مِنْ الْجِبَالِ مَا كَانَ بِأَثْقَلَ عَلَيَّ مِمَّا كَلَّفَنِي مِنْ جَمْعِ الْقُرْآنِ قُلْتُ كَيْفَ تَفْعَلَانِ شَيْئًا لَمْ يَفْعَلْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو بَكْرٍ هُوَ وَاللَّهِ خَيْرٌ فَلَمْ يَزَلْ يَحُثُّ مُرَاجَعَتِي حَتَّى شَرَحَ اللَّهُ صَدْرِي لِلَّذِي شَرَحَ اللَّهُ لَهُ صَدْرَ أَبِي بَكْرٍ وَعُمَرَ وَرَأَيْتُ فِي ذَلِكَ الَّذِي رَأَيَا فَتَتَبَّعْتُ الْقُرْآنَ أَجْمَعُهُ مِنْ الْعُسُبِ وَالرِّقَاعِ وَاللِّخَافِ وَصُدُورِ الرِّجَالِ فَوَجَدْتُ فِي آخِرِ سُورَةِ التَّوْبَةِ{ لَقَدْ جَاءَكُمْ رَسُولٌ مِنْ أَنْفُسِكُمْ }إِلَى آخِرِهَا مَعَ خُزَيْمَةَ أَوْ أَبِي خُزَيْمَةَ فَأَلْحَقْتُهَا فِي سُورَتِهَا وَكَانَتْ الصُّحُفُ عِنْدَ أَبِي بَكْرٍ حَيَاتَهُ حَتَّى تَوَفَّاهُ اللَّهُ عَزَّ وَجَلَّ ثُمَّ عِنْدَ عُمَرَ حَيَاتَهُ حَتَّى تَوَفَّاهُ اللَّهُ ثُمَّ عِنْدَ حَفْصَةَ بِنْتِ عُمَرَقَالَ مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ اللِّخَافُ يَعْنِي الْخَزَفَ","trj":"Telah menceritakan kepada kami [Muhammad bin Ubaidullah] Abu Tsabit, telah menceritakan kepada kami [Ibrahim bin sa'd] dari [Ibnu Syihab] dari [Ubaid bin Sibaq] dari [Zaid bin tsabit] mengatakan, Abu bakar mengutus seseorang menemuiku karena banyaknya korban yang gugur pada perang Yamamah, ketika itu Abu bakar bersama Umar. Abu Bakar berkata; 'Umar mendatangiku dan mengatakan; 'Korban perang telah meluas pada perang yamamah hingga merenggut qurra` (penghafal) alquran, dan saya khawatir jangan-jangan dengan meninggalnya qurra` alquran di banyak tempat, mengakibatkan sekian banyak ayat quran akan menghilang, dan saya berpendapat jika engkau perintahkan untuk mengumpulkan alquran.' Maka Saya menjawab; 'bagaimana aku lakukan sesuatu yang belum pernah Rasulullah lakukan? ' Umar kontan mengemukakan pendapatnya; 'Demi Allah, ini adalah suatu kebaikan, ' Umar tiada henti-hentinya mendorongku untuk melakukan pekerjaan ini, hingga Allah melapangkan dadaku untuk melakukan pekerjaan yang dada Umar telah lebih dahulu dilapangkan terhadapnya, dan aku sependapat dengan pendapat Umar.' Zaid mengatakan, Abu Bakar berkata; 'Sungguh engkau adalah laki-laki yang masih muda, cerdas, dan kami sama sekali tidak menyangsikan kemampuanmu, sebab engkau sudah terbiasa menulis wahyu untuk Rasulullah. Maka susurilah alquran (yang masih terpencar-pencar) dan kumpulkanlah.' Maka Zaid menjawab; \"Demi Allah, sekiranya Abu bakar menugasiku untuk memindahkan sebuah gunung, itu tidak lebih berat bagiku daripada menugasiku untuk menghimpun alquran. Maka aku berkata; 'Bagaimana mungkin anda berdua melakukan sesuatu yang tidak pernah di lakukan Rasulullah Shallallahu'alaihiwasallam? ' Abu Bakar menjawab; 'demi Alllah, pekerjaan ini adalah kebaikan.' Tiada henti-hentinya Abu Bakar memotivasi pertimbanganku hingga Allah melapangkan dadaku untuk melakukan suatu hal yang Allah telah melapangkan dada Abu Bakar dan Umar untuk melakukannya. Dan aku sependapat dengan keduanya, maka kutelusuri alquran yang terpencar-pencar dan kuhimpun dari pelepah, kulit, tembikar, tulang dan dada para penghapal, dan kutemukan di akhir surat at taubah ayat yang berbunyi; 'Telah datang kepada kalian seorang rasul dari jenis kamu sendiri,,,, hingga akhir ayat (QS. Attaubah 128) bersama Khuzaimah atau Abu Khuzaemah, sehingga aku masukkan dalam suratnya. Kemudian shuhuf (manuskrip pencatatan asli alquran) ini berada di Abu Bakar ketika hidupnya sampai Allah mewafatkannya, kemudian keberadaan shuhuf ini pada Umar 'azza wajalla semasa hidupnya sampai Allah mewafatkannya, kemudian pada Hafshah binti Umar.' Muhammad bin Ubaidullah mengatakan; maksud al likhaf ialah tembikar (tanah liat yang dibakar)."},{"p":"Bukhari","n":6522,"ar":"حَدَّثَنَا مُوسَى عَنْ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ عُبَيْدِ بْنِ السَّبَّاقِ أَنَّ زَيْدَ بْنَ ثَابِتٍ وَقَالَ اللَّيْثُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ السَّبَّاقِ أَنَّ زَيْدَ بْنَ ثَابِتٍ حَدَّثَهُ قَالَأَرْسَلَ إِلَيَّ أَبُو بَكْرٍ فَتَتَبَّعْتُ الْقُرْآنَ حَتَّى وَجَدْتُ آخِرَ سُورَةِ التَّوْبَةِ مَعَ أَبِي خُزَيْمَةَ الْأَنْصَارِيِّ لَمْ أَجِدْهَا مَعَ أَحَدٍ غَيْرِهِ{ لَقَدْ جَاءَكُمْ رَسُولٌ مِنْ أَنْفُسِكُمْ }حَتَّى خَاتِمَةِ بَرَاءَةٌحَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ بِهَذَا وَقَالَ مَعَ أَبِي خُزَيْمَةَ الْأَنْصَارِيِّ","trj":"Telah menceritakan kepada kami [Musa] dari [Ibrahim] telah menceritakan kepada kami [Ibn Syihab] dari ['Ubaid bin Sibaq] bahwa [Zaid bin Tsabit], sedang [Al Laits] berkata, telah menceritakan kepadaku [Abdurrahman bin Khalid] dari [Ibn Syihab] dari [Ibn Sibaq Zaid bin Tsabit] menceritakannya dengan berkata, \"Abu Bakar mengutus seseorang kepadaku dan Abu Khuzaimah Al Anshari, sehingga aku telusuri alquran dan hingga aku temukan akhir surat At Taubah, yang aku tidak menemukannya dengan seorang pun selain bersamanya, yaitu ayat: '(Telah datang kepada kalian seorang rasul dari kalian sendiri) ' (QS. Attaubah 128), hingga penghabisan surat al Bara'ah (surat At Taubah).\" Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Yunus] dengan hadis ini, dan beliau berkata; telah menceritakan kepada kami Yahya bin Bukair telah menceritakan kepada kami Al Laits dari Yunus dengan hadis ini, dan ia menyebutkan, 'Bersama Abu Khuzaimah Al anshari.\""},{"p":"Darimi","n":92,"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ قَالَ إِنَّ أَهْلَ الْأَهْوَاءِ أَهْلُ الضَّلَالَةِ وَلَا أَرَى مَصِيرَهُمْ إِلَّا النَّارَ فَجَرِّبْهُمْ فَلَيْسَ أَحَدٌ مِنْهُمْ يَنْتَحِلُ قَوْلًا أَوْ قَالَ حَدِيثًا فَيَتَنَاهَى بِهِ الْأَمْرُ دُونَ السَّيْفِ وَإِنَّ النِّفَاقَ كَانَ ضُرُوبًا ثُمَّ تَلَا { وَمِنْهُمْ مَنْ عَاهَدَ اللَّهَ } { وَمِنْهُمْ مَنْ يَلْمِزُكَ فِي الصَّدَقَاتِ } { وَمِنْهُمْ الَّذِينَ يُؤْذُونَ النَّبِيَّ } فَاخْتَلَفَ قَوْلُهُمْ وَاجْتَمَعُوا فِي الشَّكِّ وَالتَّكْذِيبِ وَإِنَّ هَؤُلَاءِ اخْتَلَفَ قَوْلُهُمْ وَاجْتَمَعُوا فِي السَّيْفِ وَلَا أَرَى مَصِيرَهُمْ إِلَّا النَّارَ قَالَ حَمَّادٌ ثُمَّ قَالَ أَيُّوبُ عِنْدَ ذَا الْحَدِيثِ أَوْ عِنْدَ الْأَوَّلِ وَكَانَ وَاللَّهِ مِنْ الْفُقَهَاءِ ذَوِي الْأَلْبَابِ يَعْنِي أَبَا قِلَابَةَ","trj":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] ia berkata: \" Sesungguhnya pemuja hawa nafsu adalah orang-orang yang sesat, dan aku tidak melihat akhir perjalanan yang mereka tempuh kecuali neraka. Ujilah mereka itu. Tidak ada seorang pun dari mereka yang menyitir perkataan atau berkata, hingga persoalannya tiada lain adalah pedang. Sesungguhnya kemunafikan sudah menjadi ciri khas mereka. Kemudian ia membaca ayat \"WA MINHUM MAN 'AHADALLAHA' (Dan diantara mereka ada orang yang telah berikrar kepada Allah Subhaanallahu wa Ta'ala) -Qs. At Taubah: 75-, dan ayat \"WA MINHUM MAN YALMIZUKA FIS SHADAQAAT' (Dan diantara mereka ada orang yang mencelamu tentang (pembagian) zakat) -Qs. At Taubah: 58-, dan ayat \"WAMINHUMULLADZINA YU`DZUUNANABIYYA' (Dan diantara mereka 'orang-orang munafik' ada yang menyakiti Nabi shallallahu 'alaihi wasallam) -Qs. Attaubah: 116-,. Kemudian mereka berbeda pendapat dan berselisih, dan akhirnya mereka berkumpul dalam keraguan dan kedustaan,. Sesungguhnya mereka berbeda pendapat dan bersatu dalam gelayut pedang. Dan aku tidak melihat perjalanan mereka kecuali ke neraka\". Hammad berkata: \"Ayyub berkata tentang hadits ini atau hadits awal, demi Allah Subhaanallahu wa Ta'ala, ia termasuk salah seorang pakar fikih yang sangat cerdas, maksudku adalah Abu Qilabah\"."},{"p":"Darimi","n":842,"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ الْحُمَيْدِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ دَرَّاجٍ أَبِي السَّمْحِ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَأَيْتُمْ الرَّجُلَ يَعْتَادُ الْمَسَاجِدَ فَاشْهَدُوا لَهُ بِالْإِيمَانِ فَإِنَّ اللَّهَ يَقُولُ { إِنَّمَا يَعْمُرُ مَسَاجِدَ اللَّهِ مَنْ آمَنَ بِاللَّهِ }","trj":"Telah mengabarkan kepada kami [Abdullah bin Az Zubair Al Humaidi] telah menceritakan kepada kami [Abdullah bin Wahb] dari ['Amru bin Al Harits] dari [Darraj Abu As Samah] dari [Abu Al Haitsam] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila kalian melihat seorang laki-laki yang terbiasa mendatangi masjid maka bersaksilah atas keimanannya, sesungguhnya Allah berfirman: '(Sesungguhnya hanyalah yang memakmurkan masjid itu adalah orang-orang yang beriman kepada Allah) ' (Qs. At Taubah: 18)."},{"p":"Darimi","n":1482,"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ قَرَأْتُ عَلَى أَبِي قُرَّةَ هُوَ مُوسَى بْنُ طَارِقٍ عَنْ ابْنِ جُرَيْجٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ رَجَعَ مِنْ عُمْرَةِ الْجِعْرَانَةِ بَعَثَ أَبَا بَكْرٍ عَلَى الْحَجِّ فَأَقْبَلْنَا مَعَهُ حَتَّى إِذَا كُنَّا بِالْعَرْجِ ثُوِّبَ بِالصُّبْحِ فَلَمَّا اسْتَوَى لِيُكَبِّرَ سَمِعَ الرَّغْوَةَ خَلْفَ ظَهْرِهِ فَوَقَفَ عَنْ التَّكْبِيرِ فَقَالَ هَذِهِ رَغْوَةُ نَاقَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجَدْعَاءِ لَقَدْ بَدَا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحَجِّ فَلَعَلَّهُ أَنْ يَكُونَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنُصَلِّيَ مَعَهُ فَإِذَا عَلِيٌّ عَلَيْهَا فَقَالَ أَبُو بَكْرٍ أَمِيرٌ أَمْ رَسُولٌ قَالَ لَا بَلْ رَسُولٌ أَرْسَلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِبَرَاءَةٌ أَقْرَؤُهَا عَلَى النَّاسِ فِي مَوَاقِفِ الْحَجِّ فَقَدِمْنَا مَكَّةَ فَلَمَّا كَانَ قَبْلَ التَّرْوِيَةِ بِيَوْمٍ قَامَ أَبُو بَكْرٍ فَخَطَبَ النَّاسَ فَحَدَّثَهُمْ عَنْ مَنَاسِكِهِمْ حَتَّى إِذَا فَرَغَ قَامَ عَلِيٌّ فَقَرَأَ عَلَى النَّاسِ بَرَاءَةٌ حَتَّى خَتَمَهَا ثُمَّ خَرَجْنَا مَعَهُ حَتَّى إِذَا كَانَ يَوْمُ عَرَفَةَ قَامَ أَبُو بَكْرٍ فَخَطَبَ النَّاسَ فَحَدَّثَهُمْ عَنْ مَنَاسِكِهِمْ حَتَّى إِذَا فَرَغَ قَامَ عَلِيٌّ فَقَرَأَ عَلَى النَّاسِ بَرَاءَةٌ حَتَّى خَتَمَهَا ثُمَّ كَانَ يَوْمُ النَّحْرِ فَأَفَضْنَا فَلَمَّا رَجَعَ أَبُو بَكْرٍ خَطَبَ النَّاسَ فَحَدَّثَهُمْ عَنْ إِفَاضَتِهِمْ وَعَنْ نَحْرِهِمْ وَعَنْ مَنَاسِكِهِمْ فَلَمَّا فَرَغَ قَامَ عَلِيٌّ فَقَرَأَ عَلَى النَّاسِ بَرَاءَةٌ حَتَّى خَتَمَهَا فَلَمَّا كَانَ يَوْمُ النَّفْرِ الْأَوَّلُ قَامَ أَبُو بَكْرٍ فَخَطَبَ النَّاسَ فَحَدَّثَهُمْ كَيْفَ يَنْفِرُونَ وَكَيْفَ يَرْمُونَ فَعَلَّمَهُمْ مَنَاسِكَهُمْ فَلَمَّا فَرَغَ قَامَ عَلِيٌّ فَقَرَأَ بَرَاءَةٌ عَلَى النَّاسِ حَتَّى خَتَمَهَا","trj":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; saya membacakan kepada [Abu Qurrah yaitu Musa bin Thariq], dari [Ibnu Juraij], ia berkata; telah menceritakan kepada kami [Abdullah bin Utsman bin Khutsaim] dari [Abu Az Zubair] dari [Jabir bin Abdullah] bahwa sekembalinya Nabi shallallahu 'alaihi wasallam dari Umrah Ji'ranah, beliau mengutus Abu Bakar memimpin haji, lalu kami berangkat bersama Abu Bakr, hingga tiba sampai di Al 'Arj, seseorang mengumandangkan adzan shubuh, ketika Abu Bakr berdiri untuk bertakbir, ia mendengar suara unta yang adatang dari arah dibelakangnya hingga ia menghentikan takbirnya, ia berkata; \"Ini adalah suara unta Rasulullah shallallahu 'alaihi wasallam yang bernama Al Jad'a`, tampaknya Rasulullah shallallahu 'alaihi wasallam hendak melaksanakan haji, semoga ia adalah Rasulullah shallallahu 'alaihi wasallam sehingga kita dapat melaksanakan shalat bersama beliau.\" Ternyata orang yang berada diatas unta tersebut adalah Ali, Abu Bakar berkata kepadanya; \"Engkau sebagai pemimpin (haji) ataukah hanya sebagai utusan? Ia menjawab; \"Tidak, bahkan aku hanyalah utusan. Rasulullah shallallahu 'alaihi wasallam telah mengutusku membawa surat Bara`ah yang akan aku bacakan dihadapan orang-orang di beberapa tempat pemberhentian haji.\" Setibanya kami di Makkah, yaitu sehari sebelum hari Tarwiyah (tanggal delapan dzulhijjah), Abu Bakar radliallahu 'anhu berdiri dan berkhutbah di hadapan orang-orang, ia berbicara mengenai manasik haji, seusai Abu Bakr menyampaikan khutbahnya, Ali radliallahu 'anhu berdiri dan membacakan surat Taubah hingga selesai. Setelah itu kami berangkat lagi bersama Abu Bakr, ketika hari 'Arafah, Abu Bakr berkhutbah di hadapan orang-orang dan menyampaikan tentang manasik haji mereka, seusai Abu Bakr berkhutbah, Ali berdiri dan membacakan Surat Bara`ah hingga selesai. Ketika hari raya Kurban tiba, kami pun bertolak, ketika Abu Bakr kembali, dia berdiri dan berkhutbah di hadapan orang-orang dan menyampaikan tentang ifadlah (keberangkatan), penyembelihan dan manasik mereka, seusai berkhutbah, maka Ali berdiri dan membacakan surat Al Bara`ah hingga selesai. Ketika hari nafar awal (kembali dari mina ke Makkah pada gelombang yang pertama) tiba, Abu Bakar kembali berkhutbah di hadapan orang-orang, dan menyampaikan tentang bagaimana seharusnya mereka kembali (ke Makkah), dan bagaimana mereka melontar jumrah, serta mengejari merka tentang manasik haji mereka, seusai berkhutbah, maka Ali berdiri untuk membacakan surat Taubah di hadapan orang-orang hingga selesai.\""},{"p":"Darimi","n":1902,"ar":" حَدَّثَنَا مُعَاذُ بْنُ هَانِئٍ حَدَّثَنَا مُحَمَّدُ بْنُ مُسْلِمٍ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ قَتَلَ رَجُلٌ رَجُلًا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِيَتَهُ اثْنَيْ عَشَرَ أَلْفًا فَذَلِكَ قَوْلُهُ { وَمَا نَقَمُوا إِلَّا أَنْ أَغْنَاهُمْ اللَّهُ وَرَسُولُهُ مِنْ فَضْلِهِ } بِأَخْذِهِمْ الدِّيَةَ","trj":"Telah menceritakan kepada kami [Mu'adz bin Hani`] telah menceritakan kepada kami [Muhammad bin Muslim] telah menceritakan kepada kami ['Amr bin Dinar] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; \"Seorang laki-laki membunuh laki-laki lain pada masa Rasulullah shallallahu 'alaihi wasallam. Kemudian Nabi shallallahu 'alaihi wasallam menetapkan bahwa diyatnya dua belas ribu. Yang demikian itu adalah firman Allah Dan mereka tidak mencela (Allah dan Rasul-Nya), kecuali karena Allah dan Rasul-Nya telah melimpahkan karunia-Nya kepada mereka. QS At Taubah; 74, Yaitu dalam masalah pengambilan diyat."},{"p":"Muslim","n":35,"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى التُّجِيبِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ عَنْ أَبِيهِ قَالَلَمَّا حَضَرَتْ أَبَا طَالِبٍ الْوَفَاةُ جَاءَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدَ عِنْدَهُ أَبَا جَهْلٍ وَعَبْدَ اللَّهِ بْنَ أَبِي أُمَيَّةَ بْنِ الْمُغِيرَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَمِّ قُلْ لَا إِلَهَ إِلَّا اللَّهُ كَلِمَةً أَشْهَدُ لَكَ بِهَا عِنْدَ اللَّهِ فَقَالَ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ يَا أَبَا طَالِبٍ أَتَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ فَلَمْ يَزَلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْرِضُهَا عَلَيْهِ وَيُعِيدُ لَهُ تِلْكَ الْمَقَالَةَ حَتَّى قَالَ أَبُو طَالِبٍ آخِرَ مَا كَلَّمَهُمْ هُوَ عَلَى مِلَّةِ عَبْدِ الْمُطَّلِبِ وَأَبَى أَنْ يَقُولَ لَا إِلَهَ إِلَّا اللَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا وَاللَّهِ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْكَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ وَلَوْ كَانُوا أُولِي قُرْبَى مِنْ بَعْدِ مَا تَبَيَّنَ لَهُمْ أَنَّهُمْ أَصْحَابُ الْجَحِيمِ }وَأَنْزَلَ اللَّهُ تَعَالَى فِي أَبِي طَالِبٍ فَقَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِنَّكَ لَا تَهْدِي مَنْ أَحْبَبْتَ وَلَكِنَّ اللَّهَ يَهْدِي مَنْ يَشَاءُ وَهُوَ أَعْلَمُ بِالْمُهْتَدِينَ }و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ ح و حَدَّثَنَا حَسَنٌ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا حَدَّثَنَا يَعْقُوبُ وَهُوَ ابْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ حَدَّثَنِي أَبِي عَنْ صَالِحٍ كِلَاهُمَا عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ مِثْلَهُ غَيْرَ أَنَّ حَدِيثَ صَالِحٍ انْتَهَى عِنْدَ قَوْلِهِ فَأَنْزَلَ الل��َهُ عَزَّ وَجَلَّ فِيهِ وَلَمْ يَذْكُرْ الْآيَتَيْنِ وَقَالَ فِي حَدِيثِهِ وَيَعُودَانِ فِي تِلْكَ الْمَقَالَةِ وَفِي حَدِيثِ مَعْمَرٍ مَكَانَ هَذِهِ الْكَلِمَةِ فَلَمْ يَزَالَا بِهِ","trj":"Dan telah menceritakan kepadaku [Harmalah bin Yahya at-Tujibi] telah mengabarkan kepadaku [Abdullah bin Wahb] dia berkata, telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dia berkata, telah mengabarkan kepadaku [Said bin al-Musayyab] dari [bapaknya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menziarahi Abu Thalib di saat-saat dirinya tengah menghadapi sakaratul maut. Beliau mendapati Abu Jahal dan Abdullah bin Abu Umaiyyah bin al-Mughirah turut berada di sana. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Paman! Ucaplah Dua Kalimah Syahadat, aku akan menjadi saksi kamu di hadapan Allah.\" Lalu Abu Jahal dan Abdullah bin Abu Umayyah mencelah, 'Wahai Abu Thalib sanggupkah kamu meninggalkan agama Abdul Muththalib? ' Rasulullah shallallahu 'alaihi wasallam tidak berputus asa malah tetap mengajarnya mengucap Dua Kalimah Syahadat serta berkali-kali mengulanginya. Sehingga Abu Thalib menjawab sebagai ucapan terakhir kepada mereka, bahwa dia tetap bersama dengan agama Abdul MuThalib, dan enggan mengucapkan Kalimah Syahadat. Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Demi Allah, aku akan mohonkan ampunan dari Allah untukmu, \" sehingga Allah menurunkan ayat: '(Tidak dibenarkan bagi Nabi dan orang-orang yang beriman meminta ampun bagi orang-orang yang syirik sekalipun orang itu kaum kerabat sendiri setelah nyata bagi mereka bahwa orang-orang syirik itu adalah ahli Neraka) ' (Qs. AtTaubah: 113). Lalu Allah menurunkan firman-Nya berkenaan dengan peristiwa Abu Thalib: '(Sesungguhnya kamu wahai Muhammad tidak berkuasa memberi hidayat petunjuk kepada siapa yang kamu kasihi supaya dia menerima Islam tetapi Allah jualah yang berkuasa memberi petunjuk kepada orang yang dikehendaki-Nya, dan Dia jualah yang lebih mengetahui siapakah orang-orang yang (bersedia) untuk mendapat petunjuk memeluk Islam) '. (Qs. Al Qashash: 56). Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Abd bin Humaid] keduanya berkata, telah mengabarkan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar]. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Hasan al-Hulwani] dan [Abd bin Humaid] keduanya berkata, telah menceritakan kepada kami [Ya'qub] -yaitu Ibnu Ibrahim bin Sa'ad- dia berkata, telah menceritakan kepada kami [bapakku] dari [Shalih] keduanya dari [az-Zuhri] dengan sanad ini semisalnya. Hanya saja hadits Shalih selesai pada perkataannya, 'lalu Allah menurunkan firman-Nya tentangnya, ' dan dia tidak menyebutkan dua ayat tersebut. Dan dia menyebutkan di dalam haditsnya, 'Dan keduanya kembali mengucapkan perkataan tersebut, ' pada hadits Ma'mar adalah sebagai pengganti kalimat ini. Dan mereka berdua tetap berpedoman padanya.\""},{"p":"Muslim","n":1654,"ar":"حَدَّثَنِي سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ دَاوُدَ عَنْ أَبِي حَرْبِ بْنِ أَبِي الْأَسْوَدِ عَنْ أَبِيهِ قَالَ بَعَثَ أَبُو مُوسَى الْأَشْعَرِيُّ إِلَى قُرَّاءِ أَهْلِ الْبَصْرَةِ فَدَخَلَ عَلَيْهِ ثَلَاثُ مِائَةِ رَجُلٍ قَدْ قَرَءُوا الْقُرْآنَ فَقَالَ أَنْتُمْ خِيَارُ أَهْلِ الْبَصْرَةِ وَقُرَّاؤُهُمْ فَاتْلُوهُ وَلَا يَطُولَنَّ عَلَيْكُمْ الْأَمَدُ فَتَقْسُوَ قُلُوبُكُمْ كَمَا قَسَتْ قُلُوبُ مَنْ كَانَ قَبْلَكُمْوَإِنَّا كُنَّا نَقْرَأُ سُورَةً كُنَّا نُشَبِّهُهَا فِي الطُّولِ وَالشِّدَّةِ بِبَرَاءَةَ فَأُنْسِيتُهَا غَيْرَ أَنِّي قَدْ حَفِظْتُ مِنْهَا لَوْ كَانَ لِابْنِ آدَمَ وَادِيَانِ مِنْ مَالٍ لَابْتَغَى وَادِيًا ثَالِثًا وَلَا يَمْلَأُ جَوْفَ ابْنِ آدَمَ إِلَّا التُّرَابُ وَكُنَّا نَقْرَأُ سُورَةً كُنَّا نُشَبِّهُهَا بِإِحْدَى الْمُسَبِّحَاتِ فَأُنْسِيتُهَا غَيْرَ أَنِّي حَفِظْتُ مِنْهَا يَا أَيُّهَا الَّذِينَ آمَنُوا لِمَ تَقُولُونَ مَا لَا تَفْعَلُونَ فَتُكْتَبُ شَهَادَةً فِي أَعْنَاقِكُمْ فَتُسْأَلُونَ عَنْهَا يَوْمَ الْقِيَامَةِ","trj":"Telah menceritakan kepadaku [Suwaid bin Sa'id] telah menceritakan kepada kami [Ali bin Mushir] dari [Dawud] dari [Abu Harb bin Abul Aswad] dari [bapaknya] ia berkata; Ketika [Abu Musa Al Asy'ari] mengutus seorang untuk memanggil Qurra' (orang-orang yang menguasai bacaan Al Qur'an), maka datanglah kepadanya tiga ratus orang yang memang benar-benar telah menguasai bacaan Al Qur'an. Iapun berkata, \"Kalian adalah sebaik-baik penduduk Bashrah dan kalian adalah Qurraa' mereka. Oleh karena itu bacalah dan janganlah kalian meninggalkannya terlalu lama hingga hati kalian akan membatu sebagaimana hati orang-orang sebelum kalian. Saat kami membaca satu surat yang panjang dan ketegasannya menyerupai surat Bara'ah (surat Taubah) kemudian aku dilupakan, tapi aku masih ingat sedikit darinya yaitu: 'Kalau seandainya anak cucu Adam memiliki harta benda sebanyak dua bukit niscaya ia akan mencari bukit yang ketiga, dan tidak ada yang dapat memenuhi perut anak cucu Adam kecuali tanah.' Saat itu kami juga membaca satu surat yang serupa dengan salah satu Al Musabbihaat (surat yang diawali dengan sabbaha) kemudian aku dilupakan, tapi aku masih hafal sedikit daripadanya yaitu: 'Wahai orang-orang yang beriman kenapakah kalian mengatakan (memerintahkan) apa yang tidak kalian perbuat.' Lalu akan dituliskan satu persaksian pada kalian, dan kelak di hari kiamat kalian akan ditanyai mengenai hal itu.\""},{"p":"Muslim","n":3251,"ar":"حَدَّثَنِي حَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ حَدَّثَنَا أَبُو تَوْبَةَ حَدَّثَنَا مُعَاوِيَةُ بْنُ سَلَّامٍ عَنْ زَيْدِ بْنِ سَلَّامٍ أَنَّهُ سَمِعَ أَبَا سَلَّامٍ قَالَ حَدَّثَنِي النُّعْمَانُ بْنُ بَشِيرٍ قَالَكُنْتُ عِنْدَ مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَجُلٌ مَا أُبَالِي أَنْ لَا أَعْمَلَ عَمَلًا بَعْدَ الْإِسْلَامِ إِلَّا أَنْ أُسْقِيَ الْحَاجَّ وَقَالَ آخَرُ مَا أُبَالِي أَنْ لَا أَعْمَلَ عَمَلًا بَعْدَ الْإِسْلَامِ إِلَّا أَنْ أَعْمُرَ الْمَسْجِدَ الْحَرَامَ وَقَالَ آخَرُ الْجِهَادُ فِي سَبِيلِ اللَّهِ أَفْضَلُ مِمَّا قُلْتُمْ فَزَجَرَهُمْ عُمَرُ وَقَالَ لَا تَرْفَعُوا أَصْوَاتَكُمْ عِنْدَ مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَوْمُ الْجُمُعَةِ وَلَكِنْ إِذَا صَلَّيْتُ الْجُمُعَةَ دَخَلْتُ فَاسْتَفْتَيْتُهُ فِيمَا اخْتَلَفْتُمْ فِيهِ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ أَجَعَلْتُمْ سِقَايَةَ الْحَاجِّ وَعِمَارَةَ الْمَسْجِدِ الْحَرَامِ كَمَنْ آمَنَ بِاللَّهِ وَالْيَوْمِ الْآخِرِ }الْآيَةَ إِلَى آخِرِهَاو حَدَّثَنِيهِ عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا مُعَاوِيَةُ أَخْبَرَنِي زَيْدٌ أَنَّهُ سَمِعَ أَبَا سَلَّامٍ قَالَ حَدَّثَنِي النُّعْمَانُ بْنُ بَشِيرٍ قَالَ كُنْتُ عِنْدَ مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ أَبِي تَوْبَةَ","trj":"Telah menceritakan kepadaku [Hasan bin Ali Al Khulwani] telah menceritakan kepada kami [Abu Taubah] telah menceritakan kepada kami [Mu'awiyah bin Salam] dari [Zaid bin Salam] bahwa dia mendengar [Abu Salam] berkata; telah menceritakan kepadaku [An Nu'man bin Basyir] dia berkata, \"Saya pernah berada di sisi mimbar Rasulullah shallallahu 'alaihi wasallam, tiba-tiba saya mendengar seorang laki-laki berkata, \"Saya tidak mementingkan suatu amalan setelah saya masuk Islam kecuali menjamu para Jama'ah haji.\" Sedangkan yang lain mengatakan, \"Saya tidak mementingkan suatu amalan setelah saya masuk Islam kecuali memakmurkan Masjidil Haram.\" Dan yang lainnya lagi mengatakan, \"Jihad fi sabilillah itu lebih baik dari apa yang kalian katakan tadi.\" Lalu mereka ditegur oleh Umar saraya berkata, \"Janganlah kalian meninggikan suara kalian di sisi mimbar Rasulullah shallallahu 'alaihi wasallam, bukankah hari ini adalah hari Jum'at?\" Setelah selesai shalat Jum'at, saya datang menemui beliau untuk meminta fatwa tentang apa yang diperselisihkan mereka, maka turunkah ayat: '(Apakah (orang-orang) yang memberi minuman orang-orang yang mengerjakan haji dan mengurus Masjidilharam kamu samakan dengan orang-orang yang beriman kepada Allah dan hari Kemudian serta bejihad di jalan Allah? …) ' (Qs. At Taubah: 19) sampai akhir ayat.\" Dan telah menceritakan kepadaku [Abdullah bin Abdurrahman Ad Darimi] telah menceritakan kepada kami [Yahya bin Hasan] telah menceritakan kepada kami [Mu'awiyah] telah mengabarkan kepadaku [Zaid] bahwa dia mendengar [Abu Salam] berkata; telah menceritakan kepadaku [An Nu'man bin Basyir] dia berkata, \"Ketika saya berada di sisi mimbar Rasulullah shallallahu 'alaihi wasallam…seperti hadits Abu Taubah.\""},{"p":"Muslim","n":4077,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَلَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ جَاءَ ابْنُهُ عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ أَنْ يُعْطِيَهُ قَمِيصَهُ أَنْ يُكَفِّنَ فِيهِ أَبَاهُ فَأَعْطَاهُ ثُمَّ سَأَلَهُ أَنْ يُصَلِّيَ عَلَيْهِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَقَامَ عُمَرُ فَأَخَذَ بِثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَتُصَلِّي عَلَيْهِ وَقَدْ نَهَاكَ اللَّهُ أَنْ تُصَلِّيَ عَلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا خَيَّرَنِي اللَّهُ فَقَالَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً }وَسَأَزِيدُ عَلَى سَبْعِينَ قَالَ إِنَّهُ مُنَافِقٌ فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ }و حَدَّثَنَاه مُحَمَّدُ بْنُ الْمُثَنَّى وَعُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا يَحْيَى وَهُوَ الْقَطَّانُ عَنْ عُبَيْدِ اللَّهِ بِهَذَا الْإِسْنَادِ فِي مَعْنَى حَدِيثِ أَبِي أُسَامَةَ وَزَادَ قَالَ فَتَرَكَ الصَّلَاةَ عَلَيْهِمْ","trj":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah]; Telah menceritakan kepada kami [Abu Usamah]; Telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar] dia berkata; \"Ketika Abdullah bin Ubay bin Salul meninggal dunia. anak laki-lakinya -yaitu Abdulah bin Abdullah- datang kepada Rasulullah shallallahu 'alaihi wasallam seraya memohon kepada beIiau agar sudi memberikan baju beliau kepada Abdullah untuk kain kafan ayahnya, Abdullah bin Ubay bin Salul. Lalu Rasulullah shallallahu 'alaihi wasallam memberikan bajunya kepada Abdullah. Setelah itu, Abdullah juga memohon Rasulullah agar beliau berkenan menshalati jenazah ayahnya. Kemudian Rasulullah pun bersiap-siap untuk menshalati jenazah Abdullah bin Ubay, hingga akhirnya Umar berdiri dan menarik baju Rasulullah seraya berkata, \"Ya Rasulullah, apakah engkau akan menshalati jenazah Abdullah bin Ubay sedangkan Allah telah melarang untuk menshalatinya?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Sesungguhnya Allah Subhanahu wa Ta'ala telah memberikan pilihan kepadaku.\" Lalu beliau membacakan ayat yang berbunyi; \"Kamu memohonkun ampun bagi orang-orang munafik atau tidak kamu mohonkan ampun bagi mereka, maka hal itu adalah sama saja. sekalipun kamu memohonkan ampun bagi mereka tujuh puluh kali (Qs. At-Taubah 9: 80). Oleh karena itu, aku akan menambah istighfar lebih dari tujuh puluh kali untuknya.\" Umar bin Khaththab berkata, \"Ya Rasulullah, sesungguhnya Ia adalah orang munafik?.\" Tetapi, rupanya Rasulullah shallallahu 'alaihi wasallam tetap saja menshalatinya, hingga Allah menurunkan ayat Al Qur'an: \"Janganlah kamu sekali-kali menshalati jenazah seorang di antara orang-orang munafik dan janganlah kamu berdiri di atas kuburnya.\" (Qs. At-Taubah 9: 84). Dan telah menceritakannya kepada kami [Muhammad bin Al Mutsanna] dan ['Ubaidullah bin Sa'id] keduanya berkata; Telah menceritakan kepada kami [Yahya] yaitu Al Qaththan dari ['Ubaidillah] melalui jalur ini mengenai Hadits yang semakna dengan Abu Usamah namun ada tambahan; 'Kemudian beliau meninggalkan shalat untuk mereka (orang-orang munafik)."},{"p":"Muslim","n":4927,"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُطِيعٍ حَدَّثَنَا هُشَيْمٌ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَقُلْتُ لِابْنِ عَبَّاسٍ سُورَةُ التَّوْبَةِ قَالَ آلتَّوْبَةِ قَالَ بَلْ هِيَ الْفَاضِحَةُ مَا زَالَتْ تَنْزِلُ وَمِنْهُمْ وَمِنْهُمْ حَتَّى ظَنُّوا أَنْ لَا يَبْقَى مِنَّا أَحَدٌ إِلَّا ذُكِرَ فِيهَا قَالَ قُلْتُ سُورَةُ الْأَنْفَالِ قَالَ تِلْكَ سُورَةُ بَدْرٍ قَالَ قُلْتُ فَالْحَشْرُ قَالَ نَزَلَتْ فِي بَنِي النَّضِيرِ","trj":"Telah menceritakan kepadaku [Abdullah bin Muthi'] telah menceritakan kepada kami [Husyaim] dari [Abu Bisyr] dari [Sa'id bin Jubair] berkata: Saya berkata kepada [Ibnu 'Abbas]: Surat At Taubah, ia berkata: Apa At Taubah? Ia berkata: Bahkan ia adalah Al Fadhilah (yang menyibak rahasia orang-orang munafik, pent.) yang masih turun dan dari mereka dan dari mereka hingga mereka mengira tiada seorangpun dari kita yang masih tersisa kecuali telah disebutkan di dalamnya. Ia berkata: Aku berkata: Surat Al Anfaal, ia (Ibnu Abbas) berkata: Itu adalah surat perang Badar. Ia berkata: Lalu aku berkata: Surat Al Hasyr, ia (Ibnu Abbas) berkata: Ia turun berkenaan dengan Bani Nadhir."},{"p":"Nasa'i","n":1895,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا حُجَيْنُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَلَمَّا مَاتَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ دُعِيَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصَلِّيَ عَلَيْهِ فَلَمَّا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَثَبْتُ إِلَيْهِ فَقُلْتُ يَا رَسُولَ اللَّهِ تُصَلِّي عَلَى ابْنِ أُبَيٍّ وَقَدْ قَالَ يَوْمَ كَذَا وَكَذَا كَذَا وَكَذَا أُعَدِّدُ عَلَيْهِ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَخِّرْ عَنِّي يَا عُمَرُ فَلَمَّا أَكْثَرْتُ عَلَيْهِ قَالَ إِنِّي قَدْ خُيِّرْتُ فَاخْتَرْتُ فَلَوْ عَلِمْتُ أَنِّي لَوْ زِدْتُ عَلَى السَّبْعِينَ غُفِرَ لَهُ لَزِدْتُ عَلَيْهَا فَصَلَّى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ انْصَرَفَ فَلَمْ يَمْكُثْ إِلَّا يَسِيرًا حَتَّى نَزَلَتْ الْآيَتَانِ مِنْ بَرَاءَةَ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ إِنَّهُمْ كَفَرُوا بِاللَّهِ وَرَسُولِهِ وَمَاتُوا وَهُمْ فَاسِقُونَ }فَعَجِبْتُ بَعْدُ مِنْ جُرْأَتِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ وَاللَّهُ وَرَسُولُهُ أَعْلَمُ","trj":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Hujain bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah] dari ['Abdullah bin 'Abbas] dari ['Umar bin Al Khaththab] dia berkata; Setelah Abdullah bin Ubai bin Salul meninggal dunia, Rasulullah shallallahu 'alaihi wasallam diundang untuk menshalatinya. Setelah Rasulullah shallallahu 'alaihi wasallam berdiri untuk melaksanakan Shalat, aku meloncat ke arah beliau, lalu aku berkata, \"Wahai Rasulullah shallallahu 'alaihi wasallam, engkau menshalati Ibnu Ubbay, padahal ia telah mengatakan hari ini dan itu begini dan itu begitu?! Aku menyebut kejelekannya, Rasulullah shallallahu 'alaihi wasallam tersenyum seraya bersabda: \"Tundalah -perkataanmu- dariku wahai Umar!\" setelah aku mengulang menyebut-nyebut kejelekannya, beliau bersabda: \" Aku telah diberikan pilihan, aku memilih. Andaikata aku tahu, kalau aku menambahnya lebih dari tujuh puluh ia akan diampuni, niscaya aku menambahnya!.\"Lalu Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat atasnya, kemudian beliau pergi dan tidak berada di tempat itu kecuali hanya sejenak, hingga turun dua ayat dari surah Bara'ah, \"(Dan janganlah kamu sekali-kali menshalatkan (jenazah) seorang yang mati di antara mereka, dan janganlah kamu berdiri (mendo'akan) di kuburnya. mereka telah kafir kepada Allah dan RasulNya dan mereka mati dalam keadaan fasik.\" (Qs. At-Taubah 9: 84). Setelah itu aku heran atas keberanianku terhadap Rasulullah shallallahu 'alaihi wasallam ketika itu. Dan hanya Allah dan Rasul-Nya yang lebih mengatahui.\""},{"p":"Nasa'i","n":1963,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مُحَمَّدٌ وَهُوَ ابْنُ ثَوْرٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِيهِ قَالَلَمَّا حَضَرَتْ أَبَا طَالِبٍ الْوَفَاةُ دَخَلَ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ فَقَالَ أَيْ عَمِّ قُلْ لَا إِلَهَ إِلَّا اللَّهُ كَلِمَةً أُحَاجُّ لَكَ بِهَا عِنْدَ اللَّهِ عَزَّ وَجَلَّ فَقَالَ لَهُ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ يَا أَبَا طَالِبٍ أَتَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ فَلَمْ يَزَالَا يُكَلِّمَانِهِ حَتَّى كَانَ آخِرُ شَيْءٍ كَلَّمَهُمْ بِهِ عَلَى مِلَّةِ عَبْدِ الْمُطَّلِبِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْكَ فَنَزَلَتْ{ مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ }وَنَزَلَتْ{ إِنَّكَ لَا تَهْدِي مَنْ أَحْبَبْتَ }","trj":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Muhammad bin Tsaur] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [bapaknya] dia berkata; \"Ketika Abu Thalib mendekati ajalnya, Rasulullah shallallahu 'alaihi wasallam masuk menemuinya dan di dekatnya ada Abu Jahal dan Abdullah bin Abu Umayyah. Lalu beliau bersabda: \"Wahai pamanku, ucapkanlah 'Laa Ilaaha Illallah (tidak ada sesembahan yang berhak di sembah selain Allah) ' satu kalimat yang dengannya aku akan berhujah untukmu di sisi Allah -Azza wa Jalla-.\" Maka Abu Jahal dan Abdullah bin Umayyah berkata kepadanya; \"Wahai Abu Thalib, Apakah kamu benci dengan agama Abdul Muthalib?\" dan keduanya tetap mangatakan hal itu kepadanya, hingga kalimat terakhir yang ia ucapkan kepada mereka ialah, bahwa ia tetap berpegang pada agama Abdul Muthalib! Maka Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Sungguh akan aku akan mintakan ampunan untukmu selama aku tidak dilarang.\" Lalu turunlah ayat, \"Tidak sepatutnya bagi Nabi dan orang-orang yang beriman memintakan ampun (kepada Allah) bagi orang-orang musyrik.\" (Qs. At Taubah 9; 113) Dan turun ayat, \" Kamu tidak akan dapat memberi petunjuk kepada orang yang kamu kasihi.\" (Qs. Al Qashash 28: 56)."},{"p":"Nasa'i","n":1964,"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْخَلِيلِ عَنْ عَلِيٍّ قَالَسَمِعْتُ رَجُلًا يَسْتَغْفِرُ لِأَبَوَيْهِ وَهُمَا مُشْرِكَانِ فَقُلْتُ أَتَسْتَغْفِرُ لَهُمَا وَهُمَا مُشْرِكَانِ فَقَالَ أَوَ لَمْ يَسْتَغْفِرْ إِبْرَاهِيمُ لِأَبِيهِ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَنَزَلَتْ{ وَمَا كَانَ اسْتِغْفَارُ إِبْرَاهِيمَ لِأَبِيهِ إِلَّا عَنْ مَوْعِدَةٍ وَعَدَهَا إِيَّاهُ }","trj":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dari [Sufyan] dari [Abu Ishaq] dari [Abul Khalil] dari ['Ali] dia berkata; Aku mendengar seseorang memintakan ampunan bagi kedua orang tuanya sedang keduanya musyrik, maka aku bertanya kepadanya; \"Apakah engkau memintakan ampunan untuk mereka berdua, padahal mereka musyrik?\" ia menjawab, \"Bukankah Nabi Ibrahim juga memintakan ampunan untuk bapaknya?\" lalu aku menemui Nabi shallallahu 'alaihi wasallam dan aku ceritakan hal itu kepada beliau, lalu turunlah ayat, \"Dan permintaan ampun dari Ibrahim (kepada Allah) untuk bapaknya tidak lain hanyalah karena suatu janji yang telah diikrarkannya kepada bapaknya itu.\" (Qs. At Taubah 9: 114)"},{"p":"Nasa'i","n":2398,"ar":"أَخْبَرَنَا بِشْرُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مَسْعُودٍ قَالَلَمَّا أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالصَّدَقَةِ فَتَصَدَّقَ أَبُو عَقِيلٍ بِنِصْفِ صَاعٍ وَجَاءَ إِنْسَانٌ بِشَيْءٍ أَكْثَرَ مِنْهُ فَقَالَ الْمُنَافِقُونَ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَغَنِيٌّ عَنْ صَدَقَةِ هَذَا وَمَا فَعَلَ هَذَا الْآخَرُ إِلَّا رِيَاءً فَنَزَلَتْ{ الَّذِينَ يَلْمِزُونَ الْمُطَّوِّعِينَ مِنْ الْمُؤْمِنِينَ فِي الصَّدَقَاتِ وَالَّذِينَ لَا يَجِدُونَ إِلَّا جُهْدَهُمْ }","trj":"Telah mengabarkan kepada kami [Bisyr bin Khalid] dia berkata; Telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Sulaiman] dari [Abu Wa'il] dari [Abu Mas'ud] dia berkata; \"Setelah Rasulullah Shalallahu 'Alaihi Wa Sallam memerintahkan kami untuk bersedekah, maka Abu Uqail bersedekah dengan satu sha', dan datang seseorang dengan membawa lebih banyak dari itu, lalu orang-orang munafik berkata; \" Allah Azza Wa Jalla benar-benar tidak membutuhkan sedekah orang ini, orang ini tidak melakukannya kecuali dengan riya'. Lalu turun ayat: 'Orang-orang munafik itu yaitu orang-orang yang mencela orang-orang mukmin yang memberi sedekah dengan sukarela dan (mencela) orang-orang yang tidak memperoleh (untuk disedekahkan) selain sekadar kesanggupannya.\" (Qs. At Taubah 9: 79)."},{"p":"Nasa'i","n":2852,"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ قَرَأْتُ عَلَى أَبِي قُرَّةَ مُوسَى بْنِ طَارِقٍ عَنْ ابْنِ جُرَيْجٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ رَجَعَ مِنْ عُمْرَةِ الْجِعِرَّانَةِ بَعَثَ أَبَا بَكْرٍ عَلَى الْحَجِّ فَأَقْبَلْنَا مَعَهُ حَتَّى إِذَا كَانَ بِالْعَرْجِ ثَوَّبَ بِالصُّبْحِ ثُمَّ اسْتَوَى لِيُكَبِّرَ فَسَمِعَ الرَّغْوَةَ خَلْفَ ظَهْرِهِ فَوَقَفَ عَلَى التَّكْبِيرِ فَقَالَ هَذِهِ رَغْوَةُ نَاقَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجَدْعَاءِ لَقَدْ بَدَا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحَجِّ فَلَعَلَّهُ أَنْ يَكُونَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنُصَلِّيَ مَعَهُ فَإِذَا عَلِيٌّ عَلَيْهَا فَقَالَ لَهُ أَبُو بَكْرٍ أَمِيرٌ أَمْ رَسُولٌ قَالَ لَا بَلْ رَسُولٌ أَرْسَلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِبَرَاءَةَ أَقْرَؤُهَا عَلَى النَّاسِ فِي مَوَاقِفِ الْحَجِّ فَقَدِمْنَا مَكَّةَ فَلَمَّا كَانَ قَبْلَ التَّرْوِيَةِ بِيَوْمٍ قَامَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَخَطَبَ النَّاسَ فَحَدَّثَهُمْ عَنْ مَنَاسِكِهِمْ حَتَّى إِذَا فَرَغَ قَامَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ فَقَرَأَ عَلَى النَّاسِ بَرَاءَةٌ حَتَّى خَتَمَهَا ثُمَّ خَرَجْنَا مَعَهُ حَتَّى إِذَا كَانَ يَوْمُ عَرَفَةَ قَامَ أَبُو بَكْرٍ فَخَطَبَ النَّاسَ فَحَدَّثَهُمْ عَنْ مَنَاسِكِهِمْ حَتَّى إِذَا فَرَغَ قَامَ عَلِيٌّ فَقَرَأَ عَلَى النَّاسِ بَرَاءَةٌ حَتَّى خَتَمَهَا ثُمَّ كَانَ يَوْمُ النَّحْرِ فَأَفَضْنَا فَلَمَّا رَجَعَ أَبُو بَكْرٍ خَطَبَ النَّاسَ فَحَدَّثَهُمْ عَنْ إِفَاضَتِهِمْ وَعَنْ نَحْرِهِمْ وَعَنْ مَنَاسِكِهِمْ فَلَمَّا فَرَغَ قَامَ عَلِيٌّ فَقَرَأَ عَلَى النَّاسِ بَرَاءَةٌ حَتَّى خَتَمَهَا فَلَمَّا كَانَ يَوْمُ النَّفْرِ الْأَوَّلُ قَامَ أَبُو بَكْرٍ فَخَطَبَ النَّاسَ فَحَدَّثَهُمْ كَيْفَ يَنْفِرُونَ وَكَيْفَ يَرْمُونَ فَعَلَّمَهُمْ مَنَاسِكَهُمْ فَلَمَّا فَرَغَ قَامَ عَلِيٌّ فَقَرَأَ بَرَاءَةٌ عَلَى النَّاسِ حَتَّى خَتَمَهَاقَالَ أَبُو عَبْد الرَّحْمَنِ ابْنُ خُثَيْمٍ لَيْسَ بِالْقَوِيِّ فِي الْحَدِيثِ وَإِنَّمَا أَخْرَجْتُ هَذَا لِئَلَّا يُجْعَلَ ابْنُ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ وَمَا كَتَبْنَاهُ إِلَّا عَنْ إِسْحَقَ بْنِ إِبْرَاهِيمَ وَيَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ لَمْ يَتْرُكْ حَدِيثَ ابْنِ خُثَيْمٍ وَلَا عَبْدِ الرَّحْمَنِ إِلَّا أَنَّ عَلِيَّ بْنَ الْمَدِينِيِّ قَالَ ابْنُ خُثَيْمٍ مُنْكَرُ الْحَدِيثِ وَكَأَنَّ عَلِيَّ بْنَ الْمَدِينِيِّ خُلِقَ لِلْحَدِيثِ","trj":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; saya membacakan riwayat kepada [Abu Qurrah Musa bin Thariq] dari [Ibnu Juraij], ia berkata; telah menceritakan kepadaku [Abdullah bin Utsman bn Khutsaim] dari [Abu Az Zubair] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam ketika kembali dari umrah di Ji'ranah beliau mengutus Abu Bakar memimpin haji, lalu kami datang bersamanya, hingga ketika sampai di Al 'Arj ia mengumandangkan adzan untuk shalat shubuh, lalu ia berdiri untuk bertakbir, kemudian ia mendengar suara unta dibelakangnya dan berhenti bertakbir, ia berkata 'ini adalah suara unta shallallahu 'alaihi wasallam Al Jad'a', tampaknya Rasulullah shallallahu 'alaihi wasallam melaksanakan haji, dan semoga ia adalah Rasulullah shallallahu 'alaihi wasallam sehingga kita melaksanakan sholat bersama beliau, namun ternyata Ali yang berada diatas unta tersebut, kemudian Abu Bakar berkata kepadanya; engkau sebagai amir atau utusan. Ia menjawab; tidak, aku hanyalah utusan Rasulullah shallallahu 'alaihi wasallam dengan surat Bara-ah yang akan saya bacakan di beberapa tempat pemberhentian untuk haji. Kemudian kami sampai di Mekkah, setelah sehari sebelum Tarwiyah (tanggal delapan dzulhijjah), Abu Bakar radliallahu 'anhu berdiri didepan manusia kemudian berkhutbah kepada manusia, ia berbicara mengenai ibadah haji mereka hingga setelah ia selesai, lalu Ali radliallahu 'anhu berdiri dan membacakan surat Taubah hingga selesai. Kemudian pada hari Kurban kami melakukan thawaf ifadhah, lalu setelah Abu Bakar kembali ia berkhutbah kepada manusia, ia berbicara mengenai ibadah thawaf ifadhah serta penyembelihan kurban, serta ibadah haji mereka. Setelah ia selesai, Ali berdiri dan membacakan surat Taubah hingga ia menyelesaikannya. Kemudian pada hari Nafar pertama Abu Bakar berdiri kemudian berkhutbah kepada manusia, ia berbicara mengenai bagaimana mereka kembali dari Mina, dan bagaimana mereka melempar jumrah, ia mengajarkan kepada mereka cara-cara ibadah haji mereka. Setelah ia selesai, Ali berdiri dan membacakan surat Taubah hingga ia menyelesaikannya. Abu Abdurrahman berkata; Ibnu Khutsaim tidaklah kuat dalam hal hadits, saya menyebutkannya agar Ibn Juraij tidak dijadikan dari Abi Zubair, dan tidaklah kami menulisnya kecuali dari ishaq bin Ibrahim dan Yahya bin Sa'id Alqaththan, ia tidak meninggalkan hadits Ibn Khutsaim dan Abdurrahman hanya saja Ali bin Al Madini berkata; Ibn Hutsaim itu haditsnya mungkar, dan sepertinya Ali bin Madini diciptakan untuk meriwayatkan hadits."}]};
